{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calories, and nutritional categories with weekly chart visualization",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart", "filter"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "@plaited/template": "^0"
  }
}

{
  "meals": [],
  "dailyGoal": 2000
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type MealEntry = {
  id: string;
  timestamp: string;
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type DietData = {
  meals: MealEntry[];
  dailyGoal: number;
};

export type DaySummary = {
  date: string;
  label: string;
  total: number;
};

import type { DietData, MealEntry, FoodCategory, DaySummary } from './types';

const DATA_PATH = 'data/meals.json';

const DEFAULT_DATA: DietData = { meals: [], dailyGoal: 2000 };

export const loadData = async (): Promise<DietData> => {
  try {
    const file = Bun.file(DATA_PATH);
    if (await file.exists()) {
      return await file.json();
    }
  } catch {
    // corrupted file, reset
  }
  return { ...DEFAULT_DATA, meals: [] };
};

export const saveData = async (data: DietData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

export const addMeal = async (
  name: string,
  calories: number,
  categories: FoodCategory[],
): Promise<MealEntry> => {
  const data = await loadData();
  const entry: MealEntry = {
    id: crypto.randomUUID(),
    timestamp: new Date().toISOString(),
    name,
    calories,
    categories,
  };
  data.meals.push(entry);
  await saveData(data);
  return entry;
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.meals.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  data.meals.splice(idx, 1);
  await saveData(data);
  return true;
};

export const setDailyGoal = async (calories: number): Promise<void> => {
  const data = await loadData();
  data.dailyGoal = calories;
  await saveData(data);
};

export const getTodayMeals = (data: DietData): MealEntry[] => {
  const today = new Date().toISOString().slice(0, 10);
  return data.meals.filter((m) => m.timestamp.slice(0, 10) === today);
};

export const getDailyTotal = (meals: MealEntry[]): number =>
  meals.reduce((sum, m) => sum + m.calories, 0);

export const getWeeklySummary = (data: DietData): DaySummary[] => {
  const days: DaySummary[] = [];
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const dayMeals = data.meals.filter((m) => m.timestamp.slice(0, 10) === dateStr);
    const total = getDailyTotal(dayMeals);
    days.push({
      date: dateStr,
      label: dayNames[d.getDay()],
      total,
    });
  }

  return days;
};

import type { DaySummary } from './types';

const CHART_WIDTH = 560;
const CHART_HEIGHT = 220;
const BAR_GAP = 12;
const PADDING = { top: 20, right: 20, bottom: 40, left: 50 };

export const renderWeeklyChart = (days: DaySummary[], goal: number): string => {
  const plotW = CHART_WIDTH - PADDING.left - PADDING.right;
  const plotH = CHART_HEIGHT - PADDING.top - PADDING.bottom;
  const maxVal = Math.max(goal, ...days.map((d) => d.total), 500);
  const yScale = plotH / maxVal;
  const barWidth = (plotW - BAR_GAP * (days.length - 1)) / days.length;

  const bars = days
    .map((day, i) => {
      const x = PADDING.left + i * (barWidth + BAR_GAP);
      const barH = day.total * yScale;
      const y = PADDING.top + plotH - barH;
      const fill = day.total > goal ? '#ef4444' : day.total >= goal * 0.8 ? '#f59e0b' : '#22c55e';

      return `
      <rect x="${x}" y="${y}" width="${barWidth}" height="${barH}" fill="${fill}" rx="3"/>
      <text x="${x + barWidth / 2}" y="${PADDING.top + plotH + 16}" text-anchor="middle" font-size="11" fill="#6b7280">${day.label}</text>
      <text x="${x + barWidth / 2}" y="${y - 4}" text-anchor="middle" font-size="10" fill="#374151">${day.total > 0 ? day.total : ''}</text>`;
    })
    .join('');

  const goalY = PADDING.top + plotH - goal * yScale;
  const goalLine =
    goal * yScale <= plotH
      ? `<line x1="${PADDING.left}" y1="${goalY}" x2="${CHART_WIDTH - PADDING.right}" y2="${goalY}" stroke="#6366f1" stroke-width="2" stroke-dasharray="6,3"/>
         <text x="${PADDING.left - 4}" y="${goalY + 4}" text-anchor="end" font-size="10" fill="#6366f1">${goal}</text>`
      : '';

  const yTicks = [0, 0.25, 0.5, 0.75, 1].map((pct) => {
    const val = Math.round(maxVal * pct);
    const y = PADDING.top + plotH - val * yScale;
    return `
      <line x1="${PADDING.left}" y1="${y}" x2="${CHART_WIDTH - PADDING.right}" y2="${y}" stroke="#e5e7eb" stroke-width="1"/>
      <text x="${PADDING.left - 4}" y="${y + 4}" text-anchor="end" font-size="10" fill="#9ca3af">${val}</text>`;
  });

  return `<svg viewBox="0 0 ${CHART_WIDTH} ${CHART_HEIGHT}" width="100%" style="max-width:${CHART_WIDTH}px" xmlns="http://www.w3.org/2000/svg">
    <rect width="${CHART_WIDTH}" height="${CHART_HEIGHT}" fill="white" rx="8"/>
    ${yTicks.join('')}
    ${bars}
    ${goalLine}
  </svg>`;
};

import { loadData, addMeal, deleteMeal, setDailyGoal, getTodayMeals, getDailyTotal, getWeeklySummary } from './store';
import { renderPage } from './views';
import { renderWeeklyChart } from './chart';
import type { FoodCategory } from './types';

const VALID_CATEGORIES: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber'];

const parseCategories = (formData: FormData): FoodCategory[] => {
  const raw = formData.getAll('categories');
  return raw.filter((v): v is FoodCategory => VALID_CATEGORIES.includes(v as FoodCategory));
};

const redirect = (path: string): Response =>
  new Response(null, { status: 303, headers: { Location: path } });

Bun.serve({
  port: 3000,

  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // Serve main page
    if (req.method === 'GET' && pathname === '/') {
      const data = await loadData();
      const todayMeals = getTodayMeals(data);
      const dailyTotal = getDailyTotal(todayMeals);
      const weekly = getWeeklySummary(data);
      const chartSvg = renderWeeklyChart(weekly, data.dailyGoal);
      const html = renderPage(todayMeals, dailyTotal, data.dailyGoal, chartSvg);
      return new Response(html, { headers: { 'Content-Type': 'text/html' } });
    }

    // Add meal
    if (req.method === 'POST' && pathname === '/meals') {
      const formData = await req.formData();
      const name = String(formData.get('name') ?? '').trim();
      const calories = parseInt(String(formData.get('calories') ?? '0'), 10);
      const categories = parseCategories(formData);

      if (name && calories >= 0) {
        await addMeal(name, calories, categories);
      }
      return redirect('/');
    }

    // Delete meal
    const deleteMatch = pathname.match(/^\/meals\/([^/]+)\/delete$/);
    if (req.method === 'POST' && deleteMatch) {
      await deleteMeal(deleteMatch[1]);
      return redirect('/');
    }

    // Update daily goal
    if (req.method === 'POST' && pathname === '/goal') {
      const formData = await req.formData();
      const calories = parseInt(String(formData.get('calories') ?? '2000'), 10);
      if (calories >= 100) {
        await setDailyGoal(calories);
      }
      return redirect('/');
    }

    // API: weekly summary
    if (req.method === 'GET' && pathname === '/api/weekly') {
      const data = await loadData();
      const weekly = getWeeklySummary(data);
      return Response.json({ days: weekly, goal: data.dailyGoal });
    }

    return new Response('Not Found', { status: 404 });
  },
});

