import type { Expense, ExpenseFilter, Category } from './types'

const DATA_PATH = 'data/expenses.json'

const loadExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveExpenses = async (expenses: Expense[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(expenses, null, 2))
}

const generateId = (): string => crypto.randomUUID()

export const addExpense = async (
  amount: number,
  category: Category,
  date: string,
  notes?: string
): Promise<Expense> => {
  const expenses = await loadExpenses()
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(amount * 100) / 100,
    category,
    date,
    notes: notes || undefined,
    createdAt: new Date().toISOString(),
  }
  expenses.push(expense)
  await saveExpenses(expenses)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses()
  const index = expenses.findIndex((e) => e.id === id)
  if (index === -1) return false
  expenses.splice(index, 1)
  await saveExpenses(expenses)
  return true
}

export const getExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const expenses = await loadExpenses()
  return applyFilter(expenses, filter)
}

const applyFilter = (expenses: Expense[], filter?: ExpenseFilter): Expense[] => {
  if (!filter) return expenses
  return expenses.filter((e) => {
    if (filter.category && e.category !== filter.category) return false
    if (filter.startDate && e.date < filter.startDate) return false
    if (filter.endDate && e.date > filter.endDate) return false
    return true
  })
}

export const getMonthlyExpenses = async (month: string): Promise<Expense[]> => {
  const expenses = await loadExpenses()
  return expenses.filter((e) => e.date.startsWith(month))
}

import type { Expense, MonthlySummary, Category } from './types'
import { CATEGORIES } from './types'

export const buildMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const byCategory = Object.fromEntries(
    CATEGORIES.map((cat) => [cat, 0])
  ) as Record<Category, number>

  let total = 0
  for (const expense of monthExpenses) {
    byCategory[expense.category] += expense.amount
    total += expense.amount
  }

  return {
    month,
    total: Math.round(total * 100) / 100,
    byCategory,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set<string>()
  for (const expense of expenses) {
    months.add(expense.date.slice(0, 7))
  }
  return [...months].sort().reverse()
}

import type { Expense } from './types'

const escapeCSV = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const expensesToCSV = (expenses: Expense[]): string => {
  const header = 'ID,Amount,Category,Date,Notes,Created At'
  const rows = expenses.map((e) =>
    [
      e.id,
      e.amount.toFixed(2),
      e.category,
      e.date,
      escapeCSV(e.notes ?? ''),
      e.createdAt,
    ].join(',')
  )
  return [header, ...rows].join('\n')
}

import type { MonthlySummary, Category } from './types'
import { CATEGORIES, CATEGORY_COLORS } from './types'
import { h } from 'plaited'

type SliceData = {
  category: Category
  amount: number
  percentage: number
  startAngle: number
  endAngle: number
}

const polarToCartesian = (cx: number, cy: number, r: number, angle: number) => ({
  x: cx + r * Math.cos(angle),
  y: cy + r * Math.sin(angle),
})

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, startAngle)
  const end = polarToCartesian(cx, cy, r, endAngle)
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0
  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const buildSlices = (summary: MonthlySummary): SliceData[] => {
  const slices: SliceData[] = []
  let currentAngle = -Math.PI / 2 // start at top

  for (const category of CATEGORIES) {
    const amount = summary.byCategory[category]
    if (amount <= 0) continue
    const percentage = (amount / summary.total) * 100
    const sliceAngle = (amount / summary.total) * 2 * Math.PI
    slices.push({
      category,
      amount,
      percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
    })
    currentAngle += sliceAngle
  }
  return slices
}

export const renderPieChart = (summary: MonthlySummary): ReturnType<typeof h> => {
  if (summary.total === 0) {
    return h('p', { style: { color: '#888', textAlign: 'center', padding: '2rem' } }, 'No expenses recorded for this month.')
  }

  const cx = 100
  const cy = 100
  const r = 90
  const slices = buildSlices(summary)

  // Handle single-category case (full circle)
  const paths = slices.length === 1
    ? [h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: CATEGORY_COLORS[slices[0].category] })]
    : slices.map((slice) =>
        h('path', {
          d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
          fill: CATEGORY_COLORS[slice.category],
        })
      )

  const legend = slices.map((slice) =>
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.25rem' } },
      h('span', {
        style: {
          width: '14px',
          height: '14px',
          borderRadius: '3px',
          backgroundColor: CATEGORY_COLORS[slice.category],
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', { style: { fontSize: '0.875rem' } },
        `${slice.category}: $${slice.amount.toFixed(2)} (${slice.percentage.toFixed(1)}%)`
      )
    )
  )

  return h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '1.5rem', alignItems: 'center', justifyContent: 'center' } },
    h('svg', { viewBox: '0 0 200 200', width: '220', height: '220' }, ...paths),
    h('div', {}, ...legend)
  )
}

