    h('form', { 'p-trigger': 'add-expense', method: 'POST' },
      h('div', { style: styles.formRow },
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'Amount ($)'),
          h('input', {
            type: 'number',
            name: 'amount',
            step: '0.01',
            min: '0.01',
            required: 'true',
            placeholder: '0.00',
            style: styles.input,
          })
        ),
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'Category'),
          h('select', { name: 'category', required: 'true', style: styles.select },
            ...categoryOptions
          )
        ),
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'Date'),
          h('input', {
            type: 'date',
            name: 'date',
            value: today,
            required: 'true',
            style: styles.input,
          })
        ),
      ),
      h('div', { style: styles.formRow },
        h('div', { style: { ...styles.field, flex: '3' } },
          h('label', { style: styles.label }, 'Notes (optional)'),
          h('input', {
            type: 'text',
            name: 'notes',
            placeholder: 'What was this expense for?',
            style: styles.input,
          })
        ),
        h('div', { style: { display: 'flex', alignItems: 'flex-end' } },
          h('button', { type: 'submit', style: styles.button }, 'Add')
        ),
      )
    )
  )
}

export const renderFilterBar = (filter: ExpenseFilter): ReturnType<typeof h> => {
