      h('option', {
        value: cat,
        ...(filter.category === cat ? { selected: 'true' } : {}),
      }, cat.charAt(0).toUpperCase() + cat.slice(1))
    ),
  ]

  return h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Filter & Export'),
    h('form', { 'p-trigger': 'filter-expenses', method: 'GET' },
      h('div', { style: styles.formRow },
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'From'),
          h('input', {
            type: 'date',
            name: 'startDate',
            value: filter.startDate ?? '',
            style: styles.input,
          })
        ),
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'To'),
          h('input', {
            type: 'date',
            name: 'endDate',
            value: filter.endDate ?? '',
            style: styles.input,
          })
        ),
        h('div', { style: styles.field },
          h('label', { style: styles.label }, 'Category'),
          h('select', { name: 'category', style: styles.select }, ...categoryOptions)
        ),
        h('div', { style: { display: 'flex', alignItems: 'flex-end', gap: '0.5rem' } },
          h('button', { type: 'submit', style: styles.button }, 'Filter'),
          h('button', { type: 'button', 'p-trigger': 'export-csv', style: styles.buttonSecondary }, 'Export CSV'),
        ),
      )
