export const renderExpenseTable = (expenses: Expense[]): ReturnType<typeof h> => {
  if (expenses.length === 0) {
    return h('div', { style: { ...styles.card, textAlign: 'center', color: '#888' } },
      'No expenses match the current filter.'
    )
  }

  const sorted = [...expenses].sort((a, b) => b.date.localeCompare(a.date))

  const rows = sorted.map((e) =>
    h('tr', {},
      h('td', { style: styles.td }, e.date),
      h('td', { style: styles.td },
        h('span', { style: styles.badge(e.category) }, e.category)
      ),
      h('td', { style: { ...styles.td, fontWeight: '600' } }, `$${e.amount.toFixed(2)}`),
      h('td', { style: { ...styles.td, color: '#666' } }, e.notes ?? '—'),
      h('td', { style: styles.td },
        h('button', {
          'p-trigger': 'delete-expense',
          'data-id': e.id,
          style: {
            background: 'none',
            border: 'none',
            color: '#ef4444',
            cursor: 'pointer',
            fontSize: '0.8rem',
          },
        }, 'Delete')
      )
    )
  )

  return h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, `Expenses (${expenses.length})`),
    h('table', { style: styles.table },
      h('thead', {},
        h('tr', {},
          h('th', { style: styles.th }, 'Date'),
          h('th', { style: styles.th }, 'Category'),
          h('th', { style: styles.th }, 'Amount'),
          h('th', { style: styles.th }, 'Notes'),
          h('th', { style: styles.th }, ''),
        )
      ),
      h('tbody', {}, ...rows)
    )
  )
}

export const renderMonthlySummary = (summary: MonthlySummary, availableMonths: string[]): ReturnType<typeof h> => {
  const monthOptions = availableMonths.map((m) => {
    const [year, mon] = m.split('-')
    const label = new Date(Number(year), Number(mon) - 1).toLocaleString('en-US', { month: 'long', year: 'numeric' })
    return h('option', {
      value: m,
      ...(m === summary.month ? { selected: 'true' } : {}),
    }, label)
  })

  return h('div', { style: styles.card },
    h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' } },
      h('div', { style: styles.cardTitle }, 'Monthly Summary'),
      h('select', {
        'p-trigger': 'select-month',
        name: 'month',
        style: styles.select,
      }, ...monthOptions)
    ),
    h('div', { style: styles.summaryTotal }, `$${summary.total.toFixed(2)}`),
    renderPieChart(summary),
  )
}

