import { createSSR } from 'plaited'
import { addExpense, deleteExpense, getExpenses } from './expenses'
import { buildMonthlySummary, getAvailableMonths } from './summary'
import { expensesToCSV } from './csv'
import { renderPage } from './ui'
import type { Category, ExpenseFilter } from './types'
import { CATEGORIES } from './types'

const todayISO = (): string => new Date().toISOString().slice(0, 10)

const currentMonth = (): string => todayISO().slice(0, 7)

const parseFilter = (url: URL): ExpenseFilter => {
  const startDate = url.searchParams.get('startDate') || undefined
  const endDate = url.searchParams.get('endDate') || undefined
  const category = url.searchParams.get('category') as Category | undefined
  return {
    startDate: startDate || undefined,
    endDate: endDate || undefined,
    category: category && CATEGORIES.includes(category) ? category : undefined,
  }
}

const handleAddExpense = async (req: Request): Promise<Response> => {
  const form = await req.formData()
  const amount = parseFloat(form.get('amount') as string)
  const category = form.get('category') as Category
  const date = form.get('date') as string
  const notes = (form.get('notes') as string) || undefined

  if (!amount || amount <= 0 || !CATEGORIES.includes(category) || !date) {
    return new Response('Invalid expense data', { status: 400 })
  }

  await addExpense(amount, category, date, notes)
  return Response.redirect('/', 303)
}

const handleDeleteExpense = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const id = url.searchParams.get('id')
  if (id) await deleteExpense(id)
  return Response.redirect('/', 303)
}

const handleExportCSV = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const filter = parseFilter(url)
  const expenses = await getExpenses(filter)
  const csv = expensesToCSV(expenses)
  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv',
      'Content-Disposition': `attachment; filename="expenses-${todayISO()}.csv"`,
    },
  })
}

const handlePage = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const filter = parseFilter(url)
  const selectedMonth = url.searchParams.get('month') || currentMonth()

  const allExpenses = await getExpenses()
  const filteredExpenses = await getExpenses(filter)
  const summary = buildMonthlySummary(allExpenses, selectedMonth)
  const availableMonths = getAvailableMonths(allExpenses)

  // Ensure current month is always in the list
  if (!availableMonths.includes(selectedMonth)) {
    availableMonths.unshift(selectedMonth)
  }

  const { ssr } = createSSR()
  const content = renderPage(todayISO(), filteredExpenses, filter, summary, availableMonths)
  const html = ssr(content)

  const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Expense Logger</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`

  return new Response(page, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export default {
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    if (req.method === 'POST' && url.pathname === '/add') {
      return handleAddExpense(req)
    }
    if (url.pathname === '/delete') {
      return handleDeleteExpense(req)
    }
    if (url.pathname === '/export') {
      return handleExportCSV(req)
    }
    return handlePage(req)
  },
}

