import type { InventoryData, InventoryItem, NewItemInput, UpdateItemInput } from './types'

const DATA_PATH = 'data/inventory.json'

const generateId = (): string => crypto.randomUUID()

const readData = async (): Promise<InventoryData> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    return { items: [] }
  }
  return file.json()
}

const writeData = async (data: InventoryData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getAllItems = async (): Promise<InventoryItem[]> => {
  const data = await readData()
  return data.items
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const data = await readData()
  return data.items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const data = await readData()
  return data.items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const data = await readData()
  const now = new Date().toISOString()
  const item: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now,
    updatedAt: now,
  }
  data.items.push(item)
  await writeData(data)
  return item
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem | undefined> => {
  const data = await readData()
  const index = data.items.findIndex((item) => item.id === id)
  if (index === -1) return undefined
  const existing = data.items[index]
  const updated: InventoryItem = {
    ...existing,
    ...input,
    id: existing.id,
    createdAt: existing.createdAt,
    updatedAt: new Date().toISOString(),
  }
  data.items[index] = updated
  await writeData(data)
  return updated
}

export const deleteItem = async (id: string): Promise<boolean> => {
  const data = await readData()
  const index = data.items.findIndex((item) => item.id === id)
  if (index === -1) return false
  data.items.splice(index, 1)
  await writeData(data)
  return true
}

export const bulkImport = async (items: NewItemInput[]): Promise<InventoryItem[]> => {
  const data = await readData()
  const now = new Date().toISOString()
  const newItems: InventoryItem[] = items.map((input) => ({
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now,
    updatedAt: now,
  }))
  data.items.push(...newItems)
  await writeData(data)
  return newItems
}

export const searchItems = async (query: string): Promise<InventoryItem[]> => {
  const data = await readData()
  const q = query.toLowerCase()
  return data.items.filter(
    (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q),
  )
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const data = await readData()
  return data.items.filter((item) => item.quantity <= item.reorderThreshold)
}

import {
  getAllItems,
  getItemById,
  getItemBySku,
  addItem,
  updateItem,
  deleteItem,
  bulkImport,
  searchItems,
  getLowStockItems,
} from './store'
import { renderDashboard, renderSearchResults, renderItemDetail } from './ui'
import type { NewItemInput, UpdateItemInput } from './types'

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (location: string) =>
  new Response(null, {
    status: 302,
    headers: { Location: location },
  })

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // GET / — Dashboard
    if (method === 'GET' && path === '/') {
      const [items, lowStock] = await Promise.all([getAllItems(), getLowStockItems()])
      return htmlResponse(renderDashboard(items, lowStock))
    }

    // GET /search?q=... — Search
    if (method === 'GET' && path === '/search') {
      const query = url.searchParams.get('q') ?? ''
      const results = await searchItems(query)
      return htmlResponse(renderSearchResults(results, query))
    }

    // GET /alerts — Low stock items (JSON API)
    if (method === 'GET' && path === '/alerts') {
      const lowStock = await getLowStockItems()
      return jsonResponse(lowStock)
    }

    // GET /item/:id — Item detail
    const itemGetMatch = path.match(/^\/item\/([^/]+)$/)
    if (method === 'GET' && itemGetMatch) {
      const item = await getItemById(itemGetMatch[1])
      if (!item) return jsonResponse({ error: 'Item not found' }, 404)
      const accept = req.headers.get('accept') ?? ''
      if (accept.includes('text/html')) {
        return htmlResponse(renderItemDetail(item))
      }
      return jsonResponse(item)
    }

    // POST /item — Add item (form or JSON)
    if (method === 'POST' && path === '/item') {
      const contentType = req.headers.get('content-type') ?? ''
      let input: NewItemInput
      if (contentType.includes('application/json')) {
        input = await req.json()
      } else {
        const form = await parseFormBody(req)
        input = {
          name: form.name,
          sku: form.sku,
          quantity: Number(form.quantity),
          category: form.category,
          reorderThreshold: Number(form.reorderThreshold),
        }
      }
      if (!input.name || !input.sku) {
        return jsonResponse({ error: 'name and sku are required' }, 400)
      }
      const item = await addItem(input)
      if (contentType.includes('application/json')) {
        return jsonResponse(item, 201)
      }
      return redirect('/')
    }

    // PUT /item/:id — Update item
    const itemPutMatch = path.match(/^\/item\/([^/]+)$/)
    if (method === 'PUT' && itemPutMatch) {
      const input: UpdateItemInput = await req.json()
      const item = await updateItem(itemPutMatch[1], input)
      if (!item) return jsonResponse({ error: 'Item not found' }, 404)
      return jsonResponse(item)
    }

    // DELETE /item/:id — Delete item
    const itemDeleteMatch = path.match(/^\/item\/([^/]+)$/)
    if (method === 'DELETE' && itemDeleteMatch) {
      const deleted = await deleteItem(itemDeleteMatch[1])
      if (!deleted) return jsonResponse({ error: 'Item not found' }, 404)
      return jsonResponse({ success: true })
    }

    // POST /item/:id/delete — Delete via form (HTML fallback)
    const formDeleteMatch = path.match(/^\/item\/([^/]+)\/delete$/)
    if (method === 'POST' && formDeleteMatch) {
      await deleteItem(formDeleteMatch[1])
      return redirect('/')
    }

    // POST /import — Bulk import
    if (method === 'POST' && path === '/import') {
      const contentType = req.headers.get('content-type') ?? ''
      let items: NewItemInput[]
      if (contentType.includes('application/json')) {
        items = await req.json()
      } else {
        const form = await parseFormBody(req)
        try {
          items = JSON.parse(form.items)
        } catch {
          return jsonResponse({ error: 'Invalid JSON in items field' }, 400)
        }
      }
      if (!Array.isArray(items)) {
        return jsonResponse({ error: 'Expected a JSON array of items' }, 400)
      }
      const imported = await bulkImport(items)
      if (contentType.includes('application/json')) {
        return jsonResponse({ imported: imported.length, items: imported }, 201)
      }
      return redirect('/')
    }

    // POST /barcode — Barcode/SKU lookup
    if (method === 'POST' && path === '/barcode') {
      const contentType = req.headers.get('content-type') ?? ''
      let sku: string
      if (contentType.includes('application/json')) {
        const body = await req.json()
        sku = body.sku
      } else {
        const form = await parseFormBody(req)
        sku = form.sku
      }
      if (!sku) {
        return jsonResponse({ error: 'sku is required' }, 400)
      }
      const item = await getItemBySku(sku)
      if (!item) {
        const results = await searchItems(sku)
        if (results.length > 0) {
          return htmlResponse(renderSearchResults(results, sku))
        }
        return htmlResponse(renderSearchResults([], sku))
      }
      return htmlResponse(renderItemDetail(item))
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

