export type BookStatus = 'want-to-read' | 'reading' | 'completed';

export type Book = {
  id: string;
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  currentPage: number;
  status: BookStatus;
  coverImageUrl: string;
  dateAdded: string;
};

export type ReadingListData = {
  books: Book[];
};

export type BookInput = {
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  coverImageUrl?: string;
};

export type FilterOptions = {
  status?: BookStatus;
  genre?: string;
};

export type ReadingStats = {
  totalBooks: number;
  booksCompleted: number;
  booksReading: number;
  booksWantToRead: number;
  totalPagesRead: number;
  averageProgress: number;
  genres: string[];
};

import type { Book, BookInput, BookStatus, ReadingListData, FilterOptions, ReadingStats } from './types';

const DATA_PATH = 'data/reading-list.json';

const generateId = (): string => crypto.randomUUID();

const loadData = async (): Promise<ReadingListData> => {
  const file = Bun.file(DATA_PATH);
  if (await file.exists()) {
    return file.json();
  }
  return { books: [] };
};

const saveData = async (data: ReadingListData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

export const addBook = async (input: BookInput): Promise<Book> => {
  const data = await loadData();
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    status: 'want-to-read',
    coverImageUrl: input.coverImageUrl ?? '',
    dateAdded: new Date().toISOString(),
  };
  data.books.push(book);
  await saveData(data);
  return book;
};

export const updateProgress = async (bookId: string, currentPage: number): Promise<Book | null> => {
  const data = await loadData();
  const book = data.books.find((b) => b.id === bookId);
  if (!book) return null;
  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount));
  if (book.currentPage === book.pageCount) {
    book.status = 'completed';
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading';
  }
  await saveData(data);
  return book;
};

export const updateStatus = async (bookId: string, status: BookStatus): Promise<Book | null> => {
  const data = await loadData();
  const book = data.books.find((b) => b.id === bookId);
  if (!book) return null;
  book.status = status;
  if (status === 'completed') {
    book.currentPage = book.pageCount;
  }
  await saveData(data);
  return book;
};

export const removeBook = async (bookId: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.books.findIndex((b) => b.id === bookId);
  if (idx === -1) return false;
  data.books.splice(idx, 1);
  await saveData(data);
  return true;
};

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  const data = await loadData();
  let books = data.books;
  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status);
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase());
  }
  return books;
};

export const getBook = async (bookId: string): Promise<Book | null> => {
  const data = await loadData();
  return data.books.find((b) => b.id === bookId) ?? null;
};

export const getStats = async (): Promise<ReadingStats> => {
  const data = await loadData();
  const books = data.books;
  const completed = books.filter((b) => b.status === 'completed');
  const reading = books.filter((b) => b.status === 'reading');
  const wantToRead = books.filter((b) => b.status === 'want-to-read');
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0);
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / books.length
      : 0;
  const genres = [...new Set(books.map((b) => b.genre))].sort();

  return {
    totalBooks: books.length,
    booksCompleted: completed.length,
    booksReading: reading.length,
    booksWantToRead: wantToRead.length,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 100),
    genres,
  };
};

export const getGenres = async (): Promise<string[]> => {
  const data = await loadData();
  return [...new Set(data.books.map((b) => b.genre))].sort();
};

