import { addBook, updateProgress, updateStatus, removeBook, getBooks, getBook, getStats, getGenres } from './store';
import { renderPage, renderBookItem } from './render';
import type { BookStatus, BookInput, FilterOptions } from './types';

const parseFilters = (url: URL): FilterOptions => {
  const status = url.searchParams.get('status') as BookStatus | null;
  const genre = url.searchParams.get('genre');
  return {
    ...(status ? { status } : {}),
    ...(genre ? { genre } : {}),
  };
};

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const handleGetIndex = async (url: URL): Promise<Response> => {
  const filters = parseFilters(url);
  const [books, stats, genres] = await Promise.all([getBooks(filters), getStats(), getGenres()]);
  const html = renderPage(books, stats, genres, filters);
  return htmlResponse(html);
};

const handleAddBook = async (req: Request): Promise<Response> => {
  const body = (await req.json()) as BookInput;
  if (!body.title || !body.author || !body.genre || !body.pageCount) {
    return jsonResponse({ error: 'Missing required fields: title, author, genre, pageCount' }, 400);
  }
  const book = await addBook(body);
  return jsonResponse(book, 201);
};

const handleUpdateProgress = async (req: Request, bookId: string): Promise<Response> => {
  const body = (await req.json()) as { currentPage: number };
  if (typeof body.currentPage !== 'number') {
    return jsonResponse({ error: 'currentPage must be a number' }, 400);
  }
  const book = await updateProgress(bookId, body.currentPage);
  if (!book) return jsonResponse({ error: 'Book not found' }, 404);
  return jsonResponse(book);
};

const handleUpdateStatus = async (req: Request, bookId: string): Promise<Response> => {
  const body = (await req.json()) as { status: BookStatus };
  const validStatuses: BookStatus[] = ['want-to-read', 'reading', 'completed'];
  if (!validStatuses.includes(body.status)) {
    return jsonResponse({ error: `status must be one of: ${validStatuses.join(', ')}` }, 400);
  }
  const book = await updateStatus(bookId, body.status);
  if (!book) return jsonResponse({ error: 'Book not found' }, 404);
  return jsonResponse(book);
};

const handleRemoveBook = async (bookId: string): Promise<Response> => {
  const removed = await removeBook(bookId);
  if (!removed) return jsonResponse({ error: 'Book not found' }, 404);
  return jsonResponse({ success: true });
};

const handleGetBook = async (bookId: string): Promise<Response> => {
  const book = await getBook(bookId);
  if (!book) return jsonResponse({ error: 'Book not found' }, 404);
  return jsonResponse(book);
};

const handleGetStats = async (): Promise<Response> => {
  const stats = await getStats();
  return jsonResponse(stats);
};

export default {
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url);
    const method = req.method;
    const path = url.pathname;

    // HTML page
    if (path === '/' && method === 'GET') {
      return handleGetIndex(url);
    }

    // API: list books
    if (path === '/api/books' && method === 'GET') {
      const filters = parseFilters(url);
      const books = await getBooks(filters);
      return jsonResponse(books);
    }

    // API: add book
    if (path === '/api/books' && method === 'POST') {
      return handleAddBook(req);
    }

    // API: stats
    if (path === '/api/stats' && method === 'GET') {
      return handleGetStats();
    }

    // API: single book routes
    const bookMatch = path.match(/^\/api\/books\/([^/]+)$/);
    if (bookMatch) {
      const bookId = bookMatch[1];
      if (method === 'GET') return handleGetBook(bookId);
      if (method === 'DELETE') return handleRemoveBook(bookId);
    }

    // API: update progress
    const progressMatch = path.match(/^\/api\/books\/([^/]+)\/progress$/);
    if (progressMatch && method === 'PATCH') {
      return handleUpdateProgress(req, progressMatch[1]);
    }

    // API: update status
    const statusMatch = path.match(/^\/api\/books\/([^/]+)\/status$/);
    if (statusMatch && method === 'PATCH') {
      return handleUpdateStatus(req, statusMatch[1]);
    }

    return jsonResponse({ error: 'Not found' }, 404);
  },
};

