import { BskyAgent } from '@atproto/api'
import type { SessionData, FeedItem, ProfileView } from './types'

const SESSION_PATH = 'data/session.json'

let agent: BskyAgent | null = null

const getAgent = (): BskyAgent => {
  if (!agent) {
    agent = new BskyAgent({ service: 'https://bsky.social' })
  }
  return agent
}

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const loadSession = async (): Promise<SessionData | null> => {
  try {
    const data = await Bun.file(SESSION_PATH).json()
    if (data && data.did) return data as SessionData
    return null
  } catch {
    return null
  }
}

export const clearSession = async (): Promise<void> => {
  await Bun.write(SESSION_PATH, '{}')
  agent = null
}

export const login = async (identifier: string, password: string): Promise<SessionData> => {
  const a = getAgent()
  const response = await a.login({ identifier, password })
  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
    email: response.data.email,
  }
  await saveSession(session)
  return session
}

export const resumeSession = async (): Promise<boolean> => {
  const session = await loadSession()
  if (!session) return false
  try {
    const a = getAgent()
    await a.resumeSession({
      did: session.did,
      handle: session.handle,
      accessJwt: session.accessJwt,
      refreshJwt: session.refreshJwt,
      active: true,
    })
    return true
  } catch {
    await clearSession()
    return false
  }
}

export const isAuthenticated = (): boolean => {
  return agent?.session !== undefined
}

export const getCurrentHandle = (): string => {
  return agent?.session?.handle ?? ''
}

export const getTimeline = async (cursor?: string): Promise<{ feed: FeedItem[]; cursor?: string }> => {
  const a = getAgent()
  const response = await a.getTimeline({ limit: 30, cursor })
  return {
    feed: response.data.feed as unknown as FeedItem[],
    cursor: response.data.cursor,
  }
}

export const createPost = async (text: string): Promise<void> => {
  const a = getAgent()
  await a.post({
    text,
    createdAt: new Date().toISOString(),
  })
}

export const getProfile = async (actor: string): Promise<ProfileView> => {
  const a = getAgent()
  const response = await a.getProfile({ actor })
  return response.data as unknown as ProfileView
}

export const getAuthorFeed = async (actor: string, cursor?: string): Promise<{ feed: FeedItem[]; cursor?: string }> => {
  const a = getAgent()
  const response = await a.getAuthorFeed({ actor, limit: 20, cursor })
  return {
    feed: response.data.feed as unknown as FeedItem[],
    cursor: response.data.cursor,
  }
}

export const followUser = async (did: string): Promise<void> => {
  const a = getAgent()
  await a.follow(did)
}

export const unfollowUser = async (followUri: string): Promise<void> => {
  const a = getAgent()
  await a.deleteFollow(followUri)
}

export const likePost = async (uri: string, cid: string): Promise<void> => {
  const a = getAgent()
  await a.like(uri, cid)
}

export const unlikePost = async (likeUri: string): Promise<void> => {
  const a = getAgent()
  await a.deleteLike(likeUri)
}

