import { createSSR } from 'plaited'
import {
  login,
  resumeSession,
  clearSession,
  isAuthenticated,
  getCurrentHandle,
  getTimeline,
  createPost,
  getProfile,
  getAuthorFeed,
  followUser,
  unfollowUser,
  likePost,
  unlikePost,
} from './client'
import { loginPage, feedPage, profilePage, errorPage } from './templates'

const ssr = createSSR()

const renderHtml = (template: unknown): string => {
  const result = ssr.render(template)
  return `<!DOCTYPE html>${typeof result === 'string' ? result : String(result)}`
}

const htmlResponse = (template: unknown, status = 200): Response =>
  new Response(renderHtml(template), {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (url: string): Response =>
  new Response(null, { status: 302, headers: { Location: url } })

const parseForm = async (request: Request): Promise<Record<string, string>> => {
  const text = await request.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const requireAuth = async (): Promise<Response | null> => {
  if (!isAuthenticated()) {
    const resumed = await resumeSession()
    if (!resumed) return redirect('/')
  }
  return null
}

const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const path = url.pathname
  const method = request.method

  try {
    // --- Auth routes ---
    if (path === '/' && method === 'GET') {
      if (isAuthenticated() || await resumeSession()) {
        return redirect('/feed')
      }
      return htmlResponse(loginPage())
    }

    if (path === '/auth/login' && method === 'POST') {
      const form = await parseForm(request)
      const identifier = form.identifier?.trim()
      const password = form.password?.trim()
      if (!identifier || !password) {
        return htmlResponse(loginPage('Please enter both handle and password.'))
      }
      try {
        await login(identifier, password)
        return redirect('/feed')
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Login failed'
        return htmlResponse(loginPage(msg))
      }
    }

    if (path === '/auth/logout' && method === 'POST') {
      await clearSession()
      return redirect('/')
    }

    // --- Feed ---
    if (path === '/feed' && method === 'GET') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const cursor = url.searchParams.get('cursor') ?? undefined
      const message = url.searchParams.get('message') ?? undefined
      const timeline = await getTimeline(cursor)
      return htmlResponse(feedPage(getCurrentHandle(), timeline.feed, timeline.cursor, message))
    }

    // --- Create post ---
    if (path === '/post' && method === 'POST') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const form = await parseForm(request)
      const text = form.text?.trim()
      if (!text) return redirect('/feed')
      if (text.length > 300) {
        return redirect('/feed?message=Post+must+be+300+characters+or+less')
      }
      await createPost(text)
      return redirect('/feed?message=Post+published!')
    }

    // --- Profile ---
    if (path.startsWith('/profile/') && method === 'GET') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const handle = path.slice('/profile/'.length)
      if (!handle) return redirect('/feed')
      const cursor = url.searchParams.get('cursor') ?? undefined
      const profile = await getProfile(handle)
      const authorFeed = await getAuthorFeed(handle, cursor)
      const isOwn = handle === getCurrentHandle()
      return htmlResponse(profilePage(getCurrentHandle(), profile, authorFeed.feed, authorFeed.cursor, isOwn))
    }

    // --- Follow ---
    if (path === '/follow' && method === 'POST') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const form = await parseForm(request)
      if (form.did) {
        await followUser(form.did)
      }
      return redirect(`/profile/${form.handle || ''}`)
    }

    // --- Unfollow ---
    if (path === '/unfollow' && method === 'POST') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const form = await parseForm(request)
      if (form.followUri) {
        await unfollowUser(form.followUri)
      }
      return redirect(`/profile/${form.handle || ''}`)
    }

    // --- Like ---
    if (path === '/like' && method === 'POST') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const form = await parseForm(request)
      if (form.uri && form.cid) {
        await likePost(form.uri, form.cid)
      }
      return redirect(form.returnTo || '/feed')
    }

    // --- Unlike ---
    if (path === '/unlike' && method === 'POST') {
      const authRedirect = await requireAuth()
      if (authRedirect) return authRedirect
      const form = await parseForm(request)
      if (form.likeUri) {
        await unlikePost(form.likeUri)
      }
      return redirect(form.returnTo || '/feed')
    }

    return htmlResponse(errorPage(getCurrentHandle(), 'Page not found'), 404)
  } catch (err) {
    const msg = err instanceof Error ? err.message : 'Something went wrong'
    console.error('Request error:', err)
    return htmlResponse(errorPage(getCurrentHandle(), msg), 500)
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: handleRequest,
})

console.log(`Bluesky client running at http://localhost:${server.port}`)

