export type Message = {
  id: string;
  roomId: string;
  sender: string;
  text: string;
  timestamp: string;
};

export type Room = {
  id: string;
  name: string;
  createdAt: string;
  lastReadTimestamp: string | null;
};

export type RoomWithUnread = Room & {
  unreadCount: number;
  lastMessage: Message | null;
};

export type TypingStatus = {
  roomId: string;
  sender: string;
  isTyping: boolean;
};

import type { Message, Room, RoomWithUnread } from './types';

const ROOMS_PATH = 'data/rooms.json';
const ROOMS_DIR = 'data/rooms';

const generateId = (): string => crypto.randomUUID();

const ensureDataDir = async (): Promise<void> => {
  const { mkdir } = await import('node:fs/promises');
  await mkdir(ROOMS_DIR, { recursive: true });
};

const loadRooms = async (): Promise<Room[]> => {
  await ensureDataDir();
  const file = Bun.file(ROOMS_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_PATH, JSON.stringify(rooms, null, 2));
};

const roomFilePath = (roomId: string): string => `${ROOMS_DIR}/${roomId}.jsonl`;

const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(roomFilePath(roomId));
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message);
};

const appendMessage = async (message: Message): Promise<void> => {
  await ensureDataDir();
  const path = roomFilePath(message.roomId);
  const file = Bun.file(path);
  const existing = (await file.exists()) ? await file.text() : '';
  await Bun.write(path, existing + JSON.stringify(message) + '\n');
};

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms();
  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    lastReadTimestamp: null,
  };
  rooms.push(room);
  await saveRooms(rooms);
  return room;
};

export const listRooms = async (): Promise<RoomWithUnread[]> => {
  const rooms = await loadRooms();
  const results: RoomWithUnread[] = [];
  for (const room of rooms) {
    const messages = await loadMessages(room.id);
    const unreadCount = room.lastReadTimestamp
      ? messages.filter((m) => m.timestamp > room.lastReadTimestamp!).length
      : messages.length;
    const lastMessage = messages.length > 0 ? messages[messages.length - 1] : null;
    results.push({ ...room, unreadCount, lastMessage });
  }
  return results;
};

export const getRoom = async (roomId: string): Promise<Room | null> => {
  const rooms = await loadRooms();
  return rooms.find((r) => r.id === roomId) ?? null;
};

export const getRoomMessages = async (roomId: string): Promise<Message[]> => {
  return loadMessages(roomId);
};

export const postMessage = async (roomId: string, sender: string, text: string): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  };
  await appendMessage(message);
  return message;
};

export const markRoomRead = async (roomId: string): Promise<void> => {
  const rooms = await loadRooms();
  const room = rooms.find((r) => r.id === roomId);
  if (room) {
    room.lastReadTimestamp = new Date().toISOString();
    await saveRooms(rooms);
  }
};

/**
 * Formats message text with basic markdown-style syntax:
 * **bold** → <strong>bold</strong>
 * *italic* → <em>italic</em>
 *
 * Handles nested formatting and escapes HTML entities.
 */
const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

export const formatMessageText = (text: string): string => {
  let result = escapeHtml(text);
  // Bold: **text**
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  // Italic: *text*
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>');
  return result;
};

export const formatTimestamp = (iso: string): string => {
  const date = new Date(iso);
  const hours = date.getHours().toString().padStart(2, '0');
  const minutes = date.getMinutes().toString().padStart(2, '0');
  return `${hours}:${minutes}`;
};

