import {
  createRoom,
  listRooms,
  getRoom,
  getRoomMessages,
  postMessage,
  markRoomRead,
} from './store';
import { renderApp } from './render';
import type { TypingStatus } from './types';

export type ChatAction =
  | { type: 'listRooms' }
  | { type: 'createRoom'; name: string }
  | { type: 'selectRoom'; roomId: string }
  | { type: 'sendMessage'; roomId: string; sender: string; text: string }
  | { type: 'markRead'; roomId: string }
  | { type: 'setTyping'; roomId: string; sender: string; isTyping: boolean }
  | { type: 'render'; roomId?: string };

type ChatState = {
  activeRoomId: string | null;
  typing: TypingStatus | null;
};

const state: ChatState = {
  activeRoomId: null,
  typing: null,
};

export const handleAction = async (action: ChatAction): Promise<string> => {
  switch (action.type) {
    case 'createRoom': {
      const room = await createRoom(action.name);
      state.activeRoomId = room.id;
      return renderCurrentState();
    }

    case 'selectRoom': {
      state.activeRoomId = action.roomId;
      await markRoomRead(action.roomId);
      return renderCurrentState();
    }

    case 'sendMessage': {
      await postMessage(action.roomId, action.sender, action.text);
      return renderCurrentState();
    }

    case 'markRead': {
      await markRoomRead(action.roomId);
      return renderCurrentState();
    }

    case 'setTyping': {
      state.typing = {
        roomId: action.roomId,
        sender: action.sender,
        isTyping: action.isTyping,
      };
      return renderCurrentState();
    }

    case 'listRooms': {
      const rooms = await listRooms();
      return JSON.stringify(rooms, null, 2);
    }

    case 'render': {
      if (action.roomId) {
        state.activeRoomId = action.roomId;
      }
      return renderCurrentState();
    }

    default:
      return 'Unknown action';
  }
};

const renderCurrentState = async (): Promise<string> => {
  const rooms = await listRooms();
  const activeRoom = state.activeRoomId ? await getRoom(state.activeRoomId) : null;
  const messages = state.activeRoomId ? await getRoomMessages(state.activeRoomId) : [];
  const typing =
    state.typing && state.typing.roomId === state.activeRoomId ? state.typing : null;

  return renderApp(
    rooms,
    state.activeRoomId,
    activeRoom?.name ?? null,
    messages,
    typing,
  );
};

// CLI entry point for quick testing
const main = async () => {
  const args = process.argv.slice(2);
  const command = args[0];

  switch (command) {
    case 'create': {
      const name = args[1] ?? 'general';
      const result = await handleAction({ type: 'createRoom', name });
      console.log(result);
      break;
    }
    case 'send': {
      const [, roomId, sender, ...textParts] = args;
      if (!roomId || !sender || textParts.length === 0) {
        console.log('Usage: chat send <roomId> <sender> <message>');
        break;
      }
      const result = await handleAction({
        type: 'sendMessage',
        roomId,
        sender,
        text: textParts.join(' '),
      });
      console.log(result);
      break;
    }
    case 'rooms': {
      const result = await handleAction({ type: 'listRooms' });
      console.log(result);
      break;
    }
    case 'view': {
      const roomId = args[1];
      if (!roomId) {
        console.log('Usage: chat view <roomId>');
        break;
      }
      const result = await handleAction({ type: 'render', roomId });
      console.log(result);
      break;
    }
    default: {
      const result = await handleAction({ type: 'render' });
      console.log(result);
    }
  }
};

main();

