import type { ForumData, Thread, Reply, SortMode } from './types';

const DATA_PATH = 'data/threads.json';

const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH);
  return await file.json();
};

const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

export const getThreads = async (
  sort: SortMode = 'newest',
  query?: string
): Promise<Thread[]> => {
  const data = await loadData();
  let threads = data.threads;

  if (query) {
    const q = query.toLowerCase();
    threads = threads.filter((t) => t.title.toLowerCase().includes(q));
  }

  switch (sort) {
    case 'newest':
      threads.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
      break;
    case 'votes':
      threads.sort((a, b) => b.score - a.score);
      break;
    case 'active':
      threads.sort((a, b) => b.replies.length - a.replies.length);
      break;
  }

  return threads;
};

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const data = await loadData();
  return data.threads.find((t) => t.id === id);
};

export const createThread = async (
  title: string,
  body: string,
  author: string
): Promise<Thread> => {
  const data = await loadData();
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    score: 0,
    voters: {},
    replies: [],
  };
  data.threads.push(thread);
  await saveData(data);
  return thread;
};

export const createReply = async (
  threadId: string,
  body: string,
  author: string
): Promise<Reply | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const reply: Reply = {
    id: generateId(),
    threadId,
    body,
    author,
    createdAt: new Date().toISOString(),
    score: 0,
    voters: {},
  };
  thread.replies.push(reply);
  await saveData(data);
  return reply;
};

export const voteThread = async (
  threadId: string,
  voterId: string,
  direction: 'up' | 'down'
): Promise<Thread | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const existing = thread.voters[voterId];
  if (existing === direction) {
    // Remove vote (toggle off)
    delete thread.voters[voterId];
    thread.score += direction === 'up' ? -1 : 1;
  } else if (existing) {
    // Change vote direction
    thread.voters[voterId] = direction;
    thread.score += direction === 'up' ? 2 : -2;
  } else {
    // New vote
    thread.voters[voterId] = direction;
    thread.score += direction === 'up' ? 1 : -1;
  }

  await saveData(data);
  return thread;
};

export const voteReply = async (
  threadId: string,
  replyId: string,
  voterId: string,
  direction: 'up' | 'down'
): Promise<Reply | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const reply = thread.replies.find((r) => r.id === replyId);
  if (!reply) return null;

  const existing = reply.voters[voterId];
  if (existing === direction) {
    delete reply.voters[voterId];
    reply.score += direction === 'up' ? -1 : 1;
  } else if (existing) {
    reply.voters[voterId] = direction;
    reply.score += direction === 'up' ? 2 : -2;
  } else {
    reply.voters[voterId] = direction;
    reply.score += direction === 'up' ? 1 : -1;
  }

  await saveData(data);
  return reply;
};

