import { getThreads, getThread, createThread, createReply, voteThread, voteReply } from './store';
import { renderThreadList, renderThread, renderNewThread } from './views';
import type { SortMode } from './types';

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  for (const [key, value] of params.entries()) {
    result[key] = value;
  }
  return result;
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;

    // GET / — Thread list
    if (method === 'GET' && path === '/') {
      const sort = (url.searchParams.get('sort') || 'newest') as SortMode;
      const query = url.searchParams.get('q') || '';
      const threads = await getThreads(sort, query || undefined);
      return new Response(renderThreadList(threads, sort, query), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // GET /new — New thread form
    if (method === 'GET' && path === '/new') {
      return new Response(renderNewThread(), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // GET /thread/:id — Single thread view
    const threadMatch = path.match(/^\/thread\/([^/]+)$/);
    if (method === 'GET' && threadMatch) {
      const thread = await getThread(threadMatch[1]);
      if (!thread) {
        return new Response('Thread not found', { status: 404 });
      }
      return new Response(renderThread(thread), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // POST /threads — Create thread
    if (method === 'POST' && path === '/threads') {
      const form = await parseForm(req);
      const { title, body, author } = form;
      if (!title || !body || !author) {
        return new Response('Missing required fields', { status: 400 });
      }
      const thread = await createThread(title.trim(), body.trim(), author.trim());
      return Response.redirect(`/thread/${thread.id}`, 303);
    }

    // POST /threads/:id/replies — Add reply
    const replyMatch = path.match(/^\/threads\/([^/]+)\/replies$/);
    if (method === 'POST' && replyMatch) {
      const form = await parseForm(req);
      const { body, author } = form;
      if (!body || !author) {
        return new Response('Missing required fields', { status: 400 });
      }
      const reply = await createReply(replyMatch[1], body.trim(), author.trim());
      if (!reply) {
        return new Response('Thread not found', { status: 404 });
      }
      return Response.redirect(`/thread/${replyMatch[1]}`, 303);
    }

    // POST /threads/:id/vote — Vote on thread
    const threadVoteMatch = path.match(/^\/threads\/([^/]+)\/vote$/);
    if (method === 'POST' && threadVoteMatch) {
      const form = await parseForm(req);
      const { direction, voterId } = form;
      if (!direction || !voterId) {
        return new Response('Missing required fields', { status: 400 });
      }
      await voteThread(threadVoteMatch[1], voterId, direction as 'up' | 'down');
      const referer = req.headers.get('referer') || '/';
      return Response.redirect(referer, 303);
    }

    // POST /threads/:id/replies/:replyId/vote — Vote on reply
    const replyVoteMatch = path.match(/^\/threads\/([^/]+)\/replies\/([^/]+)\/vote$/);
    if (method === 'POST' && replyVoteMatch) {
      const form = await parseForm(req);
      const { direction, voterId } = form;
      if (!direction || !voterId) {
        return new Response('Missing required fields', { status: 400 });
      }
      await voteReply(replyVoteMatch[1], replyVoteMatch[2], voterId, direction as 'up' | 'down');
      const referer = req.headers.get('referer') || '/';
      return Response.redirect(referer, 303);
    }

    // GET /api/threads — JSON API
    if (method === 'GET' && path === '/api/threads') {
      const sort = (url.searchParams.get('sort') || 'newest') as SortMode;
      const query = url.searchParams.get('q') || '';
      const threads = await getThreads(sort, query || undefined);
      return Response.json(threads);
    }

    return new Response('Not Found', { status: 404 });
  },
});

