import type { CurrentWeather, ForecastResponse, DayForecast, TemperaturePoint } from './types';

const API_BASE = 'https://api.openweathermap.org/data/2.5';

const celsiusToFahrenheit = (c: number): number => Math.round((c * 9) / 5 + 32);

const roundTemp = (t: number): number => Math.round(t * 10) / 10;

const getDayName = (timestamp: number): string => {
  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  return days[new Date(timestamp * 1000).getDay()];
};

const formatDate = (timestamp: number): string => {
  const d = new Date(timestamp * 1000);
  return `${d.getMonth() + 1}/${d.getDate()}`;
};

const getIconUrl = (iconCode: string): string =>
  `https://openweathermap.org/img/wn/${iconCode}@2x.png`;

const loadSampleData = async (): Promise<{ current: CurrentWeather; forecast: ForecastResponse }> => {
  const raw = await Bun.file('data/sample-weather.json').json();
  return raw as { current: CurrentWeather; forecast: ForecastResponse };
};

const fetchCurrentWeather = async (city: string, apiKey: string): Promise<CurrentWeather> => {
  const url = `${API_BASE}/weather?q=${encodeURIComponent(city)}&units=metric&appid=${apiKey}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Weather API error: ${res.status}`);
  return res.json() as Promise<CurrentWeather>;
};

const fetchForecast = async (city: string, apiKey: string): Promise<ForecastResponse> => {
  const url = `${API_BASE}/forecast?q=${encodeURIComponent(city)}&units=metric&appid=${apiKey}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Forecast API error: ${res.status}`);
  return res.json() as Promise<ForecastResponse>;
};

export const getWeatherData = async (city: string): Promise<{ current: CurrentWeather; forecast: ForecastResponse }> => {
  const apiKey = process.env.OPENWEATHER_API_KEY;
  if (apiKey) {
    const [current, forecast] = await Promise.all([
      fetchCurrentWeather(city, apiKey),
      fetchForecast(city, apiKey),
    ]);
    return { current, forecast };
  }
  return loadSampleData();
};

export const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, { temps: number[]; entries: ForecastResponse['list'] }>();

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0];
    const existing = dayMap.get(dateKey);
    if (existing) {
      existing.temps.push(entry.main.temp_min, entry.main.temp_max);
      existing.entries.push(entry);
    } else {
      dayMap.set(dateKey, {
        temps: [entry.main.temp_min, entry.main.temp_max],
        entries: [entry],
      });
    }
  }

  const days: DayForecast[] = [];
  for (const [date, data] of dayMap) {
    const midday = data.entries.find((e) => e.dt_txt.includes('12:00:00')) ?? data.entries[0];
    days.push({
      date,
      dayName: getDayName(midday.dt),
      tempMin: roundTemp(Math.min(...data.temps)),
      tempMax: roundTemp(Math.max(...data.temps)),
      icon: midday.weather[0].icon,
      description: midday.weather[0].description,
    });
  }

  return days.slice(0, 5);
};

export const extractTemperaturePoints = (forecast: ForecastResponse): TemperaturePoint[] =>
  forecast.list.map((entry) => ({
    label: `${getDayName(entry.dt)} ${formatDate(entry.dt)}`,
    tempC: roundTemp(entry.main.temp),
  }));

