type ChartConfig = {
  width: number;
  height: number;
  padding: { top: number; right: number; bottom: number; left: number };
};

const defaultConfig: ChartConfig = {
  width: 700,
  height: 280,
  padding: { top: 20, right: 20, bottom: 50, left: 50 },
};

export const renderTemperatureChart = (points: TemperaturePoint[], config: ChartConfig = defaultConfig) => {
  const { width, height, padding } = config;
  const plotW = width - padding.left - padding.right;
  const plotH = height - padding.top - padding.bottom;

  if (points.length === 0) {
    return h('svg', { width: String(width), height: String(height) },
      h('text', { x: String(width / 2), y: String(height / 2), 'text-anchor': 'middle', fill: '#888' }, 'No data'),
    );
  }

  const temps = points.map((p) => p.tempC);
  const minT = Math.floor(Math.min(...temps) - 2);
  const maxT = Math.ceil(Math.max(...temps) + 2);
  const rangeT = maxT - minT || 1;

  const xScale = (i: number): number => padding.left + (i / (points.length - 1)) * plotW;
  const yScale = (t: number): number => padding.top + plotH - ((t - minT) / rangeT) * plotH;

  const linePath = points
    .map((p, i) => `${i === 0 ? 'M' : 'L'}${xScale(i).toFixed(1)},${yScale(p.tempC).toFixed(1)}`)
    .join(' ');

  const gridLines: number[] = [];
  const step = rangeT <= 10 ? 2 : 5;
  for (let t = Math.ceil(minT / step) * step; t <= maxT; t += step) {
    gridLines.push(t);
  }

  const labelInterval = Math.max(1, Math.floor(points.length / 6));

  return h('svg', {
    width: '100%',
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
    style: 'font-family: -apple-system, BlinkMacSystemFont, sans-serif; background: #1e2a3a; border-radius: 8px;',
  },
    // Grid lines + Y-axis labels
    ...gridLines.map((t) =>
      h('g', {},
        h('line', {
          x1: String(padding.left),
          y1: String(yScale(t).toFixed(1)),
          x2: String(width - padding.right),
          y2: String(yScale(t).toFixed(1)),
          stroke: '#2a3a4a',
          'stroke-width': '1',
        }),
        h('text', {
          x: String(padding.left - 8),
          y: String((yScale(t) + 4).toFixed(1)),
          'text-anchor': 'end',
          fill: '#8899aa',
          'font-size': '11',
        }, `${t}\u00B0C / ${celsiusToFahrenheit(t)}\u00B0F`),
      ),
    ),
    // Temperature line
    h('path', {
      d: linePath,
      fill: 'none',
      stroke: '#4fc3f7',
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
      'stroke-linecap': 'round',
    }),
    // Data points
    ...points.map((p, i) =>
      h('circle', {
        cx: String(xScale(i).toFixed(1)),
        cy: String(yScale(p.tempC).toFixed(1)),
        r: '4',
        fill: '#4fc3f7',
        stroke: '#1e2a3a',
        'stroke-width': '2',
      }),
    ),
    // X-axis labels
    ...points
      .filter((_, i) => i % labelInterval === 0 || i === points.length - 1)
      .map((p, _, arr) => {
        const origIdx = points.indexOf(p);
        return h('text', {
          x: String(xScale(origIdx).toFixed(1)),
          y: String(height - 8),
          'text-anchor': 'middle',
          fill: '#8899aa',
          'font-size': '10',
          transform: `rotate(-25, ${xScale(origIdx).toFixed(1)}, ${height - 8})`,
        }, p.label);
      }),
    // Title
    h('text', {
      x: String(width / 2),
      y: '15',
      'text-anchor': 'middle',
      fill: '#ccd6e0',
      'font-size': '13',
      'font-weight': 'bold',
    }, 'Temperature Trend'),
  );
};

