const DEFAULT_CITY = 'London';

export const renderWeatherDashboard = async (city: string = DEFAULT_CITY): Promise<string> => {
  const { current, forecast } = await getWeatherData(city);
  const dailyForecasts = aggregateDailyForecasts(forecast);
  const temperaturePoints = extractTemperaturePoints(forecast);
  const template = renderDashboard(current, dailyForecasts, temperaturePoints, city);
  const ssr = createSSR();
  return ssr(template);
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const city = url.searchParams.get('city') ?? DEFAULT_CITY;

  const dashboardHtml = await renderWeatherDashboard(city);

  const html = `<!DOCTYPE html>
<html lang="en">
