export type FieldType = 'numeric' | 'categorical'

export type FieldInfo = {
  name: string
  type: FieldType
}

export const detectFields = (data: Record<string, unknown>[]): FieldInfo[] => {
  if (!data.length) return []

  const keys = Object.keys(data[0])

  return keys.map((name) => {
    const numericCount = data.filter((row) => {
      const v = row[name]
      return typeof v === 'number' && !Number.isNaN(v)
    }).length

    const type: FieldType =
      numericCount / data.length > 0.8 ? 'numeric' : 'categorical'

    return { name, type }
  })
}

export const getNumericFields = (fields: FieldInfo[]): FieldInfo[] =>
  fields.filter((f) => f.type === 'numeric')

export const getCategoricalFields = (fields: FieldInfo[]): FieldInfo[] =>
  fields.filter((f) => f.type === 'categorical')

import { defaultPalette } from './colors'

export type ChartType = 'bar' | 'line' | 'pie'

export type ChartConfig = {
  type: ChartType
  title: string
  xLabel: string
  yLabel: string
  width: number
  height: number
  colors: string[]
  labelField: string
  valueField: string
}

const defaults: ChartConfig = {
  type: 'bar',
  title: '',
  xLabel: '',
  yLabel: '',
  width: 800,
  height: 500,
  colors: defaultPalette,
  labelField: '',
  valueField: '',
}

const esc = (s: string): string =>
  s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const truncate = (s: string, max: number): string =>
  s.length > max ? s.slice(0, max - 1) + '\u2026' : s

/* ── Axis tick computation ─────────────────────────────────── */

const niceNum = (range: number, round: boolean): number => {
  if (range <= 0) return 1
  const exp = Math.floor(Math.log10(range))
  const frac = range / 10 ** exp
  let nice: number
  if (round) {
    nice = frac < 1.5 ? 1 : frac < 3 ? 2 : frac < 7 ? 5 : 10
  } else {
    nice = frac <= 1 ? 1 : frac <= 2 ? 2 : frac <= 5 ? 5 : 10
  }
  return nice * 10 ** exp
}

const computeTicks = (maxVal: number, count = 6): number[] => {
  if (maxVal <= 0) return [0, 1]
  const range = niceNum(maxVal, false)
  const spacing = niceNum(range / (count - 1), true)
  const niceMax = Math.ceil(maxVal / spacing) * spacing
  const ticks: number[] = []
  for (let v = 0; v <= niceMax + spacing * 0.01; v += spacing) {
    ticks.push(Math.round(v * 1e6) / 1e6)
  }
  return ticks
}

const formatNum = (n: number): string =>
  n >= 1e6
    ? (n / 1e6).toFixed(1) + 'M'
    : n >= 1e3
      ? (n / 1e3).toFixed(1) + 'K'
      : String(Math.round(n * 100) / 100)

/* ── Bar Chart ─────────────────────────────────────────────── */

const renderBarChart = (
  data: Record<string, unknown>[],
  cfg: ChartConfig,
): string => {
  const { width, height, title, xLabel, yLabel, colors, labelField, valueField } = cfg
  const labels = data.map((d) => String(d[labelField] ?? ''))
  const values = data.map((d) => Number(d[valueField]) || 0)
  const n = labels.length

  const margin = {
    top: title ? 50 : 30,
    right: 30,
    bottom: xLabel ? 80 : 60,
    left: yLabel ? 80 : 65,
  }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const maxVal = Math.max(...values, 0)
  const ticks = computeTicks(maxVal)
  const niceMax = ticks[ticks.length - 1] || 1

  const slotW = plotW / n
  const barW = slotW * 0.7
  const gap = slotW * 0.15

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui,-apple-system,sans-serif">`
  svg += `<rect width="${width}" height="${height}" fill="#fafafa" rx="4"/>`

  // Grid + Y-axis ticks
  for (const tick of ticks) {
    const y = margin.top + plotH - (tick / niceMax) * plotH
    svg += `<line x1="${margin.left}" y1="${y}" x2="${width - margin.right}" y2="${y}" stroke="#e5e7eb" stroke-width="1"/>`
    svg += `<text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" fill="#6b7280" font-size="11">${formatNum(tick)}</text>`
  }

  // Bars
  for (let i = 0; i < n; i++) {
    const x = margin.left + i * slotW + gap
    const barH = (values[i] / niceMax) * plotH
    const y = margin.top + plotH - barH
    const color = colors[i % colors.length]

    svg += `<rect x="${x}" y="${y}" width="${barW}" height="${barH}" fill="${color}" rx="3">`
    svg += `<title>${esc(labels[i])}: ${values[i]}</title></rect>`

    // Value label on top
    svg += `<text x="${x + barW / 2}" y="${y - 6}" text-anchor="middle" fill="#374151" font-size="10" font-weight="500">${formatNum(values[i])}</text>`

    // X-axis label
    svg += `<text x="${x + barW / 2}" y="${margin.top + plotH + 18}" text-anchor="middle" fill="#6b7280" font-size="11">${esc(truncate(labels[i], 14))}</text>`
  }

  // Axes
  svg += `<line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + plotH}" stroke="#374151" stroke-width="1.5"/>`
  svg += `<line x1="${margin.left}" y1="${margin.top + plotH}" x2="${width - margin.right}" y2="${margin.top + plotH}" stroke="#374151" stroke-width="1.5"/>`

  // Title
  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" fill="#111827" font-size="17" font-weight="600">${esc(title)}</text>`
  }

  // Axis labels
  if (xLabel) {
    svg += `<text x="${margin.left + plotW / 2}" y="${height - 10}" text-anchor="middle" fill="#374151" font-size="13">${esc(xLabel)}</text>`
  }
  if (yLabel) {
    svg += `<text x="16" y="${margin.top + plotH / 2}" text-anchor="middle" fill="#374151" font-size="13" transform="rotate(-90,16,${margin.top + plotH / 2})">${esc(yLabel)}</text>`
  }

  svg += '</svg>'
  return svg
}

/* ── Line Chart ────────────────────────────────────────────── */

const renderLineChart = (
  data: Record<string, unknown>[],
  cfg: ChartConfig,
): string => {
  const { width, height, title, xLabel, yLabel, colors, labelField, valueField } = cfg
  const labels = data.map((d) => String(d[labelField] ?? ''))
  const values = data.map((d) => Number(d[valueField]) || 0)
  const n = labels.length

  const margin = {
    top: title ? 50 : 30,
    right: 30,
    bottom: xLabel ? 80 : 60,
    left: yLabel ? 80 : 65,
  }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const maxVal = Math.max(...values, 0)
  const ticks = computeTicks(maxVal)
  const niceMax = ticks[ticks.length - 1] || 1

  const points = values.map((v, i) => ({
    x: margin.left + (n > 1 ? (i / (n - 1)) * plotW : plotW / 2),
    y: margin.top + plotH - (v / niceMax) * plotH,
  }))

  const lineColor = colors[0]

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui,-apple-system,sans-serif">`
  svg += `<rect width="${width}" height="${height}" fill="#fafafa" rx="4"/>`

  // Grid + Y-axis ticks
  for (const tick of ticks) {
    const y = margin.top + plotH - (tick / niceMax) * plotH
    svg += `<line x1="${margin.left}" y1="${y}" x2="${width - margin.right}" y2="${y}" stroke="#e5e7eb" stroke-width="1"/>`
    svg += `<text x="${margin.left - 10}" y="${y + 4}" text-anchor="end" fill="#6b7280" font-size="11">${formatNum(tick)}</text>`
  }

  // Area fill
  if (points.length > 1) {
    const baseline = margin.top + plotH
    const areaD =
      `M${points[0].x},${baseline} ` +
      points.map((p) => `L${p.x},${p.y}`).join(' ') +
      ` L${points[points.length - 1].x},${baseline} Z`
    svg += `<path d="${areaD}" fill="${lineColor}" opacity="0.1"/>`
  }

  // Line
  if (points.length > 1) {
    const lineD = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join(' ')
    svg += `<path d="${lineD}" fill="none" stroke="${lineColor}" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>`
  }

  // Points + X-axis labels
  for (let i = 0; i < n; i++) {
    const p = points[i]
    svg += `<circle cx="${p.x}" cy="${p.y}" r="4.5" fill="${lineColor}" stroke="#fff" stroke-width="2">`
    svg += `<title>${esc(labels[i])}: ${values[i]}</title></circle>`

    svg += `<text x="${p.x}" y="${margin.top + plotH + 18}" text-anchor="middle" fill="#6b7280" font-size="11">${esc(truncate(labels[i], 14))}</text>`
  }

  // Axes
  svg += `<line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + plotH}" stroke="#374151" stroke-width="1.5"/>`
  svg += `<line x1="${margin.left}" y1="${margin.top + plotH}" x2="${width - margin.right}" y2="${margin.top + plotH}" stroke="#374151" stroke-width="1.5"/>`

  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" fill="#111827" font-size="17" font-weight="600">${esc(title)}</text>`
  }
  if (xLabel) {
    svg += `<text x="${margin.left + plotW / 2}" y="${height - 10}" text-anchor="middle" fill="#374151" font-size="13">${esc(xLabel)}</text>`
  }
  if (yLabel) {
    svg += `<text x="16" y="${margin.top + plotH / 2}" text-anchor="middle" fill="#374151" font-size="13" transform="rotate(-90,16,${margin.top + plotH / 2})">${esc(yLabel)}</text>`
  }

  svg += '</svg>'
  return svg
}

/* ── Pie Chart ─────────────────────────────────────────────── */

const renderPieChart = (
  data: Record<string, unknown>[],
  cfg: ChartConfig,
): string => {
  const { width, height, title, colors, labelField, valueField } = cfg
  const labels = data.map((d) => String(d[labelField] ?? ''))
  const values = data.map((d) => Math.max(0, Number(d[valueField]) || 0))
  const total = values.reduce((a, b) => a + b, 0) || 1

  const legendW = 170
  const cx = (width - legendW) / 2
  const cy = height / 2 + (title ? 12 : 0)
  const radius = Math.min(width - legendW - 40, height - (title ? 100 : 60)) / 2

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui,-apple-system,sans-serif">`
  svg += `<rect width="${width}" height="${height}" fill="#fafafa" rx="4"/>`

  if (title) {
    svg += `<text x="${width / 2}" y="28" text-anchor="middle" fill="#111827" font-size="17" font-weight="600">${esc(title)}</text>`
  }

  // Slices
  let angle = -Math.PI / 2
  for (let i = 0; i < values.length; i++) {
    const sliceAngle = (values[i] / total) * 2 * Math.PI
    if (sliceAngle < 0.001) {
      angle += sliceAngle
      continue
    }

    const color = colors[i % colors.length]
    const pct = ((values[i] / total) * 100).toFixed(1)

    if (values.length === 1 || sliceAngle >= Math.PI * 2 - 0.001) {
      svg += `<circle cx="${cx}" cy="${cy}" r="${radius}" fill="${color}">`
      svg += `<title>${esc(labels[i])}: ${values[i]} (${pct}%)</title></circle>`
    } else {
      const x1 = cx + radius * Math.cos(angle)
      const y1 = cy + radius * Math.sin(angle)
      const endAngle = angle + sliceAngle
      const x2 = cx + radius * Math.cos(endAngle)
      const y2 = cy + radius * Math.sin(endAngle)
      const largeArc = sliceAngle > Math.PI ? 1 : 0

      svg += `<path d="M${cx},${cy} L${x1},${y1} A${radius},${radius} 0 ${largeArc} 1 ${x2},${y2} Z" fill="${color}" stroke="#fff" stroke-width="2">`
      svg += `<title>${esc(labels[i])}: ${values[i]} (${pct}%)</title></path>`
    }

    angle += sliceAngle
  }

  // Legend
  const legendX = width - legendW + 10
  const legendStartY = Math.max(title ? 55 : 30, cy - (values.length * 22) / 2)

  for (let i = 0; i < labels.length; i++) {
    const y = legendStartY + i * 22
    const color = colors[i % colors.length]
    const pct = ((values[i] / total) * 100).toFixed(1)

    svg += `<rect x="${legendX}" y="${y - 10}" width="12" height="12" fill="${color}" rx="2"/>`
    svg += `<text x="${legendX + 18}" y="${y + 1}" fill="#374151" font-size="11">${esc(truncate(labels[i], 12))} (${pct}%)</text>`
  }

  svg += '</svg>'
  return svg
}

/* ── Public API ─────────────────────────────────────────────── */

export const renderChart = (
  data: Record<string, unknown>[],
  config: Partial<ChartConfig> = {},
): string => {
  const cfg: ChartConfig = { ...defaults, ...config }

  if (!data.length) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${cfg.width} ${cfg.height}" width="${cfg.width}" height="${cfg.height}" font-family="system-ui,sans-serif">
      <rect width="${cfg.width}" height="${cfg.height}" fill="#fafafa" rx="4"/>
      <text x="${cfg.width / 2}" y="${cfg.height / 2}" text-anchor="middle" fill="#9ca3af" font-size="16">No data to display</text>
    </svg>`
  }

  switch (cfg.type) {
    case 'line':
      return renderLineChart(data, cfg)
    case 'pie':
      return renderPieChart(data, cfg)
    default:
      return renderBarChart(data, cfg)
  }
}

