/* ── Client-side script ────────────────────────────────────── */

const clientScript = `
(()=>{
  const editor=document.getElementById('json-editor');
  const pre=document.getElementById('editor-highlight');
  const container=document.getElementById('chart-container');
  const errEl=document.getElementById('error-msg');

  const e=s=>s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

  const tokenize=json=>{
    let r='',i=0;
    while(i<json.length){
      if(json[i]==='"'){
        let j=i+1;
        while(j<json.length){if(json[j]==='\\\\')j+=2;else if(json[j]==='"')break;else j++;}
        const s=json.slice(i,j+1);
        let k=j+1;while(k<json.length&&json[k]===' ')k++;
        r+=json[k]===':'?'<span class="tk-key">'+e(s)+'</span>':'<span class="tk-str">'+e(s)+'</span>';
        i=j+1;
      }else if(json[i]==='-'&&/\\d/.test(json[i+1]||'')||/\\d/.test(json[i])){
        let j=i;if(json[j]==='-')j++;
        while(j<json.length&&/[\\d.eE+\\-]/.test(json[j]))j++;
        r+='<span class="tk-num">'+json.slice(i,j)+'</span>';i=j;
      }else if(json.slice(i,i+4)==='true'){r+='<span class="tk-bool">true</span>';i+=4;
      }else if(json.slice(i,i+5)==='false'){r+='<span class="tk-bool">false</span>';i+=5;
      }else if(json.slice(i,i+4)==='null'){r+='<span class="tk-null">null</span>';i+=4;
      }else{r+=e(json[i]);i++;}
    }
    return r;
  };

  const updateHighlight=()=>{pre.innerHTML=tokenize(editor.value)+'\\n';};

  editor.addEventListener('input',()=>{updateHighlight();detectFields();});
  editor.addEventListener('scroll',()=>{pre.scrollTop=editor.scrollTop;pre.scrollLeft=editor.scrollLeft;});
  editor.addEventListener('keydown',ev=>{
    if(ev.key==='Tab'){
      ev.preventDefault();
      const s=editor.selectionStart,end=editor.selectionEnd;
      editor.value=editor.value.substring(0,s)+'  '+editor.value.substring(end);
      editor.selectionStart=editor.selectionEnd=s+2;
      updateHighlight();
    }
  });

  const detectFields=()=>{
    try{
      const data=JSON.parse(editor.value);
      if(!Array.isArray(data)||!data.length)return;
      const keys=Object.keys(data[0]);
      const numeric=[],categorical=[];
      keys.forEach(k=>{
        const nc=data.filter(r=>typeof r[k]==='number').length;
        (nc/data.length>0.8?numeric:categorical).push(k);
      });
      updateSelect('label-field',categorical.concat(numeric));
      updateSelect('value-field',numeric.concat(categorical));
      errEl.style.display='none';
    }catch(ex){/* not valid json yet */}
  };

  const updateSelect=(id,opts)=>{
    const sel=document.getElementById(id);
    const cur=sel.value;
    sel.innerHTML=opts.map(o=>'<option value="'+o+'"'+(o===cur?' selected':'')+'>'+o+'</option>').join('');
  };

  document.getElementById('generate-btn').addEventListener('click',async()=>{
    let data;
    try{data=JSON.parse(editor.value);}
    catch(ex){errEl.textContent='Invalid JSON: '+ex.message;errEl.style.display='block';return;}
    if(!Array.isArray(data)){errEl.textContent='Data must be a JSON array of objects';errEl.style.display='block';return;}
    errEl.style.display='none';

    const config={
      type:document.getElementById('chart-type').value,
      title:document.getElementById('chart-title').value,
      xLabel:document.getElementById('x-label').value,
      yLabel:document.getElementById('y-label').value,
      labelField:document.getElementById('label-field').value,
      valueField:document.getElementById('value-field').value,
      palette:document.getElementById('color-palette').value,
    };

    const btn=document.getElementById('generate-btn');
    btn.disabled=true;btn.textContent='Generating...';

    try{
      const res=await fetch('/generate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({data,config})});
      if(!res.ok)throw new Error(await res.text());
      container.innerHTML=await res.text();
    }catch(ex){errEl.textContent='Error: '+ex.message;errEl.style.display='block';}
    finally{btn.disabled=false;btn.textContent='Generate Chart';}
  });

  document.getElementById('download-btn').addEventListener('click',()=>{
    const svg=container.querySelector('svg');
    if(!svg){alert('No chart to download');return;}
    const data=new XMLSerializer().serializeToString(svg);
    const blob=new Blob([data],{type:'image/svg+xml'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');a.href=url;a.download='chart.svg';
    document.body.appendChild(a);a.click();document.body.removeChild(a);
    URL.revokeObjectURL(url);
  });

  document.getElementById('format-btn').addEventListener('click',()=>{
    try{
      const data=JSON.parse(editor.value);
      editor.value=JSON.stringify(data,null,2);
      updateHighlight();errEl.style.display='none';
    }catch(ex){errEl.textContent='Cannot format: '+ex.message;errEl.style.display='block';}
  });

  updateHighlight();
  detectFields();
})();
`

/* ── Form controls via plaited h() ─────────────────────────── */

const renderFormPanel = (
  config: Partial<ChartConfig>,
  numericFields: FieldInfo[],
  categoricalFields: FieldInfo[],
): string => {
  const allFields = [...categoricalFields, ...numericFields]
  const valueFields = [...numericFields, ...categoricalFields]

  const template = h(Fragment, {},
    h('div', { class: 'form-group' },
      h('label', {}, 'Chart Type'),
      h('select', { id: 'chart-type' },
        h('option', { value: 'bar', ...(config.type === 'bar' ? { selected: '' } : {}) }, 'Bar Chart'),
        h('option', { value: 'line', ...(config.type === 'line' ? { selected: '' } : {}) }, 'Line Chart'),
        h('option', { value: 'pie', ...(config.type === 'pie' ? { selected: '' } : {}) }, 'Pie Chart'),
      ),
    ),
    h('div', { class: 'field-row' },
      h('div', { class: 'form-group' },
        h('label', {}, 'Label Field'),
        h('select', { id: 'label-field' },
          ...allFields.map((f) =>
            h('option', {
              value: f.name,
              ...(f.name === config.labelField ? { selected: '' } : {}),
            }, f.name),
          ),
        ),
      ),
      h('div', { class: 'form-group' },
        h('label', {}, 'Value Field'),
        h('select', { id: 'value-field' },
          ...valueFields.map((f) =>
            h('option', {
              value: f.name,
              ...(f.name === config.valueField ? { selected: '' } : {}),
            }, f.name),
          ),
        ),
      ),
    ),
    h('div', { class: 'form-group' },
      h('label', {}, 'Chart Title'),
      h('input', { type: 'text', id: 'chart-title', placeholder: 'Optional title', value: config.title || '' }),
    ),
    h('div', { class: 'field-row' },
      h('div', { class: 'form-group' },
        h('label', {}, 'X-Axis Label'),
        h('input', { type: 'text', id: 'x-label', placeholder: 'Optional', value: config.xLabel || '' }),
      ),
      h('div', { class: 'form-group' },
        h('label', {}, 'Y-Axis Label'),
        h('input', { type: 'text', id: 'y-label', placeholder: 'Optional', value: config.yLabel || '' }),
      ),
    ),
    h('div', { class: 'form-group' },
      h('label', {}, 'Color Palette'),
      h('select', { id: 'color-palette' },
        ...paletteNames.map((name) =>
          h('option', { value: name }, name.charAt(0).toUpperCase() + name.slice(1)),
        ),
      ),
    ),
  )

  return ssr(template)
}

