  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    /* ── GET / ── render initial page with sample data ─────── */
    if (url.pathname === '/' && req.method === 'GET') {
      const sampleData = await loadSample()
      const fields = detectFields(sampleData)
      const numeric = getNumericFields(fields)
      const categorical = getCategoricalFields(fields)

      const config = {
        type: 'bar' as ChartType,
        labelField: categorical[0]?.name ?? numeric[0]?.name ?? '',
        valueField: numeric[0]?.name ?? '',
        title: '',
        xLabel: '',
        yLabel: '',
      }

      const svg = renderChart(sampleData, config)
      const jsonStr = JSON.stringify(sampleData, null, 2)
      const html = renderPage(svg, jsonStr, config, numeric, categorical)

      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    /* ── POST /generate ── return chart SVG ────────────────── */
    if (url.pathname === '/generate' && req.method === 'POST') {
      try {
        const body = (await req.json()) as GenerateBody
        const { data, config } = body

        if (!Array.isArray(data)) {
          return new Response('Data must be a JSON array', { status: 400 })
        }

        const colors = getPalette(config.palette)

        const svg = renderChart(data, {
          type: config.type,
          title: config.title,
          xLabel: config.xLabel,
          yLabel: config.yLabel,
          labelField: config.labelField,
          valueField: config.valueField,
          colors,
        })

        return new Response(svg, {
          headers: { 'Content-Type': 'image/svg+xml' },
        })
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error'
        return new Response(msg, { status: 400 })
      }
    }

    return new Response('Not Found', { status: 404 })
  },
})

