export type MarkerCategory = 'restaurant' | 'park' | 'shop' | 'office' | 'home' | 'other';

export type MapMarker = {
  id: string;
  lat: number;
  lng: number;
  title: string;
  description: string;
  category: MarkerCategory;
};

export type MapCircle = {
  id: string;
  lat: number;
  lng: number;
  radius: number;
  color: string;
  label: string;
};

export type MapData = {
  markers: MapMarker[];
  circles: MapCircle[];
};

export const CATEGORY_COLORS: Record<MarkerCategory, string> = {
  restaurant: '#e74c3c',
  park: '#27ae60',
  shop: '#3498db',
  office: '#8e44ad',
  home: '#f39c12',
  other: '#95a5a6',
};

export const CATEGORY_ICONS: Record<MarkerCategory, string> = {
  restaurant: '🍽️',
  park: '🌳',
  shop: '🛍️',
  office: '🏢',
  home: '🏠',
  other: '📍',
};

import type { MapData, MapMarker, MapCircle } from './types';

const DATA_PATH = 'data/markers.json';

const loadData = async (): Promise<MapData> => {
  try {
    return await Bun.file(DATA_PATH).json();
  } catch {
    return { markers: [], circles: [] };
  }
};

const saveData = async (data: MapData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

export const getAll = async (): Promise<MapData> => loadData();

export const addMarker = async (marker: MapMarker): Promise<MapMarker> => {
  const data = await loadData();
  data.markers.push(marker);
  await saveData(data);
  return marker;
};

export const removeMarker = async (id: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.markers.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  data.markers.splice(idx, 1);
  await saveData(data);
  return true;
};

export const addCircle = async (circle: MapCircle): Promise<MapCircle> => {
  const data = await loadData();
  data.circles.push(circle);
  await saveData(data);
  return circle;
};

export const removeCircle = async (id: string): Promise<boolean> => {
  const data = await loadData();
  const idx = data.circles.findIndex((c) => c.id === id);
  if (idx === -1) return false;
  data.circles.splice(idx, 1);
  await saveData(data);
  return true;
};

