            h('button', { id: 'circle-cancel', style: styleToStr(styles.btnCancel) }, 'Cancel'),
            h('button', { id: 'circle-save', style: styleToStr(styles.btnPrimary) }, 'Place on Map'),
          ),
        ),
      ),
      // Scripts
      h('script', { src: 'https://unpkg.com/leaflet@1/dist/leaflet.js' }),
      h('script', {},
        `(function(){
  var MARKERS = ${markerDataJson};
  var CIRCLES = ${circleDataJson};
  var COLORS = ${categoryColorsJson};
  var ICONS = ${categoryIconsJson};
  var activeCategories = new Set(${JSON.stringify(categories)});
  var leafletMarkers = {};
  var leafletCircles = {};
  var placingMarker = false;
  var placingCircle = false;
  var pendingMarker = null;
  var pendingCircle = null;

  var map = L.map('map').setView([40.7128, -74.006], 13);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19,
  }).addTo(map);

  function makeIcon(category) {
    var color = COLORS[category] || '#95a5a6';
    return L.divIcon({
      className: '',
      html: '<div style="width:28px;height:28px;border-radius:50% 50% 50% 0;background:' + color +
        ';transform:rotate(-45deg);display:flex;align-items:center;justify-content:center;border:2px solid #fff;box-shadow:0 2px 5px rgba(0,0,0,0.3)">' +
        '<span style="transform:rotate(45deg);font-size:14px">' + (ICONS[category] || '📍') + '</span></div>',
      iconSize: [28, 28],
      iconAnchor: [14, 28],
      popupAnchor: [0, -28],
    });
  }

  function popupHtml(m) {
    return '<div class="popup-category">' + (ICONS[m.category] || '') + ' ' + m.category + '</div>' +
      '<div class="popup-title">' + escapeHtml(m.title) + '</div>' +
      (m.description ? '<div class="popup-desc">' + escapeHtml(m.description) + '</div>' : '') +
      '<button class="popup-delete" onclick="window.__deleteMarker(\\''+m.id+'\\')">Remove marker</button>';
  }

  function escapeHtml(s) {
    var d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
  }

  function addMarkerToMap(m) {
    var lm = L.marker([m.lat, m.lng], { icon: makeIcon(m.category) })
      .bindPopup(popupHtml(m));
    if (activeCategories.has(m.category)) lm.addTo(map);
    leafletMarkers[m.id] = lm;
  }

  function addCircleToMap(c) {
    var lc = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    }).addTo(map);
    if (c.label) lc.bindPopup('<b>' + escapeHtml(c.label) + '</b><br>Radius: ' + c.radius + 'm' +
      '<br><button class="popup-delete" onclick="window.__deleteCircle(\\''+c.id+'\\')">Remove circle</button>');
    leafletCircles[c.id] = lc;
  }

  MARKERS.forEach(addMarkerToMap);
  CIRCLES.forEach(addCircleToMap);

  function renderSidebar() {
    var list = document.getElementById('marker-list');
    var visible = MARKERS.filter(function(m){ return activeCategories.has(m.category); });
    if (!visible.length) {
      list.innerHTML = '<div style="padding:20px;text-align:center;color:#666;font-size:13px">No markers yet. Click "+ Marker" to add one.</div>';
      return;
    }
    list.innerHTML = visible.map(function(m) {
      return '<div class="marker-item" data-id="' + m.id + '" style="padding:10px 12px;margin-bottom:4px;border-radius:6px;cursor:pointer;background:#16213e;border:1px solid transparent">' +
        '<div style="font-size:14px;font-weight:500">' + (ICONS[m.category]||'') + ' ' + escapeHtml(m.title) + '</div>' +
        (m.description ? '<div style="font-size:12px;color:#aaa;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHtml(m.description) + '</div>' : '') +
        '</div>';
    }).join('');
    list.querySelectorAll('.marker-item').forEach(function(el) {
      el.addEventListener('click', function() {
        var id = el.getAttribute('data-id');
        var lm = leafletMarkers[id];
        if (lm) { map.flyTo(lm.getLatLng(), 16); lm.openPopup(); }
      });
    });
  }
  renderSidebar();

  // Category filter buttons
  document.querySelectorAll('.category-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var cat = btn.getAttribute('data-category');
      if (activeCategories.has(cat)) {
        activeCategories.delete(cat);
        btn.classList.remove('active');
        btn.style.opacity = '0.4';
        if (leafletMarkers) Object.keys(leafletMarkers).forEach(function(id) {
          var m = MARKERS.find(function(x){return x.id===id;});
          if (m && m.category === cat) leafletMarkers[id].remove();
        });
      } else {
        activeCategories.add(cat);
        btn.classList.add('active');
        btn.style.opacity = '1';
        Object.keys(leafletMarkers).forEach(function(id) {
          var m = MARKERS.find(function(x){return x.id===id;});
          if (m && m.category === cat) leafletMarkers[id].addTo(map);
        });
      }
      renderSidebar();
    });
  });

  // Location search
  var searchInput = document.getElementById('location-search');
  var searchTimeout;
  searchInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      clearTimeout(searchTimeout);
      var q = searchInput.value.trim();
      if (!q) return;
      fetch('https://nominatim.openstreetmap.org/search?format=json&q=' + encodeURIComponent(q))
        .then(function(r){return r.json();})
        .then(function(results) {
          if (results.length) {
            var r = results[0];
            map.flyTo([parseFloat(r.lat), parseFloat(r.lon)], 15);
          } else {
            alert('Location not found');
          }
        })
        .catch(function(){alert('Search failed');});
    }
  });

  // Add marker flow
  var markerModal = document.getElementById('marker-modal');
  document.getElementById('btn-add-marker').addEventListener('click', function() {
    markerModal.style.display = 'flex';
    document.getElementById('marker-title').value = '';
    document.getElementById('marker-desc').value = '';
    document.getElementById('marker-category').value = 'other';
  });
  document.getElementById('marker-cancel').addEventListener('click', function() {
    markerModal.style.display = 'none';
    placingMarker = false;
  });
  document.getElementById('marker-save').addEventListener('click', function() {
    var title = document.getElementById('marker-title').value.trim();
    if (!title) { alert('Title is required'); return; }
    pendingMarker = {
      title: title,
      description: document.getElementById('marker-desc').value.trim(),
      category: document.getElementById('marker-category').value,
    };
    markerModal.style.display = 'none';
    placingMarker = true;
    map.getContainer().style.cursor = 'crosshair';
  });

  // Add circle flow
  var circleModal = document.getElementById('circle-modal');
  document.getElementById('btn-add-circle').addEventListener('click', function() {
    circleModal.style.display = 'flex';
    document.getElementById('circle-label').value = '';
    document.getElementById('circle-radius').value = '500';
    document.getElementById('circle-color').value = '#3498db';
  });
  document.getElementById('circle-cancel').addEventListener('click', function() {
    circleModal.style.display = 'none';
    placingCircle = false;
  });
  document.getElementById('circle-save').addEventListener('click', function() {
    pendingCircle = {
      label: document.getElementById('circle-label').value.trim(),
      radius: parseInt(document.getElementById('circle-radius').value) || 500,
      color: document.getElementById('circle-color').value,
    };
    circleModal.style.display = 'none';
    placingCircle = true;
    map.getContainer().style.cursor = 'crosshair';
  });

  // Map click handler for placing
  map.on('click', function(e) {
    if (placingMarker && pendingMarker) {
      var body = JSON.stringify({
        lat: e.latlng.lat,
        lng: e.latlng.lng,
        title: pendingMarker.title,
        description: pendingMarker.description,
        category: pendingMarker.category,
      });
      fetch('/api/markers', { method:'POST', headers:{'Content-Type':'application/json'}, body:body })
        .then(function(r){return r.json();})
        .then(function(m) {
          MARKERS.push(m);
          addMarkerToMap(m);
          renderSidebar();
        });
      placingMarker = false;
      pendingMarker = null;
      map.getContainer().style.cursor = '';
    } else if (placingCircle && pendingCircle) {
      var cbody = JSON.stringify({
        lat: e.latlng.lat,
        lng: e.latlng.lng,
        radius: pendingCircle.radius,
        color: pendingCircle.color,
        label: pendingCircle.label,
      });
      fetch('/api/circles', { method:'POST', headers:{'Content-Type':'application/json'}, body:cbody })
        .then(function(r){return r.json();})
        .then(function(c) {
          CIRCLES.push(c);
          addCircleToMap(c);
        });
      placingCircle = false;
      pendingCircle = null;
      map.getContainer().style.cursor = '';
    }
  });

  // Delete handlers
  window.__deleteMarker = function(id) {
