};

import { getAll, addMarker, removeMarker, addCircle, removeCircle } from './store';
import { renderPage } from './render';
import type { MarkerCategory } from './types';

const generateId = (): string =>
  Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // Serve the main page
    if (pathname === '/' && req.method === 'GET') {
      const data = await getAll();
      const html = renderPage(data);
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // API: Get all data
    if (pathname === '/api/data' && req.method === 'GET') {
      const data = await getAll();
      return Response.json(data);
    }

    // API: Add marker
    if (pathname === '/api/markers' && req.method === 'POST') {
      const body = await req.json() as {
        lat: number;
        lng: number;
        title: string;
        description: string;
        category: MarkerCategory;
      };
      const marker = await addMarker({
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        title: body.title,
        description: body.description || '',
        category: body.category || 'other',
      });
      return Response.json(marker);
    }

    // API: Delete marker
    const markerDeleteMatch = pathname.match(/^\/api\/markers\/(.+)$/);
    if (markerDeleteMatch && req.method === 'DELETE') {
      const ok = await removeMarker(markerDeleteMatch[1]);
      return ok
        ? Response.json({ success: true })
        : new Response('Not found', { status: 404 });
    }

    // API: Add circle
    if (pathname === '/api/circles' && req.method === 'POST') {
      const body = await req.json() as {
        lat: number;
        lng: number;
        radius: number;
        color: string;
        label: string;
      };
      const circle = await addCircle({
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        radius: body.radius || 500,
        color: body.color || '#3498db',
        label: body.label || '',
      });
      return Response.json(circle);
    }

    // API: Delete circle
    const circleDeleteMatch = pathname.match(/^\/api\/circles\/(.+)$/);
    if (circleDeleteMatch && req.method === 'DELETE') {
      const ok = await removeCircle(circleDeleteMatch[1]);
      return ok
        ? Response.json({ success: true })
        : new Response('Not found', { status: 404 });
    }

    return new Response('Not found', { status: 404 });
  },
});

