export type CategoryKey = 'length' | 'weight' | 'temperature' | 'volume' | 'time';

export type UnitEntry = {
  label: string;
  toBase?: number;
};

export type Category = {
  label: string;
  base: string;
  units: Record<string, UnitEntry>;
};

export type UnitsData = Record<CategoryKey, Category>;

export type ConversionResult = {
  value: number;
  formula: string;
  formatted: string;
};

import type { CategoryKey, UnitsData, ConversionResult } from './types';

const loadUnits = async (): Promise<UnitsData> =>
  Bun.file('data/units.json').json();

let unitsCache: UnitsData | null = null;

const getUnits = async (): Promise<UnitsData> => {
  if (!unitsCache) {
    unitsCache = await loadUnits();
  }
  return unitsCache;
};

const formatNumber = (n: number): string => {
  if (Number.isInteger(n) && Math.abs(n) < 1e15) return n.toString();
  if (Math.abs(n) < 0.0001 || Math.abs(n) > 1e10) return n.toExponential(6);
  return parseFloat(n.toPrecision(10)).toString();
};

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) {
    return { value, formula: `${from} = ${to}`, formatted: formatNumber(value) };
  }

  const formulas: Record<string, { calc: (v: number) => number; formula: string }> = {
    'C->F': { calc: (v) => v * 9 / 5 + 32, formula: '(°C × 9/5) + 32 = °F' },
    'C->K': { calc: (v) => v + 273.15, formula: '°C + 273.15 = K' },
    'F->C': { calc: (v) => (v - 32) * 5 / 9, formula: '(°F - 32) × 5/9 = °C' },
    'F->K': { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: '(°F - 32) × 5/9 + 273.15 = K' },
    'K->C': { calc: (v) => v - 273.15, formula: 'K - 273.15 = °C' },
    'K->F': { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: '(K - 273.15) × 9/5 + 32 = °F' },
  };

  const key = `${from}->${to}`;
  const entry = formulas[key]!;
  const result = entry.calc(value);
  return { value: result, formula: entry.formula, formatted: formatNumber(result) };
};

const convertStandard = (
  value: number,
  from: string,
  to: string,
  fromToBase: number,
  toToBase: number,
  fromLabel: string,
  toLabel: string,
): ConversionResult => {
  if (from === to) {
    return { value, formula: `${fromLabel} = ${toLabel}`, formatted: formatNumber(value) };
  }

  const factor = fromToBase / toToBase;
  const result = value * factor;
  const formula = `1 ${from} = ${formatNumber(factor)} ${to}`;
  return { value: result, formula, formatted: formatNumber(result) };
};

export const convert = async (
  category: CategoryKey,
  value: number,
  from: string,
  to: string,
): Promise<ConversionResult> => {
  const units = await getUnits();
  const cat = units[category];

  if (category === 'temperature') {
    return convertTemperature(value, from, to);
  }

  const fromUnit = cat.units[from]!;
  const toUnit = cat.units[to]!;

  return convertStandard(
    value,
    from,
    to,
    fromUnit.toBase!,
    toUnit.toBase!,
    fromUnit.label,
    toUnit.label,
  );
};

export const getCategories = async () => {
  const units = await getUnits();
  return Object.entries(units).map(([key, cat]) => ({
    key: key as CategoryKey,
    label: cat.label,
    units: Object.entries(cat.units).map(([unitKey, unit]) => ({
      key: unitKey,
      label: unit.label,
    })),
  }));
};

