export const render = async (params: RenderParams = {}): Promise<string> => {
  const categories = await getCategories();

  const activeCategory = params.category || 'length';
  const activeCat = categories.find((c) => c.key === activeCategory)!;
  const inputValue = params.value || '1';
  const fromUnit = params.from || activeCat.units[0].key;
  const toUnit = params.to || (activeCat.units.length > 1 ? activeCat.units[1].key : activeCat.units[0].key);

  const numValue = parseFloat(inputValue);
  const result = isNaN(numValue)
    ? null
    : await convert(activeCategory, numValue, fromUnit, toUnit);

  const fromUnitLabel = activeCat.units.find((u) => u.key === fromUnit)?.label || fromUnit;
  const toUnitLabel = activeCat.units.find((u) => u.key === toUnit)?.label || toUnit;

  const template = h('div', { style: styleStr(styles.container) },
