import { convert, getCategories } from './converter';
import { render } from './render';
import type { CategoryKey } from './types';

type RequestParams = {
  category?: CategoryKey;
  value?: string;
  from?: string;
  to?: string;
  action?: string;
};

const parseQuery = (url: URL): RequestParams => {
  const params: RequestParams = {};
  const category = url.searchParams.get('category');
  if (category) params.category = category as CategoryKey;
  const value = url.searchParams.get('value');
  if (value) params.value = value;
  const from = url.searchParams.get('from');
  if (from) params.from = from;
  const to = url.searchParams.get('to');
  if (to) params.to = to;
  const action = url.searchParams.get('action');
  if (action) params.action = action;
  return params;
};

const handleApi = async (params: RequestParams): Promise<Response> => {
  const { category = 'length', value, from, to } = params;

  if (!value || !from || !to) {
    const categories = await getCategories();
    return Response.json({ categories });
  }

  const numValue = parseFloat(value);
  if (isNaN(numValue)) {
    return Response.json({ error: 'Invalid numeric value' }, { status: 400 });
  }

  const result = await convert(category, numValue, from, to);
  return Response.json({
    input: { value: numValue, unit: from },
    output: { value: result.value, unit: to, formatted: result.formatted },
    formula: result.formula,
  });
};

const handlePage = async (params: RequestParams): Promise<Response> => {
  const html = await render(params);
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const params = parseQuery(url);

    if (url.pathname === '/api/convert') {
      return handleApi(params);
    }

    if (url.pathname === '/api/categories') {
      const categories = await getCategories();
      return Response.json({ categories });
    }

    return handlePage(params);
  },
});

