import type { CalendarEvent, EventCategory, RecurrenceType } from './types';

const DATA_PATH = 'data/events.json';

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  try {
    return await Bun.file(DATA_PATH).json();
  } catch {
    return [];
  }
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const generateId = (): string =>
  `evt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

export const createEvent = async (params: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: EventCategory;
  recurrence: RecurrenceType;
}): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const event: CalendarEvent = { id: generateId(), ...params };
  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return null;
  events[idx] = { ...events[idx], ...updates };
  await saveEvents(events);
  return events[idx];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

/** Check if a recurring event occurs on the given date */
const matchesRecurrence = (event: CalendarEvent, dateStr: string): boolean => {
  const eventDate = new Date(event.date + 'T00:00:00');
  const targetDate = new Date(dateStr + 'T00:00:00');

  if (targetDate < eventDate) return false;

  switch (event.recurrence) {
    case 'none':
      return event.date === dateStr;
    case 'daily':
      return true;
    case 'weekly': {
      return eventDate.getDay() === targetDate.getDay();
    }
    case 'monthly': {
      return eventDate.getDate() === targetDate.getDate();
    }
    default:
      return event.date === dateStr;
  }
};

/** Get all events (including recurring) for a given date */
export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return events
    .filter((e) => matchesRecurrence(e, dateStr))
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

/** Get events mapped by date for an entire month */
export const getEventsForMonth = async (
  year: number,
  month: number
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await loadEvents();
  const map = new Map<string, CalendarEvent[]>();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayEvents = events
      .filter((e) => matchesRecurrence(e, dateStr))
      .sort((a, b) => a.startTime.localeCompare(b.startTime));
    if (dayEvents.length > 0) {
      map.set(dateStr, dayEvents);
    }
  }

  return map;
};

import type { CalendarDay, CalendarEvent, MonthGrid } from './types';
import { getEventsForMonth } from './events';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const formatDate = (year: number, month: number, day: number): string =>
  `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

const getTodayStr = (): string => {
  const now = new Date();
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate());
};

export const buildMonthGrid = async (year: number, month: number): Promise<MonthGrid> => {
  const eventsMap = await getEventsForMonth(year, month);
  const today = getTodayStr();

  const firstDay = new Date(year, month, 1).getDay(); // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const prevMonthDays = new Date(year, month, 0).getDate();

  const days: CalendarDay[] = [];

  // Previous month fill
  for (let i = firstDay - 1; i >= 0; i--) {
    const day = prevMonthDays - i;
    const prevMonth = month === 0 ? 11 : month - 1;
    const prevYear = month === 0 ? year - 1 : year;
    const dateStr = formatDate(prevYear, prevMonth, day);
    days.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: false,
      isToday: dateStr === today,
      events: [],
    });
  }

  // Current month
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDate(year, month, day);
    days.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: true,
      isToday: dateStr === today,
      events: eventsMap.get(dateStr) ?? [],
    });
  }

  // Next month fill
  const remaining = 42 - days.length; // 6 rows x 7 cols
  for (let day = 1; day <= remaining; day++) {
    const nextMonth = month === 11 ? 0 : month + 1;
    const nextYear = month === 11 ? year + 1 : year;
    const dateStr = formatDate(nextYear, nextMonth, day);
    days.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: false,
      isToday: dateStr === today,
      events: [],
    });
  }

  // Chunk into weeks
  const weeks: CalendarDay[][] = [];
  for (let i = 0; i < days.length; i += 7) {
    weeks.push(days.slice(i, i + 7));
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

export const navigateMonth = (year: number, month: number, delta: number): { year: number; month: number } => {
  const d = new Date(year, month + delta, 1);
  return { year: d.getFullYear(), month: d.getMonth() };
};

