      h('span', { style: styleAttr(styles.monthLabel) }, grid.label),
      h('button', {
        style: styleAttr(styles.navBtn),
        'p-trigger': 'click:navigateNext',
      }, '\u25B6'),
      h('button', {
        style: styleAttr(styles.newEventBtn),
        'p-trigger': 'click:newEvent',
      }, '+ New Event'),
    ),
    h('div', { style: styleAttr(styles.grid) },
      ...DAY_NAMES.map((name) =>
        h('div', { style: styleAttr(styles.dayHeader) }, name)
      ),
      ...grid.weeks.flatMap((week) =>
        week.map((day) => {
          const cellStyle = {
            ...styles.dayCell,
            ...(day.isCurrentMonth ? {} : styles.dayCellOtherMonth),
            ...(day.isToday ? styles.dayCellToday : {}),
          };

          const numberEl = day.isToday
            ? h('div', { style: styleAttr(styles.dayNumberToday) }, String(day.dayOfMonth))
            : h('div', { style: styleAttr(styles.dayNumber) }, String(day.dayOfMonth));

          const eventPreviews = day.events.slice(0, 3).map((evt) =>
            h('div', {
              style: styleAttr({
                ...styles.eventPreview,
                backgroundColor: CATEGORY_COLORS[evt.category],
              }),
            }, evt.title)
          );

          const moreCount = day.events.length - 3;
          const moreEl = moreCount > 0
            ? h('div', { style: 'font-size:10px;color:#64748b;margin-top:2px' }, `+${moreCount} more`)
            : null;

          return h('div', {
            style: styleAttr(cellStyle),
            'p-trigger': `click:selectDay`,
            'data-date': day.date,
          },
            numberEl,
            ...eventPreviews,
            ...(moreEl ? [moreEl] : []),
          );
        })
