import type { CalendarEvent, EventCategory, RecurrenceType, ViewState } from './types';
import { buildMonthGrid, navigateMonth } from './calendar';
import { createEvent, updateEvent, deleteEvent, getEventsForDate, getEventById } from './events';
import { renderMonthView, renderDayView, renderEventForm } from './render';

type Action =
  | { type: 'navigatePrev' }
  | { type: 'navigateNext' }
  | { type: 'selectDay'; date: string }
  | { type: 'backToMonth' }
  | { type: 'newEvent' }
  | { type: 'newEventForDay'; date: string }
  | { type: 'editEvent'; id: string }
  | { type: 'deleteEvent'; id: string }
  | { type: 'cancelForm' }
  | { type: 'submitEvent'; data: {
      id?: string;
      title: string;
      date: string;
      startTime: string;
      endTime: string;
      description: string;
      category: EventCategory;
      recurrence: RecurrenceType;
    }};

const createInitialState = (): ViewState => {
  const now = new Date();
  return {
    mode: 'month',
    year: now.getFullYear(),
    month: now.getMonth(),
    selectedDate: null,
    editingEventId: null,
  };
};

let state: ViewState = createInitialState();

export const getState = (): ViewState => ({ ...state });

export const dispatch = async (action: Action): Promise<string> => {
  switch (action.type) {
    case 'navigatePrev': {
      const { year, month } = navigateMonth(state.year, state.month, -1);
      state = { ...state, year, month };
      return renderCurrentView();
    }

    case 'navigateNext': {
      const { year, month } = navigateMonth(state.year, state.month, 1);
      state = { ...state, year, month };
      return renderCurrentView();
    }

    case 'selectDay': {
      state = { ...state, mode: 'day', selectedDate: action.date };
      return renderCurrentView();
    }

    case 'backToMonth': {
      state = { ...state, mode: 'month', selectedDate: null, editingEventId: null };
      return renderCurrentView();
    }

    case 'newEvent': {
      state = { ...state, mode: 'event-form', editingEventId: null };
      return renderCurrentView();
    }

    case 'newEventForDay': {
      state = { ...state, mode: 'event-form', selectedDate: action.date, editingEventId: null };
      return renderCurrentView();
    }

    case 'editEvent': {
      state = { ...state, mode: 'event-form', editingEventId: action.id };
      return renderCurrentView();
    }

    case 'deleteEvent': {
      await deleteEvent(action.id);
      return renderCurrentView();
    }

    case 'cancelForm': {
      if (state.selectedDate) {
        state = { ...state, mode: 'day', editingEventId: null };
      } else {
        state = { ...state, mode: 'month', editingEventId: null };
      }
      return renderCurrentView();
    }

    case 'submitEvent': {
      const { id, ...eventData } = action.data;
      if (id) {
        await updateEvent(id, eventData);
      } else {
        await createEvent(eventData);
      }
      if (state.selectedDate) {
        state = { ...state, mode: 'day', editingEventId: null };
      } else {
        state = { ...state, mode: 'month', editingEventId: null };
      }
      return renderCurrentView();
    }

    default:
      return renderCurrentView();
  }
};

export const renderCurrentView = async (): Promise<string> => {
  switch (state.mode) {
    case 'month': {
      const grid = await buildMonthGrid(state.year, state.month);
      return renderMonthView(grid, state);
    }

    case 'day': {
      const dateStr = state.selectedDate!;
      const events = await getEventsForDate(dateStr);
      return renderDayView(dateStr, events, state);
    }

    case 'event-form': {
      if (state.editingEventId) {
        const event = await getEventById(state.editingEventId);
        return renderEventForm(event, state.selectedDate);
      }
      return renderEventForm(null, state.selectedDate);
    }

    default:
      return '';
  }
};

// HTTP server for the calendar module
const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);

    if (req.method === 'GET' && url.pathname === '/') {
      const html = await renderCurrentView();
      return new Response(wrapHtml(html), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    if (req.method === 'POST' && url.pathname === '/action') {
      const action = (await req.json()) as Action;
      const html = await dispatch(action);
      return new Response(wrapHtml(html), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // REST API endpoints
    if (req.method === 'GET' && url.pathname === '/api/state') {
      return Response.json(getState());
    }

    if (req.method === 'POST' && url.pathname === '/api/events') {
      const data = await req.json();
      const event = await createEvent(data);
      return Response.json(event);
    }

    if (req.method === 'PUT' && url.pathname.startsWith('/api/events/')) {
      const id = url.pathname.split('/').pop()!;
      const updates = await req.json();
      const event = await updateEvent(id, updates);
      if (!event) return new Response('Not found', { status: 404 });
      return Response.json(event);
    }

    if (req.method === 'DELETE' && url.pathname.startsWith('/api/events/')) {
      const id = url.pathname.split('/').pop()!;
      const deleted = await deleteEvent(id);
      if (!deleted) return new Response('Not found', { status: 404 });
      return Response.json({ ok: true });
    }

    return new Response('Not found', { status: 404 });
  },
});

const wrapHtml = (body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Calendar</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #fafafa; }
    button:hover { opacity: 0.85; }
    input:focus, select:focus, textarea:focus { border-color: #3b82f6; }
  </style>
  <script>
    document.addEventListener('click', async (e) => {
      const el = e.target.closest('[p-trigger]');
      if (!el) return;
      e.preventDefault();
      const trigger = el.getAttribute('p-trigger');
      const [, actionType] = trigger.split(':');
      let action;
      switch (actionType) {
        case 'navigatePrev': action = { type: 'navigatePrev' }; break;
        case 'navigateNext': action = { type: 'navigateNext' }; break;
        case 'selectDay': action = { type: 'selectDay', date: el.dataset.date }; break;
        case 'backToMonth': action = { type: 'backToMonth' }; break;
        case 'newEvent': action = { type: 'newEvent' }; break;
        case 'newEventForDay': action = { type: 'newEventForDay', date: el.dataset.date }; break;
        case 'editEvent': action = { type: 'editEvent', id: el.dataset.id }; break;
        case 'deleteEvent':
          if (!confirm('Delete this event?')) return;
          action = { type: 'deleteEvent', id: el.dataset.id };
          break;
        case 'cancelForm': action = { type: 'cancelForm' }; break;
        default: return;
      }
      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(action),
      });
      document.documentElement.innerHTML = await res.text();
    });
    document.addEventListener('submit', async (e) => {
      const form = e.target.closest('[p-trigger]');
      if (!form) return;
      e.preventDefault();
      const fd = new FormData(form);
      const data = Object.fromEntries(fd.entries());
      const action = { type: 'submitEvent', data };
      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(action),
      });
      document.documentElement.innerHTML = await res.text();
    });
  </script>
</head>
<body>
  ${body}
</body>
</html>`;

