export type Document = {
  id: string
  title: string
  content: string
  createdAt: string
  updatedAt: string
}

export type DocumentStore = {
  documents: Document[]
}

export type SaveRequest = {
  id?: string
  title: string
  content: string
}

import type { Document, DocumentStore, SaveRequest } from './types'

const DATA_PATH = 'data/documents.json'

const readStore = async (): Promise<DocumentStore> => {
  try {
    return await Bun.file(DATA_PATH).json()
  } catch {
    return { documents: [] }
  }
}

const writeStore = async (store: DocumentStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const getDocuments = async (): Promise<Document[]> => {
  const store = await readStore()
  return store.documents.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  )
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const store = await readStore()
  return store.documents.find((d) => d.id === id)
}

export const saveDocument = async (req: SaveRequest): Promise<Document> => {
  const store = await readStore()
  const now = new Date().toISOString()

  if (req.id) {
    const idx = store.documents.findIndex((d) => d.id === req.id)
    if (idx !== -1) {
      store.documents[idx] = {
        ...store.documents[idx],
        title: req.title,
        content: req.content,
        updatedAt: now,
      }
      await writeStore(store)
      return store.documents[idx]
    }
  }

  const doc: Document = {
    id: crypto.randomUUID(),
    title: req.title,
    content: req.content,
    createdAt: now,
    updatedAt: now,
  }
  store.documents.push(doc)
  await writeStore(store)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const idx = store.documents.findIndex((d) => d.id === id)
  if (idx === -1) return false
  store.documents.splice(idx, 1)
  await writeStore(store)
  return true
}

