const clientScript = `
const editor = document.getElementById('editor');
const preview = document.getElementById('preview');
const titleInput = document.getElementById('doc-title');
const modal = document.getElementById('load-modal');
const docList = document.getElementById('doc-list');
let currentDocId = null;

const debounce = (fn, ms) => {
  let t;
  return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); };
};

const renderPreview = debounce(async () => {
  const res = await fetch('/api/render', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content: editor.value }),
  });
  const { html } = await res.json();
  preview.innerHTML = html;
}, 150);

editor.addEventListener('input', renderPreview);

const insertAtCursor = (before, after = '') => {
  const start = editor.selectionStart;
  const end = editor.selectionEnd;
  const selected = editor.value.substring(start, end);
  const text = before + (selected || 'text') + after;
  editor.setRangeText(text, start, end, 'select');
  editor.focus();
  renderPreview();
};

const insertLine = (prefix) => {
  const start = editor.selectionStart;
  const val = editor.value;
  const lineStart = val.lastIndexOf('\\n', start - 1) + 1;
  const before = val.substring(0, lineStart);
  const after = val.substring(lineStart);
  editor.value = before + prefix + after;
  editor.selectionStart = editor.selectionEnd = start + prefix.length;
  editor.focus();
  renderPreview();
};

const insertBlock = (text) => {
  const start = editor.selectionStart;
  editor.setRangeText('\\n' + text + '\\n', start, start, 'end');
  editor.focus();
  renderPreview();
};

const toolbarActions = {
  h1: () => insertLine('# '),
  h2: () => insertLine('## '),
  h3: () => insertLine('### '),
  bold: () => insertAtCursor('**', '**'),
  italic: () => insertAtCursor('*', '*'),
  strikethrough: () => insertAtCursor('~~', '~~'),
  link: () => insertAtCursor('[', '](url)'),
  image: () => insertAtCursor('![alt](', ')'),
  code: () => insertAtCursor('\`', '\`'),
  codeblock: () => insertBlock('\`\`\`\\n\\n\`\`\`'),
  ul: () => insertLine('- '),
  ol: () => insertLine('1. '),
  quote: () => insertLine('> '),
  hr: () => insertBlock('---'),
  table: () => insertBlock('| Header | Header |\\n|--------|--------|\\n| Cell   | Cell   |'),
};

document.querySelector('.toolbar').addEventListener('click', (e) => {
  const btn = e.target.closest('[data-action]');
  if (btn) {
    const action = toolbarActions[btn.dataset.action];
    if (action) action();
  }
});

const saveDoc = async () => {
  const title = titleInput.value.trim() || 'Untitled';
  const res = await fetch('/api/documents', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ id: currentDocId, title, content: editor.value }),
  });
  const doc = await res.json();
  currentDocId = doc.id;
  titleInput.value = doc.title;
};

const newDoc = () => {
  currentDocId = null;
  titleInput.value = '';
  editor.value = '';
  preview.innerHTML = '';
};

const loadDocList = async () => {
  const res = await fetch('/api/documents');
  const docs = await res.json();
  if (docs.length === 0) {
    docList.innerHTML = '<li class="empty-state">No saved documents</li>';
  } else {
    docList.innerHTML = docs.map(d =>
      '<li class="doc-item" data-id="' + d.id + '">' +
        '<div><div class="doc-title">' + escapeHtml(d.title) + '</div>' +
        '<div class="doc-date">' + new Date(d.updatedAt).toLocaleString() + '</div></div>' +
        '<div class="doc-actions">' +
          '<button class="btn btn-danger btn-sm" data-delete="' + d.id + '" onclick="event.stopPropagation()">Del</button>' +
        '</div>' +
      '</li>'
    ).join('');
  }
  modal.classList.add('active');
};

const escapeHtml = (s) => {
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
};

docList.addEventListener('click', async (e) => {
  const delBtn = e.target.closest('[data-delete]');
  if (delBtn) {
    await fetch('/api/documents/' + delBtn.dataset.delete, { method: 'DELETE' });
    loadDocList();
    return;
  }
  const item = e.target.closest('.doc-item');
  if (item) {
    const res = await fetch('/api/documents/' + item.dataset.id);
    const doc = await res.json();
    currentDocId = doc.id;
    titleInput.value = doc.title;
    editor.value = doc.content;
    modal.classList.remove('active');
    renderPreview();
  }
});

document.getElementById('btn-save').addEventListener('click', saveDoc);
document.getElementById('btn-new').addEventListener('click', newDoc);
document.getElementById('btn-load').addEventListener('click', loadDocList);
document.querySelector('.modal-close').addEventListener('click', () => modal.classList.remove('active'));
modal.addEventListener('click', (e) => { if (e.target === modal) modal.classList.remove('active'); });

editor.addEventListener('keydown', (e) => {
  if (e.key === 'Tab') {
    e.preventDefault();
    const start = editor.selectionStart;
    editor.setRangeText('  ', start, start, 'end');
  }
  if ((e.ctrlKey || e.metaKey) && e.key === 's') {
    e.preventDefault();
    saveDoc();
  }
});

renderPreview();
`

