export type RGB = { r: number; g: number; b: number };
export type HSL = { h: number; s: number; l: number };

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '');
  const num = parseInt(cleaned, 16);
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  };
};

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) => Math.round(Math.max(0, Math.min(255, n))).toString(16).padStart(2, '0');
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`;
};

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255;
  const g = rgb.g / 255;
  const b = rgb.b / 255;
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  const l = (max + min) / 2;
  let h = 0;
  let s = 0;

  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r:
        h = ((g - b) / d + (g < b ? 6 : 0)) / 6;
        break;
      case g:
        h = ((b - r) / d + 2) / 6;
        break;
      case b:
        h = ((r - g) / d + 4) / 6;
        break;
    }
  }

  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  };
};

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360;
  const s = hsl.s / 100;
  const l = hsl.l / 100;

  if (s === 0) {
    const v = Math.round(l * 255);
    return { r: v, g: v, b: v };
  }

  const hue2rgb = (p: number, q: number, t: number): number => {
    let tt = t;
    if (tt < 0) tt += 1;
    if (tt > 1) tt -= 1;
    if (tt < 1 / 6) return p + (q - p) * 6 * tt;
    if (tt < 1 / 2) return q;
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6;
    return p;
  };

  const q = l < 0.5 ? l * (1 + s) : l + s - l * s;
  const p = 2 * l - q;

  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  };
};

export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl));

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex));

export const isValidHex = (hex: string): boolean => /^#?[0-9a-fA-F]{6}$/.test(hex);

export const normalizeHex = (hex: string): string => {
  const cleaned = hex.replace(/^#/, '');
  return `#${cleaned.toLowerCase()}`;
};

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`;

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`;

import { hexToHsl, hslToHex } from './color';

export type HarmonyMode = 'complementary' | 'analogous' | 'triadic' | 'split-complementary' | 'tetradic';

export type PaletteResult = {
  mode: HarmonyMode;
  colors: string[]; // hex values
  labels: string[];
};

const rotateHue = (h: number, degrees: number): number => ((h + degrees) % 360 + 360) % 360;

const generateFromOffsets = (
  baseHex: string,
  offsets: number[],
  labels: string[],
  mode: HarmonyMode,
): PaletteResult => {
  const hsl = hexToHsl(baseHex);
  const colors = [baseHex, ...offsets.map((deg) => hslToHex({ ...hsl, h: rotateHue(hsl.h, deg) }))];
  return { mode, colors, labels: ['Base', ...labels] };
};

export const generateComplementary = (baseHex: string): PaletteResult =>
  generateFromOffsets(baseHex, [180], ['Complement'], 'complementary');

export const generateAnalogous = (baseHex: string): PaletteResult =>
  generateFromOffsets(baseHex, [-30, 30], ['Analogous -30\u00B0', 'Analogous +30\u00B0'], 'analogous');

export const generateTriadic = (baseHex: string): PaletteResult =>
  generateFromOffsets(baseHex, [120, 240], ['Triad 120\u00B0', 'Triad 240\u00B0'], 'triadic');

export const generateSplitComplementary = (baseHex: string): PaletteResult =>
  generateFromOffsets(baseHex, [150, 210], ['Split +150\u00B0', 'Split +210\u00B0'], 'split-complementary');

export const generateTetradic = (baseHex: string): PaletteResult =>
  generateFromOffsets(baseHex, [90, 180, 270], ['Quad 90\u00B0', 'Quad 180\u00B0', 'Quad 270\u00B0'], 'tetradic');

export const generators: Record<HarmonyMode, (hex: string) => PaletteResult> = {
  complementary: generateComplementary,
  analogous: generateAnalogous,
  triadic: generateTriadic,
  'split-complementary': generateSplitComplementary,
  tetradic: generateTetradic,
};

export const generatePalette = (baseHex: string, mode: HarmonyMode): PaletteResult =>
  generators[mode](baseHex);

export const allModes: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
];

