export type ContrastResult = {
  ratio: number;
  ratioText: string;
  normalAA: boolean;
  normalAAA: boolean;
  largeAA: boolean;
  largeAAA: boolean;
};

const luminanceChannel = (c: number): number => {
  const s = c / 255;
  return s <= 0.03928 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4);
};

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * luminanceChannel(rgb.r) +
  0.7152 * luminanceChannel(rgb.g) +
  0.0722 * luminanceChannel(rgb.b);

export const contrastRatio = (hex1: string, hex2: string): number => {
  const l1 = relativeLuminance(hexToRgb(hex1));
  const l2 = relativeLuminance(hexToRgb(hex2));
  const lighter = Math.max(l1, l2);
  const darker = Math.min(l1, l2);
  return (lighter + 0.05) / (darker + 0.05);
};

export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = contrastRatio(hex1, hex2);
  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalAA: ratio >= 4.5,
    normalAAA: ratio >= 7,
    largeAA: ratio >= 3,
    largeAAA: ratio >= 4.5,
  };
};

export const wcagBadge = (pass: boolean): { label: string; color: string } =>
  pass ? { label: 'Pass', color: '#16a34a' } : { label: 'Fail', color: '#dc2626' };

