import { allModes } from './harmonies';

type AppState = {
  baseHex: string;
  mode: HarmonyMode;
  fgIndex: number;
  bgIndex: number;
};

const DEFAULT_STATE: AppState = {
  baseHex: '#3b82f6',
  mode: 'complementary',
  fgIndex: 0,
  bgIndex: 1,
};

const STATE_FILE = 'data/state.json';

const loadState = async (): Promise<AppState> => {
  try {
    const file = Bun.file(STATE_FILE);
    if (await file.exists()) {
      return { ...DEFAULT_STATE, ...(await file.json()) };
    }
  } catch {
    // fall through to default
  }
  return { ...DEFAULT_STATE };
};

const saveState = async (state: AppState): Promise<void> => {
  await Bun.write(STATE_FILE, JSON.stringify(state, null, 2));
};

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const state = await loadState();

  if (req.method === 'POST') {
    const body = await req.json() as Partial<AppState> & { action?: string; value?: string };

    if (body.action === 'setMode' && body.value && allModes.includes(body.value as HarmonyMode)) {
      state.mode = body.value as HarmonyMode;
    }

    if (body.action === 'setColor' && body.value && isValidHex(body.value)) {
      state.baseHex = normalizeHex(body.value);
    }

    if (body.action === 'setFg' && body.value !== undefined) {
      state.fgIndex = parseInt(body.value, 10) || 0;
    }

    if (body.action === 'setBg' && body.value !== undefined) {
      state.bgIndex = parseInt(body.value, 10) || 1;
    }

    await saveState(state);
    return new Response(JSON.stringify({ ok: true }), {
      headers: { 'Content-Type': 'application/json' },
    });
  }

  if (url.pathname === '/api/state') {
    return new Response(JSON.stringify(state), {
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const html = renderPalettePage(state.baseHex, state.mode, state.fgIndex, state.bgIndex);

  const page = `<!DOCTYPE html>
