      background: #1a1a2e; color: #fff; padding: 10px 24px; border-radius: 8px;
      font-size: 14px; font-weight: 600; opacity: 0; transition: opacity 0.3s;
      pointer-events: none; z-index: 1000;
    }
    .toast.show { opacity: 1; }
  </style>
</head>
<body>
  <div id="app">${html}</div>
  <div class="toast" id="toast">Copied!</div>
  <script>
    const post = async (action, value) => {
      await fetch('/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, value }),
      });
      location.reload();
    };

    const showToast = (msg) => {
      const t = document.getElementById('toast');
      t.textContent = msg;
      t.classList.add('show');
      setTimeout(() => t.classList.remove('show'), 1500);
    };

    document.addEventListener('click', (e) => {
      const trigger = e.target.closest('[p-trigger*="copy"]');
      if (trigger) {
        const val = trigger.dataset.value;
        if (val) {
          navigator.clipboard.writeText(val).then(() => showToast('Copied: ' + val));
        }
        return;
      }

      const modeBtn = e.target.closest('[p-trigger*="setMode"]');
      if (modeBtn) {
        post('setMode', modeBtn.dataset.mode);
        return;
      }
    });

    document.addEventListener('input', (e) => {
      const picker = e.target.closest('[p-trigger*="pickColor"]');
      if (picker) {
        post('setColor', picker.value);
        return;
      }

      const hexIn = e.target.closest('[p-trigger*="hexInput"]');
      if (hexIn) {
        const v = hexIn.value.startsWith('#') ? hexIn.value : '#' + hexIn.value;
        if (/^#[0-9a-fA-F]{6}$/.test(v)) {
          post('setColor', v);
        }
        return;
      }
    });

    document.addEventListener('change', (e) => {
      const fgSel = e.target.closest('[p-trigger*="selectFg"]');
      if (fgSel) {
        post('setFg', String(fgSel.selectedIndex));
        return;
      }

      const bgSel = e.target.closest('[p-trigger*="selectBg"]');
      if (bgSel) {
        post('setBg', String(bgSel.selectedIndex));
        return;
      }
    });
  </script>
</body>
</html>`;

  return new Response(page, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

