        // Lightbox script
        h('script', {}, `
          const images = ${JSON.stringify(images)};
          let currentIndex = 0;
          const lightbox = document.getElementById('lightbox');
          const lightboxImg = document.getElementById('lightbox-img');
          const lightboxCounter = document.getElementById('lightbox-counter');

          const openLightbox = (index) => {
            currentIndex = index;
            updateLightbox();
            lightbox.style.display = 'flex';
          };

          const closeLightbox = () => {
            lightbox.style.display = 'none';
          };

          const updateLightbox = () => {
            lightboxImg.src = images[currentIndex];
            lightboxImg.alt = 'Image ' + (currentIndex + 1);
            lightboxCounter.textContent = (currentIndex + 1) + ' / ' + images.length;
          };

          const nextImage = () => {
            currentIndex = (currentIndex + 1) % images.length;
            updateLightbox();
          };

          const prevImage = () => {
            currentIndex = (currentIndex - 1 + images.length) % images.length;
            updateLightbox();
          };

          lightbox.addEventListener('click', (e) => {
            if (e.target === lightbox) closeLightbox();
          });

          document.addEventListener('keydown', (e) => {
            if (lightbox.style.display !== 'flex') return;
            if (e.key === 'Escape') closeLightbox();
            if (e.key === 'ArrowRight') nextImage();
            if (e.key === 'ArrowLeft') prevImage();
          });
        `),
      ),
    ),
  )
}

import { createSSR } from '@plaited/template'
import { renderGallery, renderDetail } from './render'
import type { Project, SortOption, GalleryQuery } from './types'

const DATA_PATH = 'data/projects.json'

const loadProjects = async (): Promise<Project[]> => {
  return Bun.file(DATA_PATH).json()
}

const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

const filterProjects = (projects: Project[], query: GalleryQuery): Project[] => {
  let result = projects

  if (query.search) {
    const term = query.search.toLowerCase()
    result = result.filter(p => p.title.toLowerCase().includes(term))
  }

  if (query.tag) {
    result = result.filter(p => p.tags.includes(query.tag!))
  }

  return result
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

const parseQuery = (url: URL): GalleryQuery => ({
  search: url.searchParams.get('search') || undefined,
  tag: url.searchParams.get('tag') || undefined,
  sort: (url.searchParams.get('sort') as SortOption) || 'date-desc',
})

const buildBackQuery = (query: GalleryQuery): string => {
  const params = new URLSearchParams()
  if (query.search) params.set('search', query.search)
  if (query.tag) params.set('tag', query.tag)
  if (query.sort && query.sort !== 'date-desc') params.set('sort', query.sort)
  const qs = params.toString()
  return qs ? `?${qs}` : ''
}

