export default {
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const allProjects = await loadProjects()
    const allTags = getAllTags(allProjects)

    // Detail view: /project/:id
    const projectMatch = url.pathname.match(/^\/project\/([^/]+)$/)
    if (projectMatch) {
      const projectId = decodeURIComponent(projectMatch[1])
      const project = allProjects.find(p => p.id === projectId)

      if (!project) {
        return new Response('Project not found', { status: 404 })
      }

      const query = parseQuery(url)
      const backQuery = buildBackQuery(query)
      const template = renderDetail(project, backQuery)
      const html = render(template)

      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    // Gallery view: /
    if (url.pathname === '/' || url.pathname === '') {
      const query = parseQuery(url)
      const filtered = filterProjects(allProjects, query)
      const sorted = sortProjects(filtered, query.sort || 'date-desc')
      const template = renderGallery(sorted, allTags, query)
      const html = render(template)

      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
}

{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "A drawing canvas with freehand drawing, shapes, layers, and undo/redo",
  "main": "index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "form",
    "mechanics": ["track"],
    "boundary": "none",
    "scale": 3
  },
  "dependencies": {}
}

import type { Drawing } from './types'

const DATA_DIR = import.meta.dir + '/data'

export const saveDrawing = async (drawing: Drawing): Promise<void> => {
  drawing.updatedAt = new Date().toISOString()
  if (!drawing.createdAt) {
    drawing.createdAt = drawing.updatedAt
  }
  await Bun.write(`${DATA_DIR}/${drawing.id}.json`, JSON.stringify(drawing))
}

export const loadDrawing = async (id: string): Promise<Drawing | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.json`)
  if (await file.exists()) {
    return file.json()
  }
  return null
}

export const listDrawings = async (): Promise<string[]> => {
  const glob = new Bun.Glob('*.json')
  const files: string[] = []
  for await (const name of glob.scan(DATA_DIR)) {
    files.push(name.replace('.json', ''))
  }
  return files
}

// Client-side drawing canvas application
// Transpiled by Bun and served to the browser

type Tool = 'brush' | 'eraser' | 'rectangle' | 'circle' | 'line'

type Layer = {
  id: string
  name: string
  canvas: HTMLCanvasElement
  ctx: CanvasRenderingContext2D
  visible: boolean
}

type HistoryEntry = {
  layerId: string
  before: ImageData
  after: ImageData
}

const WIDTH = 800
const HEIGHT = 600
const MAX_HISTORY = 40

let layers: Layer[] = []
let activeLayerId = ''
let currentTool: Tool = 'brush'
let currentColor = '#000000'
let brushSize = 5
let isDrawing = false
let startX = 0
let startY = 0
let lastX = 0
let lastY = 0
let historyStack: HistoryEntry[] = []
let historyIndex = -1
let preDrawData: ImageData | null = null

let displayCanvas: HTMLCanvasElement
let displayCtx: CanvasRenderingContext2D
let tempCanvas: HTMLCanvasElement
let tempCtx: CanvasRenderingContext2D

const generateId = (): string =>
  Math.random().toString(36).slice(2, 10)

const createLayer = (name: string): Layer => {
  const canvas = document.createElement('canvas')
  canvas.width = WIDTH
  canvas.height = HEIGHT
  const ctx = canvas.getContext('2d')!
  return { id: generateId(), name, canvas, ctx, visible: true }
}

const getActiveLayer = (): Layer | undefined =>
  layers.find(l => l.id === activeLayerId)

const composite = () => {
  displayCtx.clearRect(0, 0, WIDTH, HEIGHT)
  displayCtx.fillStyle = '#ffffff'
  displayCtx.fillRect(0, 0, WIDTH, HEIGHT)
  for (const layer of layers) {
    if (layer.visible) {
      displayCtx.drawImage(layer.canvas, 0, 0)
    }
  }
}

const pushHistory = (layerId: string, before: ImageData, after: ImageData) => {
  historyStack = historyStack.slice(0, historyIndex + 1)
  historyStack.push({ layerId, before, after })
  if (historyStack.length > MAX_HISTORY) {
    historyStack.shift()
  }
  historyIndex = historyStack.length - 1
  updateUndoRedoButtons()
}

const undo = () => {
  if (historyIndex < 0) return
  const entry = historyStack[historyIndex]
  const layer = layers.find(l => l.id === entry.layerId)
  if (layer) {
    layer.ctx.putImageData(entry.before, 0, 0)
    composite()
    updateLayersPanel()
  }
  historyIndex--
  updateUndoRedoButtons()
}

const redo = () => {
  if (historyIndex >= historyStack.length - 1) return
  historyIndex++
  const entry = historyStack[historyIndex]
  const layer = layers.find(l => l.id === entry.layerId)
  if (layer) {
    layer.ctx.putImageData(entry.after, 0, 0)
    composite()
    updateLayersPanel()
  }
  updateUndoRedoButtons()
}

const getCanvasPos = (e: MouseEvent): { x: number; y: number } => {
  const rect = displayCanvas.getBoundingClientRect()
  return {
    x: e.clientX - rect.left,
    y: e.clientY - rect.top,
  }
}

const drawShape = (
  ctx: CanvasRenderingContext2D,
  shapeTool: Tool,
  x1: number,
  y1: number,
  x2: number,
  y2: number
) => {
  ctx.beginPath()
  switch (shapeTool) {
    case 'rectangle':
      ctx.strokeRect(x1, y1, x2 - x1, y2 - y1)
      break
    case 'circle': {
      const rx = Math.abs(x2 - x1) / 2
      const ry = Math.abs(y2 - y1) / 2
      const cx = (x1 + x2) / 2
      const cy = (y1 + y2) / 2
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
      break
    }
    case 'line':
      ctx.moveTo(x1, y1)
      ctx.lineTo(x2, y2)
      ctx.stroke()
      break
  }
}

const startDraw = (e: MouseEvent) => {
  const layer = getActiveLayer()
  if (!layer) return

  isDrawing = true
  const pos = getCanvasPos(e)
  startX = pos.x
  startY = pos.y
  lastX = pos.x
  lastY = pos.y

  preDrawData = layer.ctx.getImageData(0, 0, WIDTH, HEIGHT)

  if (currentTool === 'brush' || currentTool === 'eraser') {
    layer.ctx.beginPath()
    layer.ctx.moveTo(pos.x, pos.y)
    layer.ctx.globalCompositeOperation =
      currentTool === 'eraser' ? 'destination-out' : 'source-over'
    layer.ctx.strokeStyle = currentColor
    layer.ctx.lineWidth = brushSize
    layer.ctx.lineCap = 'round'
    layer.ctx.lineJoin = 'round'
    // Draw dot for single click
    layer.ctx.lineTo(pos.x + 0.1, pos.y + 0.1)
    layer.ctx.stroke()
    composite()
  }
}

const continueDraw = (e: MouseEvent) => {
  if (!isDrawing) return
  const layer = getActiveLayer()
  if (!layer) return

  const pos = getCanvasPos(e)

  if (currentTool === 'brush' || currentTool === 'eraser') {
    layer.ctx.lineTo(pos.x, pos.y)
    layer.ctx.stroke()
    composite()
  } else {
    // Shape preview on temp canvas
    tempCtx.clearRect(0, 0, WIDTH, HEIGHT)
    tempCtx.strokeStyle = currentColor
    tempCtx.lineWidth = brushSize
    tempCtx.lineCap = 'round'
    drawShape(tempCtx, currentTool, startX, startY, pos.x, pos.y)
    composite()
    displayCtx.drawImage(tempCanvas, 0, 0)
  }

  lastX = pos.x
  lastY = pos.y
}

const endDraw = (e: MouseEvent) => {
  if (!isDrawing) return
  isDrawing = false

  const layer = getActiveLayer()
  if (!layer || !preDrawData) return

  const pos = getCanvasPos(e)

  if (currentTool !== 'brush' && currentTool !== 'eraser') {
    layer.ctx.strokeStyle = currentColor
    layer.ctx.lineWidth = brushSize
    layer.ctx.lineCap = 'round'
    layer.ctx.globalCompositeOperation = 'source-over'
    drawShape(layer.ctx, currentTool, startX, startY, pos.x, pos.y)
    tempCtx.clearRect(0, 0, WIDTH, HEIGHT)
  }

  layer.ctx.globalCompositeOperation = 'source-over'

  const afterData = layer.ctx.getImageData(0, 0, WIDTH, HEIGHT)
  pushHistory(layer.id, preDrawData, afterData)
  preDrawData = null

  composite()
  updateLayersPanel()
}

const clearCanvas = () => {
  const layer = getActiveLayer()
  if (!layer) return
  const before = layer.ctx.getImageData(0, 0, WIDTH, HEIGHT)
  layer.ctx.clearRect(0, 0, WIDTH, HEIGHT)
  const after = layer.ctx.getImageData(0, 0, WIDTH, HEIGHT)
  pushHistory(layer.id, before, after)
  composite()
  updateLayersPanel()
}

const savePng = () => {
  const exportCanvas = document.createElement('canvas')
  exportCanvas.width = WIDTH
  exportCanvas.height = HEIGHT
  const exportCtx = exportCanvas.getContext('2d')!
  exportCtx.fillStyle = '#ffffff'
  exportCtx.fillRect(0, 0, WIDTH, HEIGHT)
  for (const layer of layers) {
    if (layer.visible) {
      exportCtx.drawImage(layer.canvas, 0, 0)
    }
  }
  const link = document.createElement('a')
  link.download = 'drawing.png'
  link.href = exportCanvas.toDataURL('image/png')
  link.click()
}

const loadImage = () => {
  const input = document.createElement('input')
  input.type = 'file'
  input.accept = 'image/png,image/jpeg,image/webp'
  input.onchange = () => {
    const file = input.files?.[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = () => {
      const img = new Image()
      img.onload = () => {
        const newLayer = createLayer(file.name)
        newLayer.ctx.drawImage(img, 0, 0, WIDTH, HEIGHT)
        layers.push(newLayer)
        activeLayerId = newLayer.id
        composite()
        updateLayersPanel()
        updateActiveToolButton()
      }
      img.src = reader.result as string
    }
    reader.readAsDataURL(file)
  }
  input.click()
}

const saveToServer = async () => {
  const layerData = layers.map(l => ({
    id: l.id,
    name: l.name,
    visible: l.visible,
    dataUrl: l.canvas.toDataURL('image/png'),
  }))
  await fetch('/api/save', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      id: 'current',
      name: 'Drawing',
      width: WIDTH,
      height: HEIGHT,
      layers: layerData,
    }),
  })
  const status = document.getElementById('status-msg')!
  status.textContent = 'Saved!'
  setTimeout(() => { status.textContent = '' }, 2000)
}

const loadFromServer = async () => {
  const resp = await fetch('/api/load/current')
  if (!resp.ok) {
    const status = document.getElementById('status-msg')!
    status.textContent = 'No saved drawing found'
    setTimeout(() => { status.textContent = '' }, 2000)
    return
  }
  const drawing = await resp.json()
  layers = []
  for (const ld of drawing.layers) {
    const layer = createLayer(ld.name)
    layer.id = ld.id
    layer.visible = ld.visible
    await new Promise<void>(resolve => {
      const img = new Image()
      img.onload = () => {
        layer.ctx.drawImage(img, 0, 0)
        resolve()
      }
      img.onerror = () => resolve()
      img.src = ld.dataUrl
    })
    layers.push(layer)
  }
  if (layers.length > 0) {
    activeLayerId = layers[0].id
  }
  historyStack = []
  historyIndex = -1
  composite()
  updateLayersPanel()
  updateUndoRedoButtons()
}

const updateLayersPanel = () => {
  const list = document.getElementById('layers-list')!
  list.innerHTML = ''

  for (const layer of [...layers].reverse()) {
    const item = document.createElement('div')
    item.className = 'layer-item' + (layer.id === activeLayerId ? ' active' : '')
    item.onclick = () => {
      activeLayerId = layer.id
      updateLayersPanel()
    }

    const visCheck = document.createElement('input')
    visCheck.type = 'checkbox'
    visCheck.checked = layer.visible
    visCheck.className = 'vis-check'
    visCheck.onclick = (e) => {
      e.stopPropagation()
      layer.visible = visCheck.checked
      composite()
      updateLayersPanel()
    }

    const thumb = document.createElement('canvas')
    thumb.width = 48
    thumb.height = 36
    thumb.className = 'layer-thumb'
    const thumbCtx = thumb.getContext('2d')!
    thumbCtx.fillStyle = '#e8e8e8'
    thumbCtx.fillRect(0, 0, 48, 36)
    thumbCtx.drawImage(layer.canvas, 0, 0, 48, 36)

    const nameSpan = document.createElement('span')
    nameSpan.className = 'layer-name'
    nameSpan.textContent = layer.name

    const delBtn = document.createElement('button')
    delBtn.className = 'layer-del-btn'
    delBtn.textContent = 'x'
    delBtn.title = 'Delete layer'
    delBtn.onclick = (e) => {
      e.stopPropagation()
      if (layers.length <= 1) return
      const before = layer.ctx.getImageData(0, 0, WIDTH, HEIGHT)
      layers = layers.filter(l => l.id !== layer.id)
      if (activeLayerId === layer.id) {
        activeLayerId = layers[0].id
      }
      composite()
      updateLayersPanel()
    }

    item.appendChild(visCheck)
    item.appendChild(thumb)
    item.appendChild(nameSpan)
    item.appendChild(delBtn)
    list.appendChild(item)
  }
}

const updateUndoRedoButtons = () => {
  const undoBtn = document.getElementById('undo-btn') as HTMLButtonElement | null
  const redoBtn = document.getElementById('redo-btn') as HTMLButtonElement | null
  if (undoBtn) undoBtn.disabled = historyIndex < 0
  if (redoBtn) redoBtn.disabled = historyIndex >= historyStack.length - 1
}

const updateActiveToolButton = () => {
  document.querySelectorAll('.tool-btn').forEach(btn => {
    const el = btn as HTMLElement
    el.classList.toggle('active', el.dataset.tool === currentTool)
  })
}

const init = () => {
  displayCanvas = document.getElementById('display-canvas') as HTMLCanvasElement
  displayCtx = displayCanvas.getContext('2d')!

  tempCanvas = document.createElement('canvas')
  tempCanvas.width = WIDTH
  tempCanvas.height = HEIGHT
  tempCtx = tempCanvas.getContext('2d')!

  const firstLayer = createLayer('Layer 1')
  layers.push(firstLayer)
  activeLayerId = firstLayer.id

  displayCanvas.addEventListener('mousedown', startDraw)
  displayCanvas.addEventListener('mousemove', continueDraw)
  displayCanvas.addEventListener('mouseup', endDraw)
  displayCanvas.addEventListener('mouseleave', endDraw)

  document.querySelectorAll('.tool-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      currentTool = (btn as HTMLElement).dataset.tool as Tool
      updateActiveToolButton()
    })
  })

  const colorPicker = document.getElementById('color-picker') as HTMLInputElement
  colorPicker.addEventListener('input', (e) => {
    currentColor = (e.target as HTMLInputElement).value
  })

  const sizeSlider = document.getElementById('brush-size') as HTMLInputElement
  const sizeLabel = document.getElementById('size-label')!
  sizeSlider.addEventListener('input', (e) => {
    brushSize = parseInt((e.target as HTMLInputElement).value)
    sizeLabel.textContent = brushSize + 'px'
  })

  document.getElementById('undo-btn')!.addEventListener('click', undo)
  document.getElementById('redo-btn')!.addEventListener('click', redo)
  document.getElementById('clear-btn')!.addEventListener('click', clearCanvas)
  document.getElementById('save-btn')!.addEventListener('click', savePng)
  document.getElementById('load-btn')!.addEventListener('click', loadImage)
  document.getElementById('save-server-btn')!.addEventListener('click', saveToServer)
  document.getElementById('load-server-btn')!.addEventListener('click', loadFromServer)

  document.getElementById('add-layer-btn')!.addEventListener('click', () => {
    const newLayer = createLayer('Layer ' + (layers.length + 1))
    layers.push(newLayer)
    activeLayerId = newLayer.id
    composite()
    updateLayersPanel()
  })

  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z') {
        e.preventDefault()
        if (e.shiftKey) redo()
        else undo()
      } else if (e.key === 'y') {
        e.preventDefault()
        redo()
      } else if (e.key === 's') {
        e.preventDefault()
        saveToServer()
      }
    }
  })

  composite()
  updateLayersPanel()
  updateUndoRedoButtons()
  updateActiveToolButton()
}

document.addEventListener('DOMContentLoaded', init)

