import { renderPage } from './ui'
import { saveDrawing, loadDrawing, listDrawings } from './storage'
import type { Drawing } from './types'

// Transpile client-side TypeScript at startup
const buildResult = await Bun.build({
  entrypoints: [import.meta.dir + '/canvas-app.ts'],
  target: 'browser',
  minify: true,
})

const clientJs = buildResult.success
  ? await buildResult.outputs[0].text()
  : 'console.error("Failed to build client code")'

const html = renderPage('/canvas-app.js')

const server = Bun.serve({
  port: 3000,
  routes: {
    '/': new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    }),

    '/canvas-app.js': new Response(clientJs, {
      headers: { 'Content-Type': 'application/javascript; charset=utf-8' },
    }),

    '/api/save': {
      POST: async (req) => {
        const body = await req.json() as Drawing
        await saveDrawing(body)
        return Response.json({ ok: true })
      },
    },

    '/api/load/:id': {
      GET: async (req) => {
        const id = req.params.id
        const drawing = await loadDrawing(id)
        if (!drawing) {
          return new Response('Not found', { status: 404 })
        }
        return Response.json(drawing)
      },
    },

    '/api/drawings': {
      GET: async () => {
        const ids = await listDrawings()
        return Response.json(ids)
      },
    },
  },
})

