import type { Playlist, Song, PlaybackState, RepeatMode } from './types'

const DATA_PATH = 'data/playlists.json'

const generateId = (): string => crypto.randomUUID()

// --- Persistence ---

export const loadPlaylists = async (): Promise<Playlist[]> => {
  try {
    return await Bun.file(DATA_PATH).json()
  } catch {
    return []
  }
}

export const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

// --- Playlist CRUD ---

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlists = await loadPlaylists()
  const playlist: Playlist = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    songs: [],
  }
  playlists.push(playlist)
  await savePlaylists(playlists)
  return playlist
}

export const deletePlaylist = async (playlistId: string): Promise<void> => {
  const playlists = await loadPlaylists()
  const filtered = playlists.filter((p) => p.id !== playlistId)
  await savePlaylists(filtered)
}

export const renamePlaylist = async (playlistId: string, name: string): Promise<Playlist | null> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  playlist.name = name
  await savePlaylists(playlists)
  return playlist
}

export const getPlaylist = async (playlistId: string): Promise<Playlist | null> => {
  const playlists = await loadPlaylists()
  return playlists.find((p) => p.id === playlistId) ?? null
}

// --- Song CRUD ---

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song | null> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { ...song, id: generateId() }
  playlist.songs.push(newSong)
  await savePlaylists(playlists)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  playlist.songs = playlist.songs.filter((s) => s.id !== songId)
  await savePlaylists(playlists)
}

export const reorderSongs = async (
  playlistId: string,
  songId: string,
  newIndex: number
): Promise<void> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  const oldIndex = playlist.songs.findIndex((s) => s.id === songId)
  if (oldIndex === -1) return
  const [song] = playlist.songs.splice(oldIndex, 1)
  playlist.songs.splice(newIndex, 0, song)
  await savePlaylists(playlists)
}

// --- Playback ---

export const createPlaybackState = (): PlaybackState => ({
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  shuffle: false,
  repeat: 'off',
  elapsed: 0,
  shuffleOrder: [],
})

export const generateShuffleOrder = (songCount: number, currentIndex: number): number[] => {
  const indices = Array.from({ length: songCount }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const getNextIndex = (
  state: PlaybackState,
  songCount: number
): number | null => {
  if (songCount === 0) return null

  if (state.repeat === 'one') return state.currentSongIndex

  if (state.shuffle) {
    const shufflePos = state.shuffleOrder.indexOf(state.currentSongIndex)
    const nextShufflePos = shufflePos + 1
    if (nextShufflePos < state.shuffleOrder.length) {
      return state.shuffleOrder[nextShufflePos]
    }
    if (state.repeat === 'all') return state.shuffleOrder[0]
    return null
  }

  const nextIndex = state.currentSongIndex + 1
  if (nextIndex < songCount) return nextIndex
  if (state.repeat === 'all') return 0
  return null
}

export const getPreviousIndex = (
  state: PlaybackState,
  songCount: number
): number | null => {
  if (songCount === 0) return null

  if (state.repeat === 'one') return state.currentSongIndex

  if (state.shuffle) {
    const shufflePos = state.shuffleOrder.indexOf(state.currentSongIndex)
    const prevShufflePos = shufflePos - 1
    if (prevShufflePos >= 0) return state.shuffleOrder[prevShufflePos]
    if (state.repeat === 'all') return state.shuffleOrder[state.shuffleOrder.length - 1]
    return null
  }

  const prevIndex = state.currentSongIndex - 1
  if (prevIndex >= 0) return prevIndex
  if (state.repeat === 'all') return songCount - 1
  return null
}

export const formatDuration = (seconds: number): string => {
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

