export const renderApp = (
  playlists: Playlist[],
  activePlaylistId: string | null,
  playbackState: PlaybackState,
): string => {
  const activePlaylist = playlists.find((p) => p.id === activePlaylistId) ?? null
  const currentSong =
    playbackState.currentPlaylistId !== null
      ? (() => {
          const pl = playlists.find((p) => p.id === playbackState.currentPlaylistId)
          return pl?.songs[playbackState.currentSongIndex] ?? null
        })()
      : null

  const tree = h('div', { style: styleStr(styles.root), 'p-target': 'appRoot' },
    h('div', { style: styleStr(styles.header) },
      h('h1', { style: styleStr(styles.title) }, '\u266B Playlist Manager'),
    ),
    h('div', { style: styleStr(styles.layout) },
      renderSidebar(playlists, activePlaylistId),
      activePlaylist
        ? renderPlaylistContent(activePlaylist, playbackState)
        : h('div', { style: styleStr(styles.emptyState) },
            h('p', {}, 'Select a playlist or create a new one to get started.'),
          ),
    ),
    renderNowPlayingBar(currentSong, playbackState),
    // Hidden audio element placeholder
    h('audio', { 'p-target': 'audioPlayer', preload: 'none' }),
  )

  const { render } = createSSR()
  return render(tree)
}

import type { Playlist, Song, PlaybackState, RepeatMode } from './types'
import {
  loadPlaylists,
  savePlaylists,
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  getPlaylist,
  addSong,
  removeSong,
  reorderSongs,
  createPlaybackState,
  generateShuffleOrder,
  getNextIndex,
  getPreviousIndex,
  formatDuration,
} from './store'
import { renderApp } from './render'

// --- Application State ---

type AppState = {
  playlists: Playlist[]
  activePlaylistId: string | null
  playback: PlaybackState
}

const state: AppState = {
  playlists: [],
  activePlaylistId: null,
  playback: createPlaybackState(),
}

// --- Playback timer simulation ---

let playbackInterval: ReturnType<typeof setInterval> | null = null

const startPlaybackTimer = () => {
  stopPlaybackTimer()
  playbackInterval = setInterval(() => {
    if (!state.playback.isPlaying || !state.playback.currentPlaylistId) return
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (!playlist) return
    const currentSong = playlist.songs[state.playback.currentSongIndex]
    if (!currentSong) return

    state.playback.elapsed += 1

    if (state.playback.elapsed >= currentSong.duration) {
      // Song ended — advance
      const nextIdx = getNextIndex(state.playback, playlist.songs.length)
      if (nextIdx !== null) {
        state.playback.currentSongIndex = nextIdx
        state.playback.elapsed = 0
      } else {
        state.playback.isPlaying = false
        state.playback.elapsed = 0
        stopPlaybackTimer()
      }
    }
  }, 1000)
}

const stopPlaybackTimer = () => {
  if (playbackInterval !== null) {
    clearInterval(playbackInterval)
    playbackInterval = null
  }
}

// --- API Routes ---

const parseDuration = (str: string): number => {
  const parts = str.split(':')
  if (parts.length === 2) {
    return parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10)
  }
  return parseInt(str, 10) || 0
}

