    const $$ = (sel) => document.querySelectorAll(sel);

    // Drag and drop reordering
    let dragSongId = null;
    let dragSourceIndex = null;

    document.addEventListener('dragstart', (e) => {
      const row = e.target.closest('li[draggable]');
      if (!row) return;
      dragSongId = row.dataset.songId;
      dragSourceIndex = parseInt(row.dataset.songIndex, 10);
      e.dataTransfer.effectAllowed = 'move';
      row.style.opacity = '0.5';
    });

    document.addEventListener('dragover', (e) => {
      const row = e.target.closest('li[draggable]');
      if (!row) return;
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      $$('.drag-over').forEach(el => el.classList.remove('drag-over'));
      row.classList.add('drag-over');
    });

    document.addEventListener('dragleave', (e) => {
      const row = e.target.closest('li[draggable]');
      if (row) row.classList.remove('drag-over');
    });

    document.addEventListener('drop', async (e) => {
      const row = e.target.closest('li[draggable]');
      if (!row || !dragSongId) return;
      e.preventDefault();
      $$('.drag-over').forEach(el => el.classList.remove('drag-over'));
      const playlistId = row.dataset.playlistId;
      const newIndex = parseInt(row.dataset.songIndex, 10);
      if (dragSourceIndex === newIndex) return;
      await fetch('/api/reorder', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId, songId: dragSongId, newIndex }),
      });
      location.reload();
    });

    document.addEventListener('dragend', (e) => {
      const row = e.target.closest('li[draggable]');
      if (row) row.style.opacity = '1';
      $$('.drag-over').forEach(el => el.classList.remove('drag-over'));
      dragSongId = null;
      dragSourceIndex = null;
    });

    // Event delegation for buttons
    document.addEventListener('click', async (e) => {
      const target = e.target.closest('[p-trigger]');
      if (!target) return;
      const triggers = target.getAttribute('p-trigger');

      if (triggers.includes('onCreatePlaylist')) {
        const name = prompt('Enter playlist name:');
        if (!name) return;
        await fetch('/api/playlists', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ name }),
        });
        location.reload();
      }

      if (triggers.includes('onSelectPlaylist')) {
        e.stopPropagation();
        const id = target.dataset.playlistId;
        if (!id) return;
        await fetch('/api/select-playlist', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ playlistId: id }),
        });
        location.reload();
      }

      if (triggers.includes('onDeletePlaylist')) {
        e.stopPropagation();
        const id = target.dataset.playlistId;
        if (!id || !confirm('Delete this playlist?')) return;
        await fetch('/api/playlists/' + id, { method: 'DELETE' });
        location.reload();
      }

      if (triggers.includes('onRemoveSong')) {
        e.stopPropagation();
        const songId = target.dataset.songId;
        const playlistId = target.dataset.playlistId;
        if (!songId || !playlistId) return;
        await fetch('/api/songs/' + songId, {
          method: 'DELETE',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ playlistId }),
        });
        location.reload();
      }

      if (triggers.includes('onPlayPause')) {
        await fetch('/api/playback/toggle', { method: 'POST' });
        location.reload();
      }

      if (triggers.includes('onNext')) {
        await fetch('/api/playback/next', { method: 'POST' });
        location.reload();
      }

      if (triggers.includes('onPrevious')) {
        await fetch('/api/playback/previous', { method: 'POST' });
        location.reload();
      }

      if (triggers.includes('onToggleShuffle')) {
        await fetch('/api/playback/shuffle', { method: 'POST' });
        location.reload();
      }

      if (triggers.includes('onToggleRepeat')) {
        await fetch('/api/playback/repeat', { method: 'POST' });
        location.reload();
      }

      if (triggers.includes('onSeek')) {
        const bar = target.closest('[p-target="progressBar"]') || target;
        const rect = bar.getBoundingClientRect();
        const pct = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        await fetch('/api/playback/seek', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ percent: pct }),
        });
        location.reload();
      }
    });

    // Song row click to play
    document.addEventListener('dblclick', async (e) => {
      const row = e.target.closest('li[draggable]');
      if (!row) return;
      const playlistId = row.dataset.playlistId;
      const songIndex = parseInt(row.dataset.songIndex, 10);
      await fetch('/api/playback/play', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId, songIndex }),
      });
      location.reload();
    });

    // Add song form
    document.addEventListener('submit', async (e) => {
      const form = e.target.closest('form[p-trigger]');
      if (!form) return;
      e.preventDefault();
      const fd = new FormData(form);
      const playlistId = form.dataset.playlistId;
      const durationStr = fd.get('duration') || '0:00';
      const parts = durationStr.split(':');
      const duration = parts.length === 2
        ? parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10)
        : parseInt(durationStr, 10) || 0;
      await fetch('/api/songs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          playlistId,
          title: fd.get('title'),
          artist: fd.get('artist'),
          album: fd.get('album') || '',
          duration,
          albumArtUrl: fd.get('albumArtUrl') || '',
        }),
      });
      location.reload();
    });

    // Auto-refresh for playback progress
    let refreshTimer = null;
    const startAutoRefresh = () => {
      refreshTimer = setInterval(() => {
        fetch('/api/playback/state')
          .then(r => r.json())
          .then(data => {
            if (!data.isPlaying) return;
            const fill = document.querySelector('[p-target="progressFill"]');
            const elapsed = document.querySelectorAll('[p-target="progressBar"]');
            if (fill && data.currentDuration > 0) {
              const pct = Math.min((data.elapsed / data.currentDuration) * 100, 100);
              fill.style.width = pct + '%';
            }
            // Update elapsed time display
            const timeEls = document.querySelectorAll('[style*="min-width"]');
            if (timeEls.length >= 1) {
              const mins = Math.floor(data.elapsed / 60);
              const secs = Math.floor(data.elapsed % 60);
              timeEls[0].textContent = mins + ':' + String(secs).padStart(2, '0');
            }
          })
          .catch(() => {});
      }, 1000);
    };
    startAutoRefresh();
  </script>
</body>
</html>`
}

// --- HTTP Server ---

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // --- Page ---
  if (pathname === '/' && method === 'GET') {
    await refreshState()
    return htmlResponse(getRenderedPage())
  }

  // --- Playlist API ---
  if (pathname === '/api/playlists' && method === 'GET') {
    await refreshState()
    return jsonResponse(state.playlists)
  }

  if (pathname === '/api/playlists' && method === 'POST') {
    const body = await req.json() as { name: string }
    const playlist = await createPlaylist(body.name)
    state.activePlaylistId = playlist.id
    await refreshState()
    return jsonResponse(playlist, 201)
  }

  if (pathname.startsWith('/api/playlists/') && method === 'DELETE') {
    const id = pathname.split('/').pop()!
    await deletePlaylist(id)
    if (state.activePlaylistId === id) state.activePlaylistId = null
    if (state.playback.currentPlaylistId === id) {
      state.playback = createPlaybackState()
      stopPlaybackTimer()
    }
    await refreshState()
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/select-playlist' && method === 'POST') {
    const body = await req.json() as { playlistId: string }
    state.activePlaylistId = body.playlistId
    return jsonResponse({ ok: true })
  }

  // --- Song API ---
  if (pathname === '/api/songs' && method === 'POST') {
    const body = await req.json() as {
      playlistId: string
      title: string
      artist: string
      album: string
      duration: number
      albumArtUrl: string
    }
    const song = await addSong(body.playlistId, {
      title: body.title,
      artist: body.artist,
      album: body.album,
      duration: body.duration,
      albumArtUrl: body.albumArtUrl,
    })
    await refreshState()
    return jsonResponse(song, 201)
  }

  if (pathname.startsWith('/api/songs/') && method === 'DELETE') {
    const songId = pathname.split('/').pop()!
    const body = await req.json() as { playlistId: string }
    await removeSong(body.playlistId, songId)
    await refreshState()
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/reorder' && method === 'POST') {
    const body = await req.json() as { playlistId: string; songId: string; newIndex: number }
    await reorderSongs(body.playlistId, body.songId, body.newIndex)
    await refreshState()
    return jsonResponse({ ok: true })
  }

  // --- Playback API ---
  if (pathname === '/api/playback/state' && method === 'GET') {
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    const currentSong = playlist?.songs[state.playback.currentSongIndex] ?? null
    return jsonResponse({
      ...state.playback,
      currentDuration: currentSong?.duration ?? 0,
      currentSong,
    })
  }

  if (pathname === '/api/playback/play' && method === 'POST') {
    const body = await req.json() as { playlistId: string; songIndex: number }
    state.playback.currentPlaylistId = body.playlistId
    state.playback.currentSongIndex = body.songIndex
    state.playback.isPlaying = true
    state.playback.elapsed = 0
    if (state.playback.shuffle) {
      const playlist = state.playlists.find((p) => p.id === body.playlistId)
      if (playlist) {
        state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length, body.songIndex)
      }
    }
    startPlaybackTimer()
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/toggle' && method === 'POST') {
    if (!state.playback.currentPlaylistId) {
      // Start playing first song of active playlist
      if (state.activePlaylistId) {
        const playlist = state.playlists.find((p) => p.id === state.activePlaylistId)
        if (playlist && playlist.songs.length > 0) {
          state.playback.currentPlaylistId = playlist.id
          state.playback.currentSongIndex = 0
          state.playback.isPlaying = true
          state.playback.elapsed = 0
          if (state.playback.shuffle) {
            state.playback.shuffleOrder = generateShuffleOrder(playlist.songs.length, 0)
          }
          startPlaybackTimer()
        }
      }
    } else {
      state.playback.isPlaying = !state.playback.isPlaying
      if (state.playback.isPlaying) {
        startPlaybackTimer()
      } else {
        stopPlaybackTimer()
      }
    }
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/next' && method === 'POST') {
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (playlist) {
      const nextIdx = getNextIndex(state.playback, playlist.songs.length)
      if (nextIdx !== null) {
        state.playback.currentSongIndex = nextIdx
        state.playback.elapsed = 0
      } else {
        state.playback.isPlaying = false
        stopPlaybackTimer()
      }
    }
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/previous' && method === 'POST') {
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (playlist) {
      // If more than 3 seconds in, restart current song
      if (state.playback.elapsed > 3) {
        state.playback.elapsed = 0
      } else {
        const prevIdx = getPreviousIndex(state.playback, playlist.songs.length)
        if (prevIdx !== null) {
          state.playback.currentSongIndex = prevIdx
          state.playback.elapsed = 0
        }
      }
    }
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/shuffle' && method === 'POST') {
    state.playback.shuffle = !state.playback.shuffle
    if (state.playback.shuffle && state.playback.currentPlaylistId) {
      const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
      if (playlist) {
        state.playback.shuffleOrder = generateShuffleOrder(
          playlist.songs.length,
          state.playback.currentSongIndex,
        )
      }
    }
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/repeat' && method === 'POST') {
    const modes: RepeatMode[] = ['off', 'all', 'one']
    const currentIdx = modes.indexOf(state.playback.repeat)
    state.playback.repeat = modes[(currentIdx + 1) % modes.length]
    return jsonResponse({ ok: true })
  }

  if (pathname === '/api/playback/seek' && method === 'POST') {
    const body = await req.json() as { percent: number }
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (playlist) {
      const song = playlist.songs[state.playback.currentSongIndex]
      if (song) {
        state.playback.elapsed = Math.floor(body.percent * song.duration)
      }
    }
    return jsonResponse({ ok: true })
  }

  return new Response('Not Found', { status: 404 })
}

// --- Start Server ---

const PORT = parseInt(process.env.PORT || '3000', 10)

