import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
} from './types'

const GRAVITY_DEFAULT = 9.81

export const createPendulumState = (params: PendulumParams): PendulumState => ({
  theta: Math.PI / 4,
  omega: 0,
  alpha: 0,
  initialTheta: Math.PI / 4,
})

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const alpha = -(params.gravity / params.length) * Math.sin(state.theta)
  const omega = state.omega + alpha * dt
  const theta = state.theta + omega * dt
  return { ...state, theta, omega, alpha }
}

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const rad = (params.angle * Math.PI) / 180
  return {
    x: 0,
    y: 0,
    vx: params.velocity * Math.cos(rad),
    vy: params.velocity * Math.sin(rad),
    ax: 0,
    ay: -GRAVITY_DEFAULT,
    landed: false,
    trail: [{ x: 0, y: 0 }],
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const ay = -GRAVITY_DEFAULT
  const vx = state.vx
  const vy = state.vy + ay * dt
  const x = state.x + vx * dt
  let y = state.y + vy * dt

  const landed = y <= 0 && state.y > 0 && state.trail.length > 2
  if (landed) y = 0

  const trail = [...state.trail, { x, y: Math.max(0, y) }]

  return { x, y: Math.max(0, y), vx, vy, ax: 0, ay, landed, trail }
}

export const createSpringState = (params: SpringParams): SpringState => ({
  x: 1.5,
  v: 0,
  a: 0,
  equilibriumX: 0,
  initialDisplacement: 1.5,
})

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const displacement = state.x - state.equilibriumX
  const a = -(params.k / params.mass) * displacement
  const v = state.v + a * dt
  const x = state.x + v * dt
  return { ...state, x, v, a }
}

