// ─── Reset ──────────────────────────────────────────────────────────────────

const resetSim = () => {
  running = false
  time = 0
  btnPlay.textContent = '\u25B6 Play'

  pendulum.theta = pendulum.initialTheta
  pendulum.omega = 0
  pendulum.alpha = 0

  const rad = (projectile.angle * Math.PI) / 180
  projectile.x = 0
  projectile.y = 0
  projectile.vx = projectile.velocity * Math.cos(rad)
  projectile.vy = projectile.velocity * Math.sin(rad)
  projectile.landed = false
  projectile.trail = [[0, 0]]

  spring.x = spring.initialX
  spring.v = 0
  spring.a = 0

  updateReadouts()
  draw()
}

// ─── Physics step ───────────────────────────────────────────────────────────

const DT = 1 / 120

const stepPhysics = (dt: number) => {
  time += dt

  if (activeTab === 'pendulum') {
    const alpha = -(pendulum.gravity / pendulum.length) * Math.sin(pendulum.theta)
    pendulum.omega += alpha * dt
    pendulum.theta += pendulum.omega * dt
    pendulum.alpha = alpha
  } else if (activeTab === 'projectile') {
    if (!projectile.landed) {
      const g = 9.81
      projectile.vy -= g * dt
      projectile.x += projectile.vx * dt
      projectile.y += projectile.vy * dt
      if (projectile.y <= 0 && projectile.trail.length > 2) {
        projectile.y = 0
        projectile.landed = true
      }
      projectile.trail.push([projectile.x, Math.max(0, projectile.y)])
    }
  } else if (activeTab === 'spring') {
    const displacement = spring.x
    spring.a = -(spring.k / spring.mass) * displacement
    spring.v += spring.a * dt
    spring.x += spring.v * dt
  }
}

// ─── Readouts ───────────────────────────────────────────────────────────────

const fmt = (n: number, d = 3) => n.toFixed(d)

const updateReadouts = () => {
  $val('time-display', `t = ${fmt(time)} s`)

  if (activeTab === 'pendulum') {
    $val('pend-theta', fmt(pendulum.theta))
    $val('pend-omega', fmt(pendulum.omega))
    $val('pend-alpha', fmt(pendulum.alpha))
    const lv = pendulum.length * pendulum.omega
    const la = pendulum.length * pendulum.alpha
    const lx = pendulum.length * Math.sin(pendulum.theta)
    $val('pend-x', fmt(lx))
    $val('pend-vy', fmt(lv))
    $val('pend-acc', fmt(la))
  } else if (activeTab === 'projectile') {
    $val('proj-x', fmt(projectile.x))
    $val('proj-y', fmt(projectile.y))
    $val('proj-vx', fmt(projectile.vx))
    $val('proj-vy-val', fmt(projectile.vy))
    const spd = Math.sqrt(projectile.vx ** 2 + projectile.vy ** 2)
    $val('proj-speed', fmt(spd))
    $val('proj-acc', fmt(9.81))
  } else if (activeTab === 'spring') {
    $val('spring-x', fmt(spring.x))
    $val('spring-v', fmt(spring.v))
    $val('spring-a', fmt(spring.a))
    const ke = 0.5 * spring.mass * spring.v ** 2
    const pe = 0.5 * spring.k * spring.x ** 2
    $val('spring-ke', fmt(ke))
    $val('spring-pe', fmt(pe))
    $val('spring-te', fmt(ke + pe))
  }
}

// ─── Drawing ────────────────────────────────────────────────────────────────

const W = 928
const H = 400

const drawGrid = (originX: number, originY: number) => {
  ctx.strokeStyle = '#1a2240'
  ctx.lineWidth = 1
  for (let x = 0; x < W; x += 40) {
    ctx.beginPath()
    ctx.moveTo(x, 0)
    ctx.lineTo(x, H)
    ctx.stroke()
  }
  for (let y = 0; y < H; y += 40) {
    ctx.beginPath()
    ctx.moveTo(0, y)
    ctx.lineTo(W, y)
    ctx.stroke()
  }
}

const drawPendulum = () => {
  const cx = W / 2
  const cy = 60
  const scale = 120
  const bobX = cx + pendulum.length * scale * Math.sin(pendulum.theta)
  const bobY = cy + pendulum.length * scale * Math.cos(pendulum.theta)

  ctx.clearRect(0, 0, W, H)
  ctx.fillStyle = '#0a0a1a'
  ctx.fillRect(0, 0, W, H)
  drawGrid(cx, cy)

  // Pivot
  ctx.fillStyle = '#8899aa'
  ctx.fillRect(cx - 30, cy - 4, 60, 8)

  // Rod
  ctx.strokeStyle = '#5588bb'
  ctx.lineWidth = 3
  ctx.beginPath()
  ctx.moveTo(cx, cy)
  ctx.lineTo(bobX, bobY)
  ctx.stroke()

  // Arc showing angle
  ctx.strokeStyle = 'rgba(233,69,96,0.4)'
  ctx.lineWidth = 2
  ctx.beginPath()
  const arcR = 40
  ctx.arc(cx, cy, arcR, Math.PI / 2 - pendulum.theta, Math.PI / 2, pendulum.theta > 0)
  ctx.stroke()

  // Angle label
  ctx.fillStyle = '#e94560'
  ctx.font = '13px Inter, sans-serif'
  const labelAngle = (Math.PI / 2 - pendulum.theta / 2)
  ctx.fillText(
    `\u03B8=${(pendulum.theta * 180 / Math.PI).toFixed(1)}\u00B0`,
    cx + (arcR + 10) * Math.cos(labelAngle) - 20,
    cy + (arcR + 10) * Math.sin(labelAngle),
  )

  // Bob
  const bobRadius = 18
  const gradient = ctx.createRadialGradient(bobX - 4, bobY - 4, 2, bobX, bobY, bobRadius)
  gradient.addColorStop(0, '#ff6b81')
  gradient.addColorStop(1, '#e94560')
  ctx.fillStyle = gradient
  ctx.beginPath()
  ctx.arc(bobX, bobY, bobRadius, 0, Math.PI * 2)
  ctx.fill()

  // Velocity arrow
  const velScale = 30
  const vx = pendulum.length * pendulum.omega * Math.cos(pendulum.theta)
  const vy = -pendulum.length * pendulum.omega * Math.sin(pendulum.theta)
  if (Math.abs(pendulum.omega) > 0.01) {
    ctx.strokeStyle = '#00cc88'
    ctx.lineWidth = 2
    ctx.beginPath()
    ctx.moveTo(bobX, bobY)
    ctx.lineTo(bobX + vx * velScale, bobY + vy * velScale)
    ctx.stroke()
    // Arrowhead
    const angle = Math.atan2(vy, vx)
    ctx.fillStyle = '#00cc88'
    ctx.beginPath()
    ctx.moveTo(bobX + vx * velScale, bobY + vy * velScale)
    ctx.lineTo(
      bobX + vx * velScale - 8 * Math.cos(angle - 0.4),
      bobY + vy * velScale - 8 * Math.sin(angle - 0.4),
    )
    ctx.lineTo(
      bobX + vx * velScale - 8 * Math.cos(angle + 0.4),
      bobY + vy * velScale - 8 * Math.sin(angle + 0.4),
    )
    ctx.fill()
  }

  // Labels
  ctx.fillStyle = '#5588bb'
  ctx.font = '12px JetBrains Mono, monospace'
  ctx.fillText(`L = ${pendulum.length.toFixed(1)} m`, 20, 30)
  ctx.fillText(`g = ${pendulum.gravity.toFixed(1)} m/s\u00B2`, 20, 50)
}

const drawProjectile = () => {
  ctx.clearRect(0, 0, W, H)
  ctx.fillStyle = '#0a0a1a'
  ctx.fillRect(0, 0, W, H)

  const groundY = H - 40
  const originX = 60
  const maxRange = (projectile.velocity ** 2) / 9.81
  const maxHeight = (projectile.velocity ** 2 * Math.sin((projectile.angle * Math.PI / 90)) ** 2) / (2 * 9.81)
  const scaleX = (W - 120) / Math.max(maxRange * 1.1, 1)
  const scaleY = (H - 100) / Math.max(maxHeight * 1.1, 30)
  const scale = Math.min(scaleX, scaleY)

  drawGrid(originX, groundY)

  // Ground
  ctx.strokeStyle = '#5588bb'
  ctx.lineWidth = 2
  ctx.beginPath()
  ctx.moveTo(originX, groundY)
  ctx.lineTo(W - 20, groundY)
  ctx.stroke()

  // Y-axis
  ctx.beginPath()
  ctx.moveTo(originX, groundY)
  ctx.lineTo(originX, 20)
  ctx.stroke()

  // Axis labels
  ctx.fillStyle = '#5588bb'
  ctx.font = '11px Inter, sans-serif'
  ctx.fillText('x (m)', W - 50, groundY + 25)
  ctx.fillText('y (m)', originX - 5, 15)

  // Tick marks
  const xStep = Math.pow(10, Math.floor(Math.log10(Math.max(maxRange, 1))))
  const xTickStep = xStep > 1 ? xStep / 2 : xStep
  for (let xm = xTickStep; xm * scale + originX < W - 20; xm += xTickStep) {
    const px = originX + xm * scale
    ctx.beginPath()
    ctx.moveTo(px, groundY - 4)
    ctx.lineTo(px, groundY + 4)
    ctx.stroke()
    ctx.fillText(xm.toFixed(0), px - 8, groundY + 18)
  }

  // Trail
  if (projectile.trail.length > 1) {
    ctx.strokeStyle = 'rgba(233,69,96,0.6)'
    ctx.lineWidth = 2
    ctx.beginPath()
    projectile.trail.forEach(([tx, ty], i) => {
      const px = originX + tx * scale
      const py = groundY - ty * scale
      if (i === 0) ctx.moveTo(px, py)
      else ctx.lineTo(px, py)
    })
    ctx.stroke()

    // Trail dots
    ctx.fillStyle = 'rgba(233,69,96,0.3)'
    const dotInterval = Math.max(1, Math.floor(projectile.trail.length / 30))
    projectile.trail.forEach(([tx, ty], i) => {
      if (i % dotInterval === 0) {
        ctx.beginPath()
        ctx.arc(originX + tx * scale, groundY - ty * scale, 3, 0, Math.PI * 2)
        ctx.fill()
      }
    })
  }

  // Projectile
  const px = originX + projectile.x * scale
  const py = groundY - projectile.y * scale
  const gradient = ctx.createRadialGradient(px - 2, py - 2, 1, px, py, 10)
  gradient.addColorStop(0, '#ff6b81')
  gradient.addColorStop(1, '#e94560')
  ctx.fillStyle = gradient
  ctx.beginPath()
  ctx.arc(px, py, 10, 0, Math.PI * 2)
  ctx.fill()

  // Velocity vector
  const velScale = 3
  const totalV = Math.sqrt(projectile.vx ** 2 + projectile.vy ** 2)
  if (totalV > 0.1) {
    const nvx = (projectile.vx / totalV) * Math.min(totalV * velScale, 60)
    const nvy = (-projectile.vy / totalV) * Math.min(totalV * velScale, 60)
    ctx.strokeStyle = '#00cc88'
    ctx.lineWidth = 2
    ctx.beginPath()
    ctx.moveTo(px, py)
    ctx.lineTo(px + nvx, py + nvy)
    ctx.stroke()
    const angle = Math.atan2(nvy, nvx)
    ctx.fillStyle = '#00cc88'
    ctx.beginPath()
    ctx.moveTo(px + nvx, py + nvy)
    ctx.lineTo(px + nvx - 8 * Math.cos(angle - 0.4), py + nvy - 8 * Math.sin(angle - 0.4))
    ctx.lineTo(px + nvx - 8 * Math.cos(angle + 0.4), py + nvy - 8 * Math.sin(angle + 0.4))
    ctx.fill()
  }

  // Gravity arrow
  ctx.strokeStyle = '#ffaa33'
  ctx.lineWidth = 2
  ctx.beginPath()
  ctx.moveTo(px, py)
  ctx.lineTo(px, py + 30)
  ctx.stroke()
  ctx.fillStyle = '#ffaa33'
  ctx.beginPath()
  ctx.moveTo(px, py + 30)
  ctx.lineTo(px - 5, py + 22)
  ctx.lineTo(px + 5, py + 22)
  ctx.fill()
  ctx.font = '11px Inter, sans-serif'
  ctx.fillText('g', px + 8, py + 30)

  // Info
  ctx.fillStyle = '#5588bb'
  ctx.font = '12px JetBrains Mono, monospace'
  ctx.fillText(`\u03B8 = ${projectile.angle}\u00B0  v\u2080 = ${projectile.velocity} m/s`, 20, 25)
  if (projectile.landed) {
    ctx.fillStyle = '#e94560'
    ctx.font = '14px Inter, sans-serif'
    ctx.fillText(`Range: ${projectile.x.toFixed(2)} m`, px - 40, py - 20)
  }
}

const drawSpring = () => {
  ctx.clearRect(0, 0, W, H)
  ctx.fillStyle = '#0a0a1a'
  ctx.fillRect(0, 0, W, H)
  drawGrid(W / 2, H / 2)

  const cy = H / 2
  const wallX = 80
  const eqX = W / 2
  const scale = 100
  const massX = eqX + spring.x * scale

  // Wall
  ctx.fillStyle = '#5588bb'
  ctx.fillRect(wallX - 8, cy - 60, 8, 120)
  // Hatching
  ctx.strokeStyle = '#5588bb'
  ctx.lineWidth = 1
  for (let i = -60; i < 120; i += 12) {
    ctx.beginPath()
    ctx.moveTo(wallX - 8, cy + i)
    ctx.lineTo(wallX - 20, cy + i + 12)
    ctx.stroke()
  }

  // Spring coils
  const springStart = wallX
  const springEnd = massX - 25
  const coils = 12
  const coilWidth = (springEnd - springStart) / (coils * 2)
  const coilHeight = 20

  ctx.strokeStyle = '#8899aa'
  ctx.lineWidth = 2.5
  ctx.beginPath()
  ctx.moveTo(springStart, cy)
  for (let i = 0; i < coils * 2; i++) {
    const x = springStart + coilWidth * (i + 1)
    const y = cy + (i % 2 === 0 ? -coilHeight : coilHeight)
    ctx.lineTo(x, y)
  }
  ctx.lineTo(springEnd, cy)
  ctx.stroke()

  // Equilibrium marker
  ctx.strokeStyle = 'rgba(233,69,96,0.3)'
  ctx.lineWidth = 1
  ctx.setLineDash([5, 5])
  ctx.beginPath()
  ctx.moveTo(eqX, cy - 80)
  ctx.lineTo(eqX, cy + 80)
  ctx.stroke()
  ctx.setLineDash([])
  ctx.fillStyle = 'rgba(233,69,96,0.5)'
  ctx.font = '11px Inter, sans-serif'
  ctx.fillText('x = 0', eqX - 14, cy - 85)

  // Mass block
  const blockW = 50
  const blockH = 50
  const gradient = ctx.createLinearGradient(massX - blockW / 2, cy - blockH / 2, massX + blockW / 2, cy + blockH / 2)
  gradient.addColorStop(0, '#ff6b81')
  gradient.addColorStop(1, '#e94560')
  ctx.fillStyle = gradient
  ctx.beginPath()
  ctx.roundRect(massX - blockW / 2, cy - blockH / 2, blockW, blockH, 8)
  ctx.fill()

  // Mass label
  ctx.fillStyle = '#ffffff'
  ctx.font = 'bold 14px Inter, sans-serif'
  ctx.textAlign = 'center'
  ctx.fillText(`${spring.mass.toFixed(1)}kg`, massX, cy + 5)
  ctx.textAlign = 'start'

  // Displacement arrow
  if (Math.abs(spring.x) > 0.05) {
    const arrowY = cy + 50
    ctx.strokeStyle = '#e94560'
    ctx.lineWidth = 2
    ctx.beginPath()
    ctx.moveTo(eqX, arrowY)
    ctx.lineTo(massX, arrowY)
    ctx.stroke()
    // Arrowhead
    const dir = spring.x > 0 ? 1 : -1
    ctx.fillStyle = '#e94560'
    ctx.beginPath()
    ctx.moveTo(massX, arrowY)
    ctx.lineTo(massX - dir * 8, arrowY - 5)
    ctx.lineTo(massX - dir * 8, arrowY + 5)
    ctx.fill()
    ctx.font = '12px JetBrains Mono, monospace'
    ctx.fillText(`x = ${spring.x.toFixed(2)} m`, (eqX + massX) / 2 - 30, arrowY + 20)
  }

  // Velocity arrow
  if (Math.abs(spring.v) > 0.1) {
    const velScale = 15
    const arrowY = cy - 50
    const vEnd = massX + spring.v * velScale
    ctx.strokeStyle = '#00cc88'
    ctx.lineWidth = 2
    ctx.beginPath()
    ctx.moveTo(massX, arrowY)
    ctx.lineTo(vEnd, arrowY)
    ctx.stroke()
    const dir = spring.v > 0 ? 1 : -1
    ctx.fillStyle = '#00cc88'
    ctx.beginPath()
    ctx.moveTo(vEnd, arrowY)
    ctx.lineTo(vEnd - dir * 8, arrowY - 5)
    ctx.lineTo(vEnd - dir * 8, arrowY + 5)
    ctx.fill()
    ctx.font = '11px Inter, sans-serif'
    ctx.fillText('v', vEnd + dir * 5, arrowY - 5)
  }

  // Force arrow (F = -kx)
  const force = -spring.k * spring.x
  if (Math.abs(force) > 0.5) {
    const forceScale = 1.5
    const arrowY = cy
    const fEnd = massX + force * forceScale
    ctx.strokeStyle = '#ffaa33'
    ctx.lineWidth = 2
    ctx.beginPath()
    ctx.moveTo(massX, arrowY)
    ctx.lineTo(fEnd, arrowY)
    ctx.stroke()
    const dir = force > 0 ? 1 : -1
    ctx.fillStyle = '#ffaa33'
    ctx.beginPath()
    ctx.moveTo(fEnd, arrowY)
    ctx.lineTo(fEnd - dir * 8, arrowY - 5)
    ctx.lineTo(fEnd - dir * 8, arrowY + 5)
    ctx.fill()
  }

  // Info
  ctx.fillStyle = '#5588bb'
  ctx.font = '12px JetBrains Mono, monospace'
  ctx.fillText(`k = ${spring.k.toFixed(0)} N/m   m = ${spring.mass.toFixed(1)} kg`, 20, 25)
  const omega = Math.sqrt(spring.k / spring.mass)
  ctx.fillText(`\u03C9\u2099 = ${omega.toFixed(2)} rad/s   T = ${(2 * Math.PI / omega).toFixed(2)} s`, 20, 45)

  // Legend
  ctx.fillStyle = '#00cc88'
  ctx.fillRect(W - 160, 15, 12, 12)
  ctx.fillStyle = '#8899aa'
  ctx.font = '11px Inter, sans-serif'
  ctx.fillText('Velocity', W - 142, 25)
  ctx.fillStyle = '#ffaa33'
  ctx.fillRect(W - 160, 33, 12, 12)
  ctx.fillStyle = '#8899aa'
  ctx.fillText('Force (F = -kx)', W - 142, 43)
}

// ─── Main draw dispatch ─────────────────────────────────────────────────────

const draw = () => {
  canvas.width = canvas.clientWidth
  canvas.height = canvas.clientHeight
  if (activeTab === 'pendulum') drawPendulum()
  else if (activeTab === 'projectile') drawProjectile()
  else drawSpring()
}

// ─── Animation loop ─────────────────────────────────────────────────────────

const loop = (timestamp: number) => {
  if (!running) return

  const elapsed = (timestamp - lastFrame) / 1000
  lastFrame = timestamp

  const simDt = Math.min(elapsed, 0.05) * speed
  const steps = Math.ceil(simDt / DT)
  const stepDt = simDt / steps

  for (let i = 0; i < steps; i++) {
    stepPhysics(stepDt)
  }

  updateReadouts()
  draw()
  requestAnimationFrame(loop)
}

// ─── Initial draw ───────────────────────────────────────────────────────────

const initProjectile = () => {
  const rad = (projectile.angle * Math.PI) / 180
  projectile.vx = projectile.velocity * Math.cos(rad)
  projectile.vy = projectile.velocity * Math.sin(rad)
  projectile.trail = [[0, 0]]
}

initProjectile()
resetSim()
draw()

// Handle resize
window.addEventListener('resize', () => draw())

import { renderPage } from './render'

/**
 * Main entry point for the Newton's Laws Simulator module.
 * Serves the interactive simulation page and client-side script.
 */

const buildClientScript = async (): Promise<string> => {
  const result = await Bun.build({
    entrypoints: ['./client.ts'],
    target: 'browser',
    minify: true,
  })

  if (!result.success) {
    const errors = result.logs.map((l) => l.message).join('\n')
    throw new Error(`Client build failed:\n${errors}`)
  }

  return await result.outputs[0].text()
}

let cachedClientJS: string | null = null

const getClientJS = async (): Promise<string> => {
  if (!cachedClientJS) {
    cachedClientJS = await buildClientScript()
  }
  return cachedClientJS
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/client.js') {
      const js = await getClientJS()
      return new Response(js, {
        headers: { 'Content-Type': 'application/javascript' },
      })
    }

    const html = renderPage()
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)

