<body>
<h1>Periodic Table of Elements</h1>
<div class="controls">
  <input type="text" id="search" placeholder="Search by name, symbol, or number...">
  <select id="category-filter">
    <option value="">All Categories</option>
    ${categoryOptions}
  </select>
</div>
<div class="table-wrapper">
<div class="periodic-table">
  ${elementCells}
  <div class="series-label" style="grid-row:6;grid-column:3">57-71<br>Lan</div>
  <div class="series-label" style="grid-row:7;grid-column:3">89-103<br>Act</div>
  <div class="spacer-row" style="grid-row:8"></div>
</div>
</div>
<div class="legend">
  ${legendItems}
</div>
<div id="detail-panel" class="detail-panel">
  <button id="close-detail" onclick="closeDetail()">&times;</button>
  <div id="detail-content"></div>
</div>
<div id="overlay" class="overlay" onclick="closeDetail()"></div>
<script>
const elements = ${JSON.stringify(elements)};
const categoryColors = ${JSON.stringify(categoryColors)};
const categoryLabels = ${JSON.stringify(categoryLabels)};

const formatCategory = (cat) => categoryLabels[cat] || cat;

const showDetail = (atomicNumber) => {
  const el = elements.find(e => e.atomicNumber === atomicNumber);
  if (!el) return;
  const panel = document.getElementById('detail-panel');
  const overlay = document.getElementById('overlay');
  const content = document.getElementById('detail-content');
  const bg = categoryColors[el.category] || '#555';

  content.innerHTML =
    '<div class="detail-header">' +
      '<span class="detail-symbol">' + el.symbol + '</span>' +
      '<span class="detail-name">' + el.name + '</span>' +
      '<span class="detail-number">#' + el.atomicNumber + '</span>' +
    '</div>' +
    '<div class="detail-category" style="background:' + bg + '">' + formatCategory(el.category) + '</div>' +
    '<div class="detail-grid">' +
      '<div class="detail-field"><label>Atomic Mass</label><span class="value">' + el.atomicMass + ' u</span></div>' +
      '<div class="detail-field"><label>Discovery Year</label><span class="value">' + (el.discoveryYear || 'Ancient') + '</span></div>' +
      '<div class="detail-field full"><label>Electron Configuration</label><span class="value">' + el.electronConfiguration + '</span></div>' +
      '<div class="detail-field full"><label>Oxidation States</label><span class="value">' + (el.oxidationStates.length ? el.oxidationStates.join(', ') : 'N/A') + '</span></div>' +
      '<div class="detail-field"><label>Melting Point</label><span class="value">' + (el.meltingPoint != null ? el.meltingPoint + ' \\u00B0C' : 'Unknown') + '</span></div>' +
      '<div class="detail-field"><label>Boiling Point</label><span class="value">' + (el.boilingPoint != null ? el.boilingPoint + ' \\u00B0C' : 'Unknown') + '</span></div>' +
    '</div>' +
    '<div class="detail-description">' + el.description + '</div>';

  panel.classList.add('open');
  overlay.classList.add('open');
};

const closeDetail = () => {
  document.getElementById('detail-panel').classList.remove('open');
  document.getElementById('overlay').classList.remove('open');
};

const filterElements = () => {
  const query = document.getElementById('search').value.toLowerCase();
  const cat = document.getElementById('category-filter').value;
  document.querySelectorAll('.element').forEach(cell => {
    const num = parseInt(cell.dataset.number);
    const el = elements.find(e => e.atomicNumber === num);
    if (!el) return;
    const matchSearch = !query ||
      el.name.toLowerCase().includes(query) ||
      el.symbol.toLowerCase().includes(query) ||
      String(el.atomicNumber).includes(query);
    const matchCategory = !cat || el.category === cat;
    cell.classList.toggle('hidden', !(matchSearch && matchCategory));
  });
};

document.getElementById('search').addEventListener('input', filterElements);
document.getElementById('category-filter').addEventListener('change', filterElements);

document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') closeDetail();
});
</script>
</body>
</html>`;
};

{
  "name": "@node/prompt-statistics-calculator",
  "version": "1.0.0",
  "modnet": {
    "contentType": "science",
    "structure": "form",
    "mechanics": ["chart", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {}
}

export type DatasetStats = {
  name: string
  data: number[]
  count: number
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const computeMean = (data: number[]): number =>
  data.reduce((sum, v) => sum + v, 0) / data.length

const computeMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const computeMode = (data: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of data) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return []
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const computeQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

const computeVariance = (data: number[], mean: number): number =>
  data.reduce((sum, v) => sum + (v - mean) ** 2, 0) / data.length

export const calculateStats = (name: string, data: number[]): DatasetStats => {
  const sorted = sortAsc(data)
  const mean = computeMean(data)
  const variance = computeVariance(data, mean)
  const q1 = computeQuartile(sorted, 0.25)
  const q3 = computeQuartile(sorted, 0.75)
  return {
    name,
    data: sorted,
    count: data.length,
    mean,
    median: computeMedian(sorted),
    mode: computeMode(data),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
  }
}

export const parseDataset = (input: string): number[] => {
  const trimmed = input.trim()
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }
  return trimmed
    .split(',')
    .map((s) => Number(s.trim()))
    .filter((n) => !Number.isNaN(n))
}

import { h, Fragment } from '@plaited/template'
import { createSSR } from '@plaited/template/ssr'
import type { DatasetStats } from './stats.js'

const COLORS = [
  '#4285f4', '#ea4335', '#34a853', '#fbbc05',
  '#8e24aa', '#00acc1', '#ff7043', '#7cb342',
]

const fmt = (n: number): string =>
  Number.isInteger(n) ? String(n) : n.toFixed(4)

const STAT_KEYS: { label: string; key: keyof DatasetStats }[] = [
  { label: 'Count', key: 'count' },
  { label: 'Mean', key: 'mean' },
  { label: 'Median', key: 'median' },
  { label: 'Mode', key: 'mode' },
  { label: 'Std Dev', key: 'stdDev' },
  { label: 'Variance', key: 'variance' },
  { label: 'Min', key: 'min' },
  { label: 'Max', key: 'max' },
  { label: 'Range', key: 'range' },
  { label: 'Q1', key: 'q1' },
  { label: 'Q3', key: 'q3' },
  { label: 'IQR', key: 'iqr' },
]

const formatStatValue = (val: unknown): string => {
  if (Array.isArray(val)) return val.length === 0 ? 'none' : val.map(fmt).join(', ')
  if (typeof val === 'number') return fmt(val)
  return String(val)
}

// --- Summary table ---

const renderSummaryTable = (datasets: DatasetStats[]) => {
  const headerCells = [
    h('th', { style: 'padding:6px 12px;text-align:left;border-bottom:2px solid #333;background:#f0f0f0;position:sticky;left:0;z-index:1' }, 'Statistic'),
    ...datasets.map((ds, i) =>
      h('th', { style: `padding:6px 12px;text-align:right;border-bottom:2px solid #333;color:${COLORS[i % COLORS.length]}` }, ds.name)
    ),
  ]
  const rows = STAT_KEYS.map(({ label, key }) =>
    h('tr', {},
      h('td', { style: 'padding:4px 12px;font-weight:600;border-right:1px solid #ddd;background:#fafafa;position:sticky;left:0' }, label),
      ...datasets.map((ds) =>
        h('td', { style: 'padding:4px 12px;text-align:right;font-variant-numeric:tabular-nums' }, formatStatValue(ds[key]))
      ),
    )
  )
  return h('div', { style: 'overflow-x:auto;margin:16px 0' },
    h('table', { style: 'border-collapse:collapse;width:100%;font-size:14px;font-family:system-ui,sans-serif' },
      h('thead', {}, h('tr', {}, ...headerCells)),
      h('tbody', {}, ...rows),
    )
  )
}

// --- SVG Box Plot ---

const renderBoxPlot = (datasets: DatasetStats[]) => {
  const padding = { top: 40, right: 30, bottom: 50, left: 60 }
  const plotWidth = 600
  const plotHeight = 50 * datasets.length + 60
  const svgW = plotWidth + padding.left + padding.right
  const svgH = plotHeight + padding.top + padding.bottom

  const globalMin = Math.min(...datasets.map((d) => d.min))
  const globalMax = Math.max(...datasets.map((d) => d.max))
  const dataRange = globalMax - globalMin || 1
  const xPad = dataRange * 0.05
  const xMin = globalMin - xPad
  const xMax = globalMax + xPad

  const xScale = (v: number): number =>
    padding.left + ((v - xMin) / (xMax - xMin)) * plotWidth

  const tickCount = 6
  const ticks: number[] = []
  for (let i = 0; i <= tickCount; i++) {
    ticks.push(xMin + (i / tickCount) * (xMax - xMin))
  }

  const tickElements = ticks.map((t) =>
    h('g', {},
      h('line', { x1: String(xScale(t)), y1: String(padding.top), x2: String(xScale(t)), y2: String(padding.top + plotHeight), stroke: '#e0e0e0', 'stroke-width': '1' }),
      h('text', { x: String(xScale(t)), y: String(padding.top + plotHeight + 20), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, fmt(t)),
    )
  )

  const boxHeight = 30
  const boxElements = datasets.map((ds, i) => {
    const cy = padding.top + 30 + i * 50
    const color = COLORS[i % COLORS.length]
    const whiskerLow = Math.max(ds.min, ds.q1 - 1.5 * ds.iqr)
    const whiskerHigh = Math.min(ds.max, ds.q3 + 1.5 * ds.iqr)
    const outliers = ds.data.filter((v) => v < whiskerLow || v > whiskerHigh)

    return h('g', {},
      // whisker line
      h('line', { x1: String(xScale(whiskerLow)), y1: String(cy), x2: String(xScale(whiskerHigh)), y2: String(cy), stroke: color, 'stroke-width': '2' }),
      // whisker caps
      h('line', { x1: String(xScale(whiskerLow)), y1: String(cy - boxHeight / 4), x2: String(xScale(whiskerLow)), y2: String(cy + boxHeight / 4), stroke: color, 'stroke-width': '2' }),
      h('line', { x1: String(xScale(whiskerHigh)), y1: String(cy - boxHeight / 4), x2: String(xScale(whiskerHigh)), y2: String(cy + boxHeight / 4), stroke: color, 'stroke-width': '2' }),
      // box
      h('rect', {
        x: String(xScale(ds.q1)),
        y: String(cy - boxHeight / 2),
        width: String(xScale(ds.q3) - xScale(ds.q1)),
        height: String(boxHeight),
        fill: color,
        'fill-opacity': '0.25',
        stroke: color,
        'stroke-width': '2',
        rx: '2',
      }),
      // median line
      h('line', { x1: String(xScale(ds.median)), y1: String(cy - boxHeight / 2), x2: String(xScale(ds.median)), y2: String(cy + boxHeight / 2), stroke: color, 'stroke-width': '3' }),
      // outliers
      ...outliers.map((v) =>
        h('circle', { cx: String(xScale(v)), cy: String(cy), r: '4', fill: 'none', stroke: color, 'stroke-width': '1.5' })
      ),
      // label
      h('text', { x: String(padding.left - 8), y: String(cy + 4), 'text-anchor': 'end', 'font-size': '12', fill: color, 'font-weight': '600' }, ds.name),
    )
  })

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,sans-serif;font-size:16px;margin-bottom:8px' }, 'Box Plot'),
    h('svg', { viewBox: `0 0 ${svgW} ${svgH}`, width: String(svgW), height: String(svgH), style: 'background:#fff;border:1px solid #e0e0e0;border-radius:4px' },
      ...tickElements,
      ...boxElements,
    )
  )
}

// --- SVG Histogram ---

const computeBins = (data: number[], binCount: number, min: number, max: number): number[] => {
  const bins = new Array(binCount).fill(0) as number[]
  const range = max - min || 1
  const binWidth = range / binCount
  for (const v of data) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    if (idx < 0) idx = 0
    bins[idx]++
  }
  return bins
}

const renderHistogram = (datasets: DatasetStats[]) => {
  const padding = { top: 40, right: 30, bottom: 60, left: 60 }
  const plotWidth = 600
  const plotHeight = 300
  const svgW = plotWidth + padding.left + padding.right
  const svgH = plotHeight + padding.top + padding.bottom

  const globalMin = Math.min(...datasets.map((d) => d.min))
  const globalMax = Math.max(...datasets.map((d) => d.max))

  const binCount = Math.max(5, Math.min(30, Math.ceil(Math.sqrt(datasets.reduce((m, d) => Math.max(m, d.count), 0)))))
  const allBins = datasets.map((ds) => computeBins(ds.data, binCount, globalMin, globalMax))
  const maxFreq = Math.max(...allBins.flat(), 1)

  const barGroupWidth = plotWidth / binCount
  const barWidth = (barGroupWidth * 0.8) / datasets.length
  const binWidth = (globalMax - globalMin || 1) / binCount

  const xScale = (bin: number): number => padding.left + bin * barGroupWidth
  const yScale = (freq: number): number => padding.top + plotHeight - (freq / maxFreq) * plotHeight

  // X-axis ticks (bin edges)
  const xTickCount = Math.min(binCount + 1, 10)
  const xTickStep = Math.max(1, Math.floor(binCount / (xTickCount - 1)))
  const xTicks: number[] = []
  for (let i = 0; i <= binCount; i += xTickStep) xTicks.push(i)
  if (xTicks[xTicks.length - 1] !== binCount) xTicks.push(binCount)

  const xTickEls = xTicks.map((i) => {
    const val = globalMin + i * binWidth
    const x = xScale(i)
    return h('g', {},
      h('line', { x1: String(x), y1: String(padding.top + plotHeight), x2: String(x), y2: String(padding.top + plotHeight + 6), stroke: '#666', 'stroke-width': '1' }),
      h('text', { x: String(x), y: String(padding.top + plotHeight + 20), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, fmt(val)),
    )
  })

  // Y-axis ticks
  const yTickCount = 5
  const yTicks: number[] = []
  for (let i = 0; i <= yTickCount; i++) yTicks.push(Math.round((i / yTickCount) * maxFreq))

  const yTickEls = yTicks.map((freq) =>
    h('g', {},
      h('line', { x1: String(padding.left - 6), y1: String(yScale(freq)), x2: String(padding.left), y2: String(yScale(freq)), stroke: '#666', 'stroke-width': '1' }),
      h('line', { x1: String(padding.left), y1: String(yScale(freq)), x2: String(padding.left + plotWidth), y2: String(yScale(freq)), stroke: '#f0f0f0', 'stroke-width': '1' }),
      h('text', { x: String(padding.left - 10), y: String(yScale(freq) + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#666' }, String(freq)),
    )
  )

  // Bars
  const bars = allBins.flatMap((bins, dsIdx) =>
    bins.map((freq, binIdx) => {
      if (freq === 0) return h('g', {})
      const x = xScale(binIdx) + barGroupWidth * 0.1 + dsIdx * barWidth
      const y = yScale(freq)
      const barH = padding.top + plotHeight - y
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barH),
        fill: COLORS[dsIdx % COLORS.length],
        'fill-opacity': '0.6',
        stroke: COLORS[dsIdx % COLORS.length],
        'stroke-width': '1',
        rx: '1',
      })
    })
  )

  // Legend
  const legend = datasets.length > 1
    ? datasets.map((ds, i) =>
        h('g', { transform: `translate(${padding.left + 10 + i * 120}, ${padding.top - 20})` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: COLORS[i % COLORS.length], 'fill-opacity': '0.6', rx: '2' }),
          h('text', { x: '18', y: '2', 'font-size': '12', fill: '#333' }, ds.name),
        )
      )
    : []

  // Axis labels
  const xLabel = h('text', { x: String(padding.left + plotWidth / 2), y: String(svgH - 10), 'text-anchor': 'middle', 'font-size': '13', fill: '#333' }, 'Value')
  const yLabel = h('text', { x: '15', y: String(padding.top + plotHeight / 2), 'text-anchor': 'middle', 'font-size': '13', fill: '#333', transform: `rotate(-90, 15, ${padding.top + plotHeight / 2})` }, 'Frequency')

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,sans-serif;font-size:16px;margin-bottom:8px' }, 'Histogram'),
    h('svg', { viewBox: `0 0 ${svgW} ${svgH}`, width: String(svgW), height: String(svgH), style: 'background:#fff;border:1px solid #e0e0e0;border-radius:4px' },
      // axes
      h('line', { x1: String(padding.left), y1: String(padding.top), x2: String(padding.left), y2: String(padding.top + plotHeight), stroke: '#333', 'stroke-width': '1' }),
      h('line', { x1: String(padding.left), y1: String(padding.top + plotHeight), x2: String(padding.left + plotWidth), y2: String(padding.top + plotHeight), stroke: '#333', 'stroke-width': '1' }),
      ...xTickEls,
      ...yTickEls,
      ...bars,
      ...legend,
      xLabel,
      yLabel,
    )
  )
}

// --- Main render ---

export const renderPage = (datasets: DatasetStats[]): string => {
  const tree = h('div', { style: 'max-width:720px;margin:0 auto;padding:24px;font-family:system-ui,sans-serif' },
    h('h1', { style: 'font-size:24px;margin-bottom:4px' }, 'Statistics Calculator'),
    h('p', { style: 'color:#666;margin-bottom:20px;font-size:14px' }, `${datasets.length} dataset${datasets.length > 1 ? 's' : ''} loaded`),
    renderSummaryTable(datasets),
    renderBoxPlot(datasets),
    renderHistogram(datasets),
  )
  const { render } = createSSR()
  return render(tree)
}

import { parseDataset, calculateStats } from './stats.js'
import { renderPage } from './render.js'
import type { DatasetStats } from './stats.js'

type DatasetInput = {
  name: string
  values: string
}

const STORE_PATH = 'data/datasets.json'

const loadStored = async (): Promise<DatasetInput[]> => {
  const file = Bun.file(STORE_PATH)
  if (await file.exists()) {
    return (await file.json()) as DatasetInput[]
  }
  return []
}

const saveStored = async (inputs: DatasetInput[]): Promise<void> => {
  await Bun.write(STORE_PATH, JSON.stringify(inputs, null, 2))
}

export const addDataset = async (name: string, values: string): Promise<DatasetStats[]> => {
  const inputs = await loadStored()
  const existing = inputs.findIndex((d) => d.name === name)
  if (existing >= 0) {
    inputs[existing] = { name, values }
  } else {
    inputs.push({ name, values })
  }
  await saveStored(inputs)
  return inputs.map((d) => calculateStats(d.name, parseDataset(d.values)))
}

export const removeDataset = async (name: string): Promise<DatasetStats[]> => {
  const inputs = (await loadStored()).filter((d) => d.name !== name)
  await saveStored(inputs)
  return inputs.map((d) => calculateStats(d.name, parseDataset(d.values)))
}

export const getAll = async (): Promise<DatasetStats[]> => {
  const inputs = await loadStored()
  return inputs.map((d) => calculateStats(d.name, parseDataset(d.values)))
}

export const render = async (): Promise<string> => {
  const datasets = await getAll()
  if (datasets.length === 0) return '<p>No datasets loaded. Add a dataset to get started.</p>'
  return renderPage(datasets)
}

// CLI entry: pass datasets as "name:values" arguments
// Example: bun run index.ts "Sales:10,20,30,40,50" "Revenue:[15,25,35,45,55]"
const main = async () => {
  const args = process.argv.slice(2)

  if (args.length === 0) {
    const html = await render()
    console.log(html)
    return
  }

  for (const arg of args) {
    const colonIdx = arg.indexOf(':')
    if (colonIdx === -1) {
      await addDataset('Dataset', arg)
    } else {
      const name = arg.slice(0, colonIdx).trim()
      const values = arg.slice(colonIdx + 1).trim()
      await addDataset(name, values)
    }
  }

  const html = await render()
  console.log(html)
}

