export type Ingredient = {
  amount: string;
  unit: string;
  name: string;
};

export type Recipe = {
  id: string;
  title: string;
  ingredients: Ingredient[];
  steps: string[];
  tags: string[];
  prepTime: number;
  cookTime: number;
  createdAt: string;
  updatedAt: string;
};

export type RecipeInput = Omit<Recipe, 'id' | 'createdAt' | 'updatedAt'>;

export const ALL_TAGS = [
  'vegetarian',
  'vegan',
  'gluten-free',
  'dairy-free',
  'nut-free',
  'low-carb',
  'quick',
  'breakfast',
  'lunch',
  'dinner',
  'dessert',
  'snack',
  'side-dish',
] as const;

export type Tag = (typeof ALL_TAGS)[number];

import type { Recipe, RecipeInput } from './types';

const DATA_PATH = 'data/recipes.jsonl';

const generateId = (): string => crypto.randomUUID();

const readAllRecipes = async (): Promise<Recipe[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Recipe);
};

const writeAllRecipes = async (recipes: Recipe[]): Promise<void> => {
  const content = recipes.map((r) => JSON.stringify(r)).join('\n');
  await Bun.write(DATA_PATH, content + (recipes.length ? '\n' : ''));
};

export const getAllRecipes = async (): Promise<Recipe[]> => {
  return readAllRecipes();
};

export const getRecipeById = async (id: string): Promise<Recipe | null> => {
  const recipes = await readAllRecipes();
  return recipes.find((r) => r.id === id) ?? null;
};

export const searchRecipes = async (
  query: string,
  tags: string[],
): Promise<Recipe[]> => {
  const recipes = await readAllRecipes();
  const q = query.toLowerCase().trim();

  return recipes.filter((recipe) => {
    const matchesTags =
      tags.length === 0 || tags.every((tag) => recipe.tags.includes(tag));

    if (!matchesTags) return false;
    if (!q) return true;

    const titleMatch = recipe.title.toLowerCase().includes(q);
    const ingredientMatch = recipe.ingredients.some((ing) =>
      ing.name.toLowerCase().includes(q),
    );
    return titleMatch || ingredientMatch;
  });
};

export const createRecipe = async (input: RecipeInput): Promise<Recipe> => {
  const now = new Date().toISOString();
  const recipe: Recipe = {
    ...input,
    id: generateId(),
    createdAt: now,
    updatedAt: now,
  };
  const recipes = await readAllRecipes();
  recipes.push(recipe);
  await writeAllRecipes(recipes);
  return recipe;
};

export const updateRecipe = async (
  id: string,
  input: RecipeInput,
): Promise<Recipe | null> => {
  const recipes = await readAllRecipes();
  const index = recipes.findIndex((r) => r.id === id);
  if (index === -1) return null;
  const updated: Recipe = {
    ...input,
    id,
    createdAt: recipes[index].createdAt,
    updatedAt: new Date().toISOString(),
  };
  recipes[index] = updated;
  await writeAllRecipes(recipes);
  return updated;
};

export const deleteRecipe = async (id: string): Promise<boolean> => {
  const recipes = await readAllRecipes();
  const filtered = recipes.filter((r) => r.id !== id);
  if (filtered.length === recipes.length) return false;
  await writeAllRecipes(filtered);
  return true;
};

