export const renderRecipeList = (
  recipes: Recipe[],
  query: string,
  activeTags: string[],
): string => {
  const buildFilterUrl = (tag: string): string => {
    const newTags = activeTags.includes(tag)
      ? activeTags.filter((t) => t !== tag)
      : [...activeTags, tag];
    const params = new URLSearchParams();
    if (query) params.set('q', query);
    newTags.forEach((t) => params.append('tag', t));
    const qs = params.toString();
    return qs ? `/?${qs}` : '/';
  };

  const tagFilters = ALL_TAGS.map((tag) =>
    h(
      'a',
      {
        href: buildFilterUrl(tag),
        style: activeTags.includes(tag) ? styles.tagActive : styles.tag,
      },
      tag,
    ),
  );

  const recipeCards =
    recipes.length > 0
      ? recipes.map((recipe) =>
          h(
            'a',
            {
              href: `/recipe/${recipe.id}`,
              style: styles.recipeCard,
              class: 'recipe-card',
            },
            h('div', { style: styles.cardTitle }, recipe.title),
            h(
              'div',
              { style: styles.cardMeta },
              `Prep: ${formatTime(recipe.prepTime)} · Cook: ${formatTime(recipe.cookTime)} · ${recipe.ingredients.length} ingredients`,
            ),
            recipe.tags.length > 0
              ? h(
                  'div',
                  { style: styles.cardTags },
                  ...recipe.tags.map((tag) =>
                    h('span', { style: styles.cardTag }, tag),
                  ),
                )
              : null,
          ),
        )
      : [
          h(
            'div',
            { style: styles.empty },
            query || activeTags.length > 0
              ? 'No recipes match your search.'
              : 'No recipes yet. Add your first recipe!',
          ),
        ];

  const searchParams = new URLSearchParams();
  if (query) searchParams.set('q', query);
  activeTags.forEach((t) => searchParams.append('tag', t));

  const page = layout(
    'Recipe Manager',
    h(
      'div',
      { style: styles.header },
      h('h1', { style: styles.h1 }, 'Recipe Manager'),
      h('a', { href: '/new', style: styles.addBtn }, '+ New Recipe'),
    ),
    h(
      'form',
      { method: 'GET', action: '/', style: styles.searchBar },
      ...activeTags.map((t) => h('input', { type: 'hidden', name: 'tag', value: t })),
      h('input', {
        type: 'text',
        name: 'q',
        placeholder: 'Search by title or ingredient...',
        value: query,
        style: styles.searchInput,
      }),
      h('button', { type: 'submit', style: styles.searchBtn }, 'Search'),
    ),
    h('div', { style: styles.tagFilters }, ...tagFilters),
    ...recipeCards,
  );

  return createSSR(page);
};

