        stepCount++;
      }
      `,
    ),
  );

  return createSSR(page);
};

import type { RecipeInput, Ingredient } from './types';
import {
  getAllRecipes,
  getRecipeById,
  searchRecipes,
  createRecipe,
  updateRecipe,
  deleteRecipe,
} from './store';
import { renderRecipeList, renderRecipeDetail, renderRecipeForm } from './views';

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const redirect = (url: string) =>
  new Response(null, { status: 303, headers: { Location: url } });

const parseFormIngredients = (form: FormData): Ingredient[] => {
  const ingredients: Ingredient[] = [];
  let i = 0;
  while (form.has(`ing_name_${i}`)) {
    const name = (form.get(`ing_name_${i}`) as string).trim();
    if (name) {
      ingredients.push({
        amount: (form.get(`ing_amount_${i}`) as string).trim(),
        unit: (form.get(`ing_unit_${i}`) as string).trim(),
        name,
      });
    }
    i++;
  }
  return ingredients;
};

const parseFormSteps = (form: FormData): string[] => {
  const steps: string[] = [];
  let i = 0;
  while (form.has(`step_${i}`)) {
    const step = (form.get(`step_${i}`) as string).trim();
    if (step) steps.push(step);
    i++;
  }
  return steps;
};

const parseRecipeInput = (form: FormData): RecipeInput => {
  const tags = form.getAll('tags').map((t) => String(t));
  return {
    title: (form.get('title') as string).trim(),
    ingredients: parseFormIngredients(form),
    steps: parseFormSteps(form),
    tags,
    prepTime: parseInt(form.get('prepTime') as string, 10) || 0,
    cookTime: parseInt(form.get('cookTime') as string, 10) || 0,
  };
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;
  const method = req.method;

  // GET / — recipe list with search & filter
  if (path === '/' && method === 'GET') {
    const query = url.searchParams.get('q') ?? '';
    const tags = url.searchParams.getAll('tag');
    const recipes = await searchRecipes(query, tags);
    return html(renderRecipeList(recipes, query, tags));
  }

  // GET /new — new recipe form
  if (path === '/new' && method === 'GET') {
    return html(renderRecipeForm());
  }

  // GET /recipe/:id — recipe detail
  const detailMatch = path.match(/^\/recipe\/([^/]+)$/);
  if (detailMatch && method === 'GET') {
    const recipe = await getRecipeById(detailMatch[1]);
    if (!recipe) return html('<h1>Recipe not found</h1>', 404);
    return html(renderRecipeDetail(recipe));
  }

  // GET /edit/:id — edit recipe form
  const editMatch = path.match(/^\/edit\/([^/]+)$/);
  if (editMatch && method === 'GET') {
    const recipe = await getRecipeById(editMatch[1]);
    if (!recipe) return html('<h1>Recipe not found</h1>', 404);
    return html(renderRecipeForm(recipe));
  }

  // POST /recipes — create recipe
  if (path === '/recipes' && method === 'POST') {
    const form = await req.formData();
    const methodOverride = form.get('_method');

    if (methodOverride === 'PUT') {
      // This shouldn't happen on /recipes, but handle gracefully
      return redirect('/');
    }

    const input = parseRecipeInput(form);
    if (!input.title) return redirect('/new');
    await createRecipe(input);
    return redirect('/');
  }

  // POST /recipes/:id — update recipe (with _method=PUT)
  const updateMatch = path.match(/^\/recipes\/([^/]+)$/);
  if (updateMatch && method === 'POST') {
    const form = await req.formData();
    const input = parseRecipeInput(form);
    if (!input.title) return redirect(`/edit/${updateMatch[1]}`);
    await updateRecipe(updateMatch[1], input);
    return redirect(`/recipe/${updateMatch[1]}`);
  }

  // POST /recipes/:id/delete — delete recipe
  const deleteMatch = path.match(/^\/recipes\/([^/]+)\/delete$/);
  if (deleteMatch && method === 'POST') {
    await deleteRecipe(deleteMatch[1]);
    return redirect('/');
  }

  return html('<h1>Not Found</h1>', 404);
};

