import type { Habit, Completion, HabitStore, CompletionStore } from './types'

const HABITS_PATH = 'data/habits.json'
const COMPLETIONS_PATH = 'data/completions.json'

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  try {
    const file = Bun.file(path)
    if (await file.exists()) {
      return await file.json() as T
    }
  } catch {
    // file missing or malformed — use fallback
  }
  return fallback
}

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const getHabits = async (): Promise<Habit[]> => {
  const store = await readJson<HabitStore>(HABITS_PATH, { habits: [] })
  return store.habits
}

export const saveHabits = async (habits: Habit[]): Promise<void> => {
  await writeJson<HabitStore>(HABITS_PATH, { habits })
}

export const addHabit = async (name: string, frequency: Habit['frequency']): Promise<Habit> => {
  const habits = await getHabits()
  const habit: Habit = {
    id: crypto.randomUUID(),
    name,
    frequency,
    createdAt: new Date().toISOString(),
  }
  habits.push(habit)
  await saveHabits(habits)
  return habit
}

export const removeHabit = async (id: string): Promise<boolean> => {
  const habits = await getHabits()
  const filtered = habits.filter((h) => h.id !== id)
  if (filtered.length === habits.length) return false
  await saveHabits(filtered)
  // Also remove completions for this habit
  const completions = await getCompletions()
  const filteredCompletions = completions.filter((c) => c.habitId !== id)
  await saveCompletions(filteredCompletions)
  return true
}

export const getCompletions = async (): Promise<Completion[]> => {
  const store = await readJson<CompletionStore>(COMPLETIONS_PATH, { completions: [] })
  return store.completions
}

export const saveCompletions = async (completions: Completion[]): Promise<void> => {
  await writeJson<CompletionStore>(COMPLETIONS_PATH, { completions })
}

export const toggleCompletion = async (habitId: string, date: string): Promise<boolean> => {
  const completions = await getCompletions()
  const idx = completions.findIndex((c) => c.habitId === habitId && c.date === date)
  if (idx >= 0) {
    completions.splice(idx, 1)
    await saveCompletions(completions)
    return false // now uncompleted
  }
  completions.push({ habitId, date })
  await saveCompletions(completions)
  return true // now completed
}

export const isCompleted = (completions: Completion[], habitId: string, date: string): boolean =>
  completions.some((c) => c.habitId === habitId && c.date === date)

export const toDateString = (d: Date): string => {
  const year = d.getFullYear()
  const month = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  return `${year}-${month}-${day}`
}

export const today = (): string => toDateString(new Date())

const DAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'] as const

export const getWeekDates = (): { date: string; dayLabel: string }[] => {
  const now = new Date()
  const dayOfWeek = now.getDay() // 0 = Sunday
  const monday = new Date(now)
  monday.setDate(now.getDate() - ((dayOfWeek + 6) % 7))

  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday)
    d.setDate(monday.getDate() + i)
    return {
      date: toDateString(d),
      dayLabel: DAY_LABELS[d.getDay()],
    }
  })
}

