export const renderToday = (habits: Habit[], completions: Completion[]): string => {
  const todayStr = today()
  const habitRows = habits.map((habit) => {
    const done = isCompleted(completions, habit.id, todayStr)
    return `<div style="${styleAttr(styles.habitRow)}">
      <div style="${styleAttr(styles.habitInfo)}">
        <span style="${styleAttr(styles.habitName)}">${escapeHtml(habit.name)}</span>
        <span style="${styleAttr(styles.badge)}">${habit.frequency}</span>
      </div>
      <div style="${styleAttr(styles.habitActions)}">
        <form method="POST" action="/completions" style="margin:0">
          <input type="hidden" name="habitId" value="${habit.id}">
          <input type="hidden" name="date" value="${todayStr}">
          <input type="checkbox" style="${styleAttr(styles.checkbox)}" ${done ? 'checked' : ''} onchange="this.form.submit()">
        </form>
        <form method="POST" action="/habits/${habit.id}/delete" style="margin:0">
          <button type="submit" style="${styleAttr(styles.deleteBtn)}">remove</button>
        </form>
      </div>
    </div>`
  }).join('')

  const completedCount = habits.filter((h) => isCompleted(completions, h.id, todayStr)).length
  const totalCount = habits.length
  const pct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0

  const todaySection = habits.length > 0
    ? `<div style="${styleAttr(styles.card)}">
        <div style="${styleAttr(styles.sectionTitle)}">Today &mdash; ${todayStr}</div>
        ${habitRows}
        <div style="padding-top:12px;text-align:center;font-size:14px;color:#718096">
          ${completedCount}/${totalCount} completed (${pct}%)
        </div>
      </div>`
    : `<div style="${styleAttr(styles.card)}">
        <div style="${styleAttr(styles.emptyState)}">No habits yet. Add one below!</div>
      </div>`

  const addForm = `<div style="${styleAttr(styles.card)}">
    <div style="${styleAttr(styles.sectionTitle)}">Add Habit</div>
    <form method="POST" action="/habits" style="${styleAttr(styles.form)}">
      <input type="text" name="name" placeholder="Habit name" required style="${styleAttr(styles.input)}">
      <select name="frequency" style="${styleAttr(styles.select)}">
        <option value="daily">Daily</option>
        <option value="weekly">Weekly</option>
      </select>
      <button type="submit" style="${styleAttr(styles.button)}">Add</button>
    </form>
  </div>`

  return Layout('today', todaySection + addForm)
}

export const renderWeek = (habits: Habit[], completions: Completion[]): string => {
  const weekDates = getWeekDates()
  const todayStr = today()

  if (habits.length === 0) {
    return Layout('week', `<div style="${styleAttr(styles.card)}">
      <div style="${styleAttr(styles.emptyState)}">No habits yet. Go to Today to add some!</div>
    </div>`)
  }

  // Overall weekly completion rate
  let totalChecks = 0
  let totalPossible = 0
  const todayIdx = weekDates.findIndex((d) => d.date === todayStr)
  const daysElapsed = todayIdx >= 0 ? todayIdx + 1 : 7

  habits.forEach((habit) => {
    if (habit.frequency === 'daily') {
      totalPossible += daysElapsed
      weekDates.slice(0, daysElapsed).forEach((d) => {
        if (isCompleted(completions, habit.id, d.date)) totalChecks++
      })
    } else {
      // weekly: 1 completion needed for the week
      totalPossible += 1
      const anyDone = weekDates.some((d) => isCompleted(completions, habit.id, d.date))
      if (anyDone) totalChecks++
    }
  })

  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0

  const rateCard = `<div style="${styleAttr(styles.card)}">
    <div style="${styleAttr(styles.completionRate)}">${overallRate}%</div>
    <div style="${styleAttr(styles.rateLabel)}">Weekly Completion Rate</div>
  </div>`

  const habitCards = habits.map((habit) => {
    let habitCompleted = 0
    let habitPossible = 0

    const dayCells = weekDates.map((d) => {
      const done = isCompleted(completions, habit.id, d.date)
      const isFuture = d.date > todayStr

      if (!isFuture) {
        if (habit.frequency === 'daily') {
          habitPossible++
          if (done) habitCompleted++
        }
      }

      const cellStyle = isFuture ? styles.dayCellFuture : done ? styles.dayCellDone : styles.dayCellMissed
      return `<div style="${styleAttr({ ...styles.dayCell, ...cellStyle })}">${done ? '\u2713' : isFuture ? '\u00b7' : '\u2717'}</div>`
    }).join('')

    if (habit.frequency === 'weekly') {
      habitPossible = 1
      habitCompleted = weekDates.some((d) => isCompleted(completions, habit.id, d.date)) ? 1 : 0
    }

    const habitRate = habitPossible > 0 ? Math.round((habitCompleted / habitPossible) * 100) : 0

    const dayHeaders = weekDates.map((d) =>
      `<div style="${styleAttr(styles.dayHeader)}">${d.dayLabel}</div>`
    ).join('')

    return `<div style="${styleAttr(styles.card)}">
      <div style="${styleAttr(styles.weekHabitName)}">${escapeHtml(habit.name)} <span style="${styleAttr(styles.badge)}">${habit.frequency}</span></div>
      <div style="${styleAttr(styles.weekHabitRate)}">${habitRate}% this week</div>
      <div style="${styleAttr(styles.streakGrid)}">
        ${dayHeaders}
        ${dayCells}
      </div>
    </div>`
  }).join('')

  return Layout('week', rateCard + habitCards)
}

const escapeHtml = (s: string): string =>
  s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

import { getHabits, getCompletions, addHabit, removeHabit, toggleCompletion } from './data'
import { renderToday, renderWeek } from './render'
import type { Frequency } from './types'

const html = (body: string) => new Response(body, {
  headers: { 'Content-Type': 'text/html; charset=utf-8' },
})

const redirect = (path: string) => new Response(null, {
  status: 303,
  headers: { Location: path },
})

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((v, k) => { result[k] = v })
  return result
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // GET / — Today's checklist
    if (method === 'GET' && pathname === '/') {
      const [habits, completions] = await Promise.all([getHabits(), getCompletions()])
      return html(renderToday(habits, completions))
    }

    // GET /week — Weekly streak view
    if (method === 'GET' && pathname === '/week') {
      const [habits, completions] = await Promise.all([getHabits(), getCompletions()])
      return html(renderWeek(habits, completions))
    }

    // POST /habits — Create a new habit
    if (method === 'POST' && pathname === '/habits') {
      const form = await parseForm(req)
      const name = form.name?.trim()
      const frequency = form.frequency as Frequency
      if (name && (frequency === 'daily' || frequency === 'weekly')) {
        await addHabit(name, frequency)
      }
      return redirect('/')
    }

    // POST /habits/:id/delete — Remove a habit
    const deleteMatch = pathname.match(/^\/habits\/([^/]+)\/delete$/)
    if (method === 'POST' && deleteMatch) {
      await removeHabit(deleteMatch[1])
      return redirect('/')
    }

    // POST /completions — Toggle habit completion
    if (method === 'POST' && pathname === '/completions') {
      const form = await parseForm(req)
      const { habitId, date } = form
      if (habitId && date) {
        await toggleCompletion(habitId, date)
      }
      const referer = req.headers.get('referer') ?? '/'
      const refUrl = new URL(referer)
      return redirect(refUrl.pathname)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Habit Tracker running at http://localhost:${server.port}`)

