const buildPieChartSvg = (entries: PortfolioSummary['entries']): string => {
  if (entries.length === 0) return ''

  const size = 200
  const cx = size / 2
  const cy = size / 2
  const r = 80

  if (entries.length === 1) {
    return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">
      <circle cx="${cx}" cy="${cy}" r="${r}" fill="${CHART_COLORS[0]}" />
    </svg>`
  }

  let currentAngle = -Math.PI / 2
  const paths: string[] = []

  entries.forEach((entry, i) => {
    const sliceAngle = (entry.allocationPercent / 100) * 2 * Math.PI
    if (sliceAngle <= 0) return

    const x1 = cx + r * Math.cos(currentAngle)
    const y1 = cy + r * Math.sin(currentAngle)
    const x2 = cx + r * Math.cos(currentAngle + sliceAngle)
    const y2 = cy + r * Math.sin(currentAngle + sliceAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0
    const color = CHART_COLORS[i % CHART_COLORS.length]

    paths.push(
      `<path d="M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2} Z" fill="${color}" />`
    )
    currentAngle += sliceAngle
  })

  return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">${paths.join('')}</svg>`
}

