import { addHolding, removeHolding, updatePrice, getPortfolioSummary, loadPrices } from './portfolio'
import { renderPortfolio } from './ui'

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // Serve portfolio page
    if (pathname === '/' && req.method === 'GET') {
      const summary = await getPortfolioSummary()
      const prices = await loadPrices()
      const html = renderPortfolio(summary, prices)
      return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
    }

    // Add holding
    if (pathname === '/holdings' && req.method === 'POST') {
      const body = await parseFormBody(req)
      const symbol = body.symbol ?? ''
      const amount = parseFloat(body.amount ?? '0')
      const purchasePrice = parseFloat(body.purchasePrice ?? '0')

      if (symbol && amount > 0 && purchasePrice >= 0) {
        await addHolding(symbol, amount, purchasePrice)
      }
      return Response.redirect('/', 303)
    }

    // Delete holding
    const deleteMatch = pathname.match(/^\/holdings\/([^/]+)\/delete$/)
    if (deleteMatch && req.method === 'POST') {
      await removeHolding(deleteMatch[1])
      return Response.redirect('/', 303)
    }

    // Update price
    if (pathname === '/prices' && req.method === 'POST') {
      const body = await parseFormBody(req)
      const symbol = body.symbol ?? ''
      const price = parseFloat(body.price ?? '0')

      if (symbol && price >= 0) {
        await updatePrice(symbol, price)
      }
      return Response.redirect('/', 303)
    }

    // API: get portfolio JSON
    if (pathname === '/api/portfolio' && req.method === 'GET') {
      const summary = await getPortfolioSummary()
      return new Response(JSON.stringify(summary, null, 2), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

