export type Snippet = {
  id: string;
  title: string;
  language: string;
  tags: string[];
  code: string;
  createdAt: string;
};

export type SnippetStore = {
  snippets: Snippet[];
};

export type FilterParams = {
  language?: string;
  tag?: string;
};

{
  "snippets": []
}

import type { Snippet, SnippetStore, FilterParams } from './types';

const DATA_PATH = 'data/snippets.json';

const readStore = async (): Promise<SnippetStore> => {
  try {
    return await Bun.file(DATA_PATH).json() as SnippetStore;
  } catch {
    return { snippets: [] };
  }
};

const writeStore = async (store: SnippetStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2));
};

export const getAllSnippets = async (): Promise<Snippet[]> => {
  const store = await readStore();
  return store.snippets;
};

export const getFilteredSnippets = async (params: FilterParams): Promise<Snippet[]> => {
  const store = await readStore();
  let result = store.snippets;

  if (params.language) {
    const lang = params.language.toLowerCase();
    result = result.filter((s) => s.language.toLowerCase() === lang);
  }

  if (params.tag) {
    const tag = params.tag.toLowerCase();
    result = result.filter((s) => s.tags.some((t) => t.toLowerCase() === tag));
  }

  return result;
};

export const addSnippet = async (input: {
  title: string;
  language: string;
  tags: string[];
  code: string;
}): Promise<Snippet> => {
  const store = await readStore();
  const snippet: Snippet = {
    id: crypto.randomUUID(),
    title: input.title,
    language: input.language,
    tags: input.tags,
    code: input.code,
    createdAt: new Date().toISOString(),
  };
  store.snippets.push(snippet);
  await writeStore(store);
  return snippet;
};

export const deleteSnippet = async (id: string): Promise<boolean> => {
  const store = await readStore();
  const idx = store.snippets.findIndex((s) => s.id === id);
  if (idx === -1) return false;
  store.snippets.splice(idx, 1);
  await writeStore(store);
  return true;
};

export const getAllLanguages = async (): Promise<string[]> => {
  const store = await readStore();
  const langs = new Set(store.snippets.map((s) => s.language));
  return [...langs].sort();
};

export const getAllTags = async (): Promise<string[]> => {
  const store = await readStore();
  const tags = new Set(store.snippets.flatMap((s) => s.tags));
  return [...tags].sort();
};

