const styleToString = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';');

const copyScript = `
<script>
  document.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-copy-id]');
    if (!btn) return;
    const id = btn.getAttribute('data-copy-id');
    const codeEl = document.getElementById('code-' + id);
    if (!codeEl) return;
    navigator.clipboard.writeText(codeEl.textContent || '').then(() => {
      btn.textContent = 'Copied!';
      setTimeout(() => { btn.textContent = 'Copy'; }, 1500);
    });
  });
</script>
`;

export const renderPage = (
  snippets: Snippet[],
  languages: string[],
  tags: string[],
  activeLanguage?: string,
  activeTag?: string,
  showForm?: boolean,
): string => {
  const buildFilterUrl = (lang?: string, tag?: string): string => {
    const params = new URLSearchParams();
    if (lang) params.set('language', lang);
    if (tag) params.set('tag', tag);
    return '/?' + params.toString();
  };

  const filterBar = h('div', { style: styleToString(styles.filterBar) },
    h('form', { method: 'GET', action: '/', style: 'display:flex;gap:12px;align-items:center' },
      activeTag ? h('input', { type: 'hidden', name: 'tag', value: activeTag }) : null,
      h('select', {
        name: 'language',
        style: styleToString(styles.select),
        onchange: 'this.form.submit()',
      },
        h('option', { value: '' }, 'All Languages'),
        ...languages.map((lang) =>
          h('option', {
            value: lang,
            ...(activeLanguage === lang ? { selected: 'selected' } : {}),
          }, lang),
        ),
      ),
    ),
    ...tags.map((tag) =>
      h('a', {
        href: buildFilterUrl(activeLanguage, activeTag === tag ? undefined : tag),
        style: styleToString(activeTag === tag ? styles.tagBtnActive : styles.tagBtn),
      }, tag),
    ),
    (activeLanguage || activeTag)
      ? h('a', { href: '/', style: styleToString({ ...styles.tagBtn, color: '#f85149' }) }, 'Clear filters')
      : null,
  );

  const form = showForm
    ? h('div', { style: styleToString(styles.form) },
        h('form', { method: 'POST', action: '/snippets' },
          h('div', { style: styleToString(styles.formGroup) },
            h('label', { style: styleToString(styles.label) }, 'Title'),
            h('input', { type: 'text', name: 'title', required: 'required', placeholder: 'e.g. Array deduplication', style: styleToString(styles.input) }),
          ),
          h('div', { style: styleToString(styles.formGroup) },
            h('label', { style: styleToString(styles.label) }, 'Language'),
            h('input', { type: 'text', name: 'language', required: 'required', placeholder: 'e.g. TypeScript', style: styleToString(styles.input) }),
          ),
          h('div', { style: styleToString(styles.formGroup) },
            h('label', { style: styleToString(styles.label) }, 'Tags (comma-separated)'),
            h('input', { type: 'text', name: 'tags', placeholder: 'e.g. array, utility, es6', style: styleToString(styles.input) }),
          ),
          h('div', { style: styleToString(styles.formGroup) },
            h('label', { style: styleToString(styles.label) }, 'Code'),
            h('textarea', { name: 'code', required: 'required', placeholder: 'Paste your code here...', style: styleToString(styles.textarea) }),
          ),
          h('div', { style: 'display:flex;gap:8px' },
            h('button', { type: 'submit', style: styleToString(styles.submitBtn) }, 'Save Snippet'),
            h('a', { href: '/', style: styleToString({ ...styles.btn, textDecoration: 'none', padding: '8px 16px', fontSize: '14px' }) }, 'Cancel'),
          ),
        ),
      )
    : null;

  const snippetCards = snippets.length > 0
    ? snippets.map((snippet) =>
        h('div', { style: styleToString(styles.card) },
          h('div', { style: styleToString(styles.cardHeader) },
            h('span', { style: styleToString(styles.cardTitle) }, snippet.title),
            h('span', { style: styleToString(styles.langBadge) }, snippet.language),
          ),
          h('div', { style: styleToString(styles.codeWrap) },
            h('pre', { style: 'margin:0' },
              h('code', {
                id: `code-${snippet.id}`,
                style: styleToString(styles.code),
              }, snippet.code),
            ),
          ),
          h('div', { style: styleToString(styles.cardFooter) },
            h('div', { style: styleToString(styles.tagsRow) },
              ...snippet.tags.map((tag) =>
                h('span', { style: styleToString(styles.snippetTag) }, tag),
              ),
            ),
            h('div', { style: styleToString(styles.actions) },
              h('button', {
                type: 'button',
                'data-copy-id': snippet.id,
                style: styleToString(styles.btn),
              }, 'Copy'),
              h('form', { method: 'POST', action: `/snippets/${snippet.id}/delete`, style: 'margin:0' },
                h('button', { type: 'submit', style: styleToString(styles.btnDanger) }, 'Delete'),
              ),
            ),
          ),
        ),
      )
    : [h('div', { style: styleToString(styles.emptyState) },
        h('p', {}, 'No snippets found.'),
        h('p', {}, 'Click "New Snippet" to add your first one.'),
      )];

  const page = h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Code Snippets'),
      h('style', {}, 'body{margin:0;background:#0d1117}*{box-sizing:border-box}'),
    ),
    h('body', {},
      h('div', { style: styleToString(styles.page) },
        h('div', { style: styleToString(styles.header) },
          h('h1', { style: styleToString(styles.title) }, 'Code Snippets'),
          showForm
            ? null
            : h('a', { href: '/?form=1', style: styleToString(styles.toggleBtn) }, '+ New Snippet'),
        ),
        form,
        filterBar,
        ...snippetCards,
      ),
    ),
  );

  const ssr = createSSR();
  const html = ssr(page);
  return `<!DOCTYPE html>${html}${copyScript}`;
};

import {
  getAllSnippets,
  getFilteredSnippets,
  addSnippet,
  deleteSnippet,
  getAllLanguages,
  getAllTags,
} from './store';
import { renderPage } from './render';

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  for (const [key, value] of params.entries()) {
    result[key] = value;
  }
  return result;
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const method = req.method;

    // GET / — list snippets with optional filters
    if (method === 'GET' && url.pathname === '/') {
      const language = url.searchParams.get('language') || undefined;
      const tag = url.searchParams.get('tag') || undefined;
      const showForm = url.searchParams.get('form') === '1';

      const snippets = (language || tag)
        ? await getFilteredSnippets({ language, tag })
        : await getAllSnippets();

      const languages = await getAllLanguages();
      const tags = await getAllTags();

      const html = renderPage(snippets, languages, tags, language, tag, showForm);
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    // POST /snippets — create new snippet
    if (method === 'POST' && url.pathname === '/snippets') {
      const body = await parseFormBody(req);
      const title = (body.title || '').trim();
      const language = (body.language || '').trim();
      const tags = (body.tags || '')
        .split(',')
        .map((t) => t.trim())
        .filter((t) => t.length > 0);
      const code = body.code || '';

      if (!title || !language || !code) {
        return new Response('Missing required fields', { status: 400 });
      }

      await addSnippet({ title, language, tags, code });
      return Response.redirect('/', 303);
    }

    // POST /snippets/:id/delete — delete snippet
    const deleteMatch = url.pathname.match(/^\/snippets\/([^/]+)\/delete$/);
    if (method === 'POST' && deleteMatch) {
      const id = deleteMatch[1];
      await deleteSnippet(id);
      return Response.redirect('/', 303);
    }

    return new Response('Not Found', { status: 404 });
  },
});

