    h('h2', { style: { ...styles.subheader, marginBottom: '16px' } }, `Results: ${summary.quizTitle}`),
    h('div', {},
      ...summary.results.map((r, i) =>
        h('div', { style: styles.resultRow },
          h('div', { style: { flex: '1' } },
            h('div', { style: { fontWeight: '600', marginBottom: '4px' } }, `${i + 1}. ${r.questionText}`),
            r.selectedOption !== null
              ? h('div', { style: { fontSize: '13px', color: '#666' } }, `Your answer: ${r.selectedOption}`)
              : h('div', { style: { fontSize: '13px', color: '#999' } }, 'No answer'),
            !r.isCorrect
              ? h('div', { style: { fontSize: '13px', color: '#27ae60' } }, `Correct answer: ${r.correctOption}`)
              : h(Fragment, {}),
          ),
          h('div', { style: r.isCorrect ? styles.correct : styles.incorrect },
            r.isCorrect ? 'Correct' : 'Incorrect',
          ),
        ),
      ),
    ),
    h('div', { style: { display: 'flex', gap: '12px', marginTop: '24px' } },
      h('a', { href: '/', style: styles.button, 'p-trigger': 'click:navigate' }, 'Back to Quizzes'),
    ),
  )
  return template.content
}

import { createSSR } from '@plaited/template'
import { loadQuizzes, getQuiz, addQuiz, deleteQuiz, generateId } from './store'
import { renderQuizList, renderCreateQuiz, renderTakeQuestion, renderScore } from './render'
import type { Quiz, QuizAttempt, ScoreSummary, Question } from './types'

const attempts = new Map<string, QuizAttempt>()

const wrapPage = (bodyHtml: string): string => {
  const ssr = createSSR()
  return ssr`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Quiz Builder</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f5f6fa; min-height: 100vh; }
    a { text-decoration: none; }
  </style>
</head>
<body>${bodyHtml}</body>
</html>`
}

const parseFormQuestions = (formData: FormData): { title: string; questions: Question[] } => {
  const title = (formData.get('title') as string)?.trim() ?? ''
  const questions: Question[] = []
  let qi = 0
  while (formData.has(`q${qi}_text`)) {
    const text = (formData.get(`q${qi}_text`) as string)?.trim() ?? ''
    const options: [string, string, string, string] = [
      (formData.get(`q${qi}_option0`) as string)?.trim() ?? '',
      (formData.get(`q${qi}_option1`) as string)?.trim() ?? '',
      (formData.get(`q${qi}_option2`) as string)?.trim() ?? '',
      (formData.get(`q${qi}_option3`) as string)?.trim() ?? '',
    ]
    const correctIndex = parseInt(formData.get(`q${qi}_correct`) as string ?? '0', 10)
    questions.push({ text, options, correctIndex })
    qi++
  }
  return { title, questions }
}

const computeScore = (quiz: Quiz, attempt: QuizAttempt): ScoreSummary => {
  let totalCorrect = 0
  const results = quiz.questions.map((q, i) => {
    const selected = attempt.answers[i]
    const isCorrect = selected === q.correctIndex
    if (isCorrect) totalCorrect++
    return {
      questionText: q.text,
      selectedOption: selected !== null && selected !== undefined ? q.options[selected] : null,
      correctOption: q.options[q.correctIndex],
      isCorrect,
    }
  })
  return {
    quizTitle: quiz.title,
    totalCorrect,
    totalQuestions: quiz.questions.length,
    results,
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Home — quiz list
    if (path === '/' && method === 'GET') {
      const quizzes = await loadQuizzes()
      return new Response(wrapPage(renderQuizList(quizzes)), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Create quiz form
    if (path === '/create' && method === 'GET') {
      const emptyQuestion = { text: '', options: ['', '', '', ''] as [string, string, string, string], correctIndex: 0 }
      return new Response(wrapPage(renderCreateQuiz('', [emptyQuestion])), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Save new quiz
    if (path === '/create' && method === 'POST') {
      const formData = await req.formData()
      const { title, questions } = parseFormQuestions(formData)

      if (!title) {
        return new Response(wrapPage(renderCreateQuiz(title, questions, 'Please enter a quiz title.')), {
          status: 400,
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (questions.length === 0) {
        return new Response(wrapPage(renderCreateQuiz(title, questions, 'Add at least one question.')), {
          status: 400,
          headers: { 'Content-Type': 'text/html' },
        })
      }

      const emptyFields = questions.some((q) => !q.text || q.options.some((o) => !o))
      if (emptyFields) {
        return new Response(wrapPage(renderCreateQuiz(title, questions, 'Please fill in all question fields and options.')), {
          status: 400,
          headers: { 'Content-Type': 'text/html' },
        })
      }

      const quiz: Quiz = {
        id: generateId(),
        title,
        questions,
        createdAt: new Date().toISOString(),
      }
      await addQuiz(quiz)
      return Response.redirect('/', 303)
    }

    // Start taking a quiz
    const takeMatch = path.match(/^\/take\/([a-f0-9-]+)$/)
    if (takeMatch && method === 'GET') {
      const quizId = takeMatch[1]
      const quiz = await getQuiz(quizId)
      if (!quiz) {
        return Response.redirect('/', 303)
      }

      const attemptId = generateId()
      const attempt: QuizAttempt = {
        quizId,
        answers: new Array(quiz.questions.length).fill(null),
        currentQuestion: 0,
        completed: false,
      }
      attempts.set(attemptId, attempt)

      return new Response(wrapPage(renderTakeQuestion(quiz, attempt, null)), {
        headers: {
          'Content-Type': 'text/html',
          'Set-Cookie': `attemptId=${attemptId}; Path=/; SameSite=Strict`,
        },
      })
    }

    // Submit answer and go to next question
    if (path === '/answer' && method === 'POST') {
      const formData = await req.formData()
      const attemptId = parseCookie(req.headers.get('cookie') ?? '', 'attemptId')
      const attempt = attemptId ? attempts.get(attemptId) : undefined
      if (!attempt || !attemptId) return Response.redirect('/', 303)

      const quiz = await getQuiz(attempt.quizId)
      if (!quiz) return Response.redirect('/', 303)

      const answerStr = formData.get('answer') as string | null
      const answer = answerStr !== null ? parseInt(answerStr, 10) : null
      if (answer !== null) {
        attempt.answers[attempt.currentQuestion] = answer
      }

      const action = formData.get('action') as string

      if (action === 'next' && attempt.currentQuestion < quiz.questions.length - 1) {
        attempt.currentQuestion++
        return new Response(wrapPage(renderTakeQuestion(quiz, attempt, attempt.answers[attempt.currentQuestion])), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (action === 'finish') {
        attempt.completed = true
        const summary = computeScore(quiz, attempt)
        attempts.delete(attemptId)
        return new Response(wrapPage(renderScore(summary)), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      return new Response(wrapPage(renderTakeQuestion(quiz, attempt, answer)), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Delete quiz
    if (path.startsWith('/delete/') && method === 'POST') {
      const quizId = path.replace('/delete/', '')
      await deleteQuiz(quizId)
      return Response.redirect('/', 303)
    }

    // Add question (returns to create page with one more question)
    if (path === '/add-question' && method === 'POST') {
      const formData = await req.formData()
      const { title, questions } = parseFormQuestions(formData)
      questions.push({ text: '', options: ['', '', '', ''], correctIndex: 0 })
      return new Response(wrapPage(renderCreateQuiz(title, questions)), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Remove question
    const removeMatch = path.match(/^\/remove-question\/(\d+)$/)
    if (removeMatch && method === 'POST') {
      const idx = parseInt(removeMatch[1], 10)
      const formData = await req.formData()
      const { title, questions } = parseFormQuestions(formData)
      if (questions.length > 1) {
        questions.splice(idx, 1)
      }
      return new Response(wrapPage(renderCreateQuiz(title, questions)), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

const parseCookie = (cookieHeader: string, name: string): string | undefined => {
  const match = cookieHeader.match(new RegExp(`(?:^|;\\s*)${name}=([^;]*)`))
  return match?.[1]
}

console.log(`Quiz Builder running at http://localhost:${server.port}`)
